INSERT INTO public.photos VALUES (21273, '&quot;Ambos Mundos&quot; c.1900', '"Zaragoza: Caf‚îú¬Æ de Ambos Mundos". Tarjeta postal que reproduce el original exterior del edificio del Paseo Independencia, que ocupa toda la manzana entre el paseo, y las calles Casa Jim‚îú¬Ænez (derecha), Ponzano, traseras, y Albareda (izquierda). Era mundialmente conocido porque en sus bajos estaba ubicado desde 1881 el "Gran Caf‚îú¬Æ de Ambos Mundos", ah‚îú¬° es nada. En 1928 este edificio ser‚îú√≠ intensamente reformado, por fuera, y por dentro. Fuente: Fot. Laurent (Madrid), AMZ.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64922800, -0.88416200, '0101000020E6100000E1B54B1B0E4BECBFE1D231E719D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22645585436.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22645585436.webp', 'https://www.flickr.com/photos/zaragozaantigua/22645585436/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21337, 'Teatro Gran Casino 1908', 'Teatro del Gran Casino en la Exposici‚îú‚îÇn Hispano-Francesa de 1908, huerta de Santa Engracia..', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64922600, -0.88035400, '0101000020E61000009BE3DC26DC2BECBF40DB6AD619D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53816006627.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53816006627.webp', 'https://www.flickr.com/photos/zaragozaantigua/53816006627/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21342, 'Restaurante Gran Casino 1908', 'Restaurante del Gran Casino en la Exposici‚îú‚îÇn Hispano-Francesa de 1908, huerta de Santa Engracia..', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64922600, -0.88035400, '0101000020E61000009BE3DC26DC2BECBF40DB6AD619D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53817182728.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53817182728.webp', 'https://www.flickr.com/photos/zaragozaantigua/53817182728/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21346, 'Quiosco Confiteros 1908', 'Quiosco de la Asociaci‚îú‚îÇn de Confiteros en la Exposici‚îú‚îÇn Hispano-Francesa de 1908, huerta de Santa Engracia.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64844800, -0.87992500, '0101000020E61000007FD93D795828ECBF0C94145800D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53817321054.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53817321054.webp', 'https://www.flickr.com/photos/zaragozaantigua/53817321054/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21466, 'Palacio de la M‚îú‚ïësica 1911', 'Imagen capturada durante la inauguraci‚îú‚îÇn oficial de la Exposici‚îú‚îÇn Regional de Bellas Artes alojada en el "Palacio de la M‚îú‚ïësica". Este evento fue organizado por la Secci‚îú‚îÇn de Artes del Ateneo Cient‚îú¬°fico y Literario de Zaragoza, cuyo presidente, Sr. Marqu‚îú¬Æs de Arlanza, dio el discurso inaugural ante un selecto auditorio de personalidades encabezado por el arzobispo Soldevila, el gobernador civil Eduardo Garc‚îú¬°a Bajo, el gobernador militar Sr. Salcedo, el presidente de la Audiencia Territorial Sr. Marqu‚îú¬Æs de Santa Amalia, el rector de la Universidad Sr. Gim‚îú¬Ænez Soler y el vicepresidente de la Diputaci‚îú‚îÇn Sr. Sancho Arroyo. Esta exposici‚îú‚îÇn ten‚îú¬°a por objeto la promoci‚îú‚îÇn del arte regional, con la presencia de 177 obras de escultores y pintores aragoneses, algunos noveles y prometedores como el escultor Antonio Torres Clavero y los pintores Julio Garc‚îú¬°a Condoy y Ram‚îú‚îÇn Ac‚îú¬°n Aquilu‚îú¬Æ, adem‚îú√≠s de figuras consagradas como Juan Jos‚îú¬Æ G‚îú√≠rate. La entrada normal costaba 30 c‚îú¬Æntimos, que se reduc‚îú¬°a a 15 los domingos, y ascend‚îú¬°a a una peseta cuando se programaban atracciones suplementarias destinadas a la "gente bien" de mayor poder adquisitivo, como los "d‚îú¬°as de moda", "fiestas aristocr‚îú√≠ticas con un five ‚îú‚îÇclok tea chocolat", conciertos y t‚îú‚îÇmbolas. Este Palacio de la M‚îú‚ïësica hab‚îú¬°a sido proyectado por el arquitecto Ricardo Magdalena para la Exposici‚îú‚îÇn Hispano-Francesa de 1908, fue luego reformado para albergar espect‚îú√≠culos y eventos varios hasta su demolici‚îú‚îÇn postrera para urbanizar el entorno de la plaza de Castelar.', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.64922600, -0.88035400, '0101000020E61000009BE3DC26DC2BECBF40DB6AD619D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53457533823.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53457533823.webp', 'https://www.flickr.com/photos/zaragozaantigua/53457533823/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21515, 'Plaza de Castelar 1922', 'Miguel Faci Abad. 1922. "Zaragoza. Casa de la familia Castellano en la plaza de Castelar." Imagen de la casa de Tom‚îú√≠s Castellano Echenique en la plaza de Castelar, esquina con la calle de Costa (a la izquierda). Este edificio de vivienda, ecl‚îú¬Æctico en sus formas, es dise‚îú‚ñío de Teodoro R‚îú¬°os. A‚îú‚ñíos despu‚îú¬Æs ser‚îú√≠ adquirido por una entidad local de ahorro, que desde 1935 utiliz‚îú‚îÇ los bajos para dispensario sanitario, hasta que en 1999 quiso ser reconvertido en "Espacio Goya", pero se qued‚îú‚îÇ en centro cultural. Fuente visual: "Miguel y Gabriel Faci. Fot‚îú‚îÇgrafos fundadores de la Real Sociedad Fotogr‚îú√≠fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaci‚îú‚îÇn Provincial de Zaragoza, 1999.', 1922, 1922, 1922, 'Anos 20', 'CENTRO', 41.64855500, -0.88024900, '0101000020E610000047C66AF3FF2AECBF2254A9D903D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15741820995.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15741820995.webp', 'https://www.flickr.com/photos/zaragozaantigua/15741820995/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21530, 'Falla 1920', 'Primera falla valenciana levantada en Zaragoza, por parte de la comunidad de valencianos afincados en la ciudad. Representa la futura l‚îú¬°nea f‚îú¬Ærrea que unir‚îú√≠ las dos ciudades. Al fondo, la portada de la iglesia de Santa Engracia. Fuente: La Hormiga de Oro, 1920.', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.64926600, -0.88294000, '0101000020E610000053910A630B41ECBFCE33F6251BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18984321460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18984321460.webp', 'https://www.flickr.com/photos/zaragozaantigua/18984321460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21563, 'Gran Hotel 1929', 'Imagen del nov‚îú¬°simo Gran Hotel, con su caracter‚îú¬°stico chafl‚îú√≠n, unos d‚îú¬°as antes de su inauguraci‚îú‚îÇn oficial, cuando ofertaba 200 habitaciones y la "pensi‚îú‚îÇn completa" m‚îú¬°nima alcanzaba las 22,50 pesetas. A su derecha, solar sobre el que unos a‚îú‚ñíos despu‚îú¬Æs ser‚îú√≠ levantado el actual n‚î¨‚ïë 7 de la calle Costa. A su izquierda, el original colegio "Nuestra Se‚îú‚ñíora del Pilar" de la Compa‚îú‚ñí‚îú¬°a de Santa Teresa de Jes‚îú‚ïës. Fuente: revista "Estampa" (Madrid).', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.64898400, -0.88166400, '0101000020E6100000FAEFC16B9736ECBF4AD05FE811D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22549409958.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22549409958.webp', 'https://www.flickr.com/photos/zaragozaantigua/22549409958/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21606, 'Calle Costa 1926', '"Proyecto de casas propiedad de do‚îú‚ñía Carmen Yarza y don Valent‚îú¬°n de Torres Solanot", Regino Borobio, 1926. Dibujo del edificio de viviendas racionalista de la calle de Joaqu‚îú¬°n Costa 5 y 7 (hoy 9 y 11). Fue terminado en 1928. A la derecha, fuera de plano, se encuentra el patio del antiguo dispensario antituberculoso de la plaza de los Sitios. Fuente visual: "Regino Borobio Ojeda, 1895-1976", Jos‚îú¬Æ Manuel Pozo Municio, Colegio Oficial de Arquitectos de Arag‚îú‚îÇn, 1991, a trav‚îú¬Æs de www.facebook.com/photo.php?fbid=665218510309483&set=p...', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.64870300, -0.88074100, '0101000020E6100000FCE1E7BF072FECBF96E82CB308D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27944770554.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27944770554.webp', 'https://www.flickr.com/photos/zaragozaantigua/27944770554/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21635, 'Calle del Arquitecto Magdalena 1927', 'Imagen desde cierta altura del reci‚îú¬Æn terminado inmueble del n‚î¨‚ïë 10 de la calle de Felipe Sanclemente, proyectado por Teodoro R‚îú¬°os Balaguer para Tom‚îú√≠s Castellano y Echenique, esquinero con la plaza de Castelar, a la derecha y fuera de plano. En primer t‚îú¬Ærmino, su gran patio con fuente e ingreso por el n‚î¨‚ïë 13 de la calle de Joaqu‚îú¬°n Costa, de igual superficie que el edificio. A la izquierda, y en la calle de Isaac Peral, se destaca la chimenea de El‚îú¬Æctricas Reunidas de Zaragoza y las traseras del Teatro Circo. A la derecha y al fondo, el panorama despejado de inmediatas edificaciones nos lleva hasta las traseras del n‚î¨‚ïë 14 de la calle de San Miguel.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64876900, -0.88011800, '0101000020E6100000A4DE5339ED29ECBF4ED4D2DC0AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49762506842.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49762506842.webp', 'https://www.flickr.com/photos/zaragozaantigua/49762506842/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21637, 'Calle de Joaqu‚îú¬°n Costa c.1927', 'Imagen capturada desde cierta altura en el inmueble del n‚î¨‚ïë 12 de la calle de Joaqu‚îú¬°n Costa, con vista del panorama edilicio de esta calle en el lado de los impares desde el inmueble del n‚î¨‚ïë 9, en primer t‚îú¬Ærmino, pasando por los solares de los n‚îú‚ïëmeros 7 y 5, donde poco despu‚îú¬Æs se levantar‚îú¬°a el Gran Hotel. Tras el cruce con la calle de Isaac Peral destaca el destacado y reciente inmueble del n‚î¨‚ïë 3, construido para el general S‚îú√≠inz Mend‚îú¬°vil, A su derecha aparece, de repente, la c‚îú‚ïëpula de la iglesia parroquial de Santiago el Mayor. Hacia el fondo, la plaza de santa Engracia y el principio de la calle, con la enorme casa del conde de La Rosa, esquinera con el paseo de la Independencia. Tras ‚îú¬Æl, la calle del marqu‚îú¬Æs de Casa Jim‚îú¬Ænez.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64905700, -0.88165200, '0101000020E6100000E97E4E417E36ECBFB41EBE4C14D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50768170792.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50768170792.webp', 'https://www.flickr.com/photos/zaragozaantigua/50768170792/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21700, 'P.‚î¨‚ïë de la Independencia 1936', 'Ni Guerra Civil ni nada. En Zaragoza, para las fiestas del Pilar, a sacar a los gigantes, aunque llueva lo que llueva. No obstante, Don Quijote no las tiene todas consigo y otea el horizonte por si las moscas. Detr‚îú√≠s, en el edificio esquina con Albareda, el colegio de la Sagrada Familia, por supuesto. Fuente: www.facebook.com/photo.php?fbid=883970591636022&set=o...', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64900800, -0.88419600, '0101000020E6100000E620E868554BECBFD36BB3B112D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15566994358.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15566994358.webp', 'https://www.flickr.com/photos/zaragozaantigua/15566994358/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21798, 'P.‚î¨‚ïë de la Independencia 1931', 'Postal, Roisin. Vista de la acera de los pares del paseo de la Independencia, con la plaza de Arag‚îú‚îÇn a la espalda. Tras la calle de Albareda, el edificio del Banco de Cr‚îú¬Ædito de Zaragoza reformado por Pascual Bravo, y en cuyos bajos estaba el caf‚îú¬Æ Ambos Mundos. A la derecha, el cenotafio "A los funcionarios muertos en agosto de 1920". Fuente: www.ebay.com/', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.64894400, -0.88429300, '0101000020E6100000849D62D5204CECBFBC77D49810D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25503955481.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25503955481.webp', 'https://www.flickr.com/photos/zaragozaantigua/25503955481/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21799, 'Isaac Peral 1931', 'Fotograf‚îú¬°a de Lucien Roisin. Imagen del achaflanado cruce entre las calles Isaac Peral y Costa, uno de los espacios reurbanizados tras la Exposici‚îú‚îÇn de 1908 en la que fuera antigua huerta del convento de Santa Engracia. En primer plano, el nov‚îú¬°simo Gran Hotel, con notable flota de autom‚îú‚îÇviles, como reflejo del exclusivo signo social de la clientela. A su derecha, las vallas indican que su solar vecino va a ser pronto obrado. Hacia el fondo, en Peral, el tambi‚îú¬Æn reciente nuevo recinto para el convento y colegio de las Teresianas. A su izquierda, la poderosa chimenea de la f‚îú√≠brica de electricidad de Electra Peral, en el cruce con la calle San Miguel. Inmediato, y a la derecha y posiblemente con dise‚îú‚ñío de Teodoro R‚îú¬°os Balaguer, el desaparecido edificio entre Peral y Costa, sustituido al poco por otro nuevo, menos clasicista, y m‚îú√≠s vertical, que de eso se trataba.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.64898400, -0.88166400, '0101000020E6100000FAEFC16B9736ECBF4AD05FE811D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25600514522.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25600514522.webp', 'https://www.flickr.com/photos/zaragozaantigua/25600514522/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21856, 'P.‚î¨‚ïë Independencia 1934', 'Imagen capturada desde cierta altura y centrada en el inmueble del n‚î¨‚ïë 31 del paseo de la Independencia, construido a finales del siglo XIX. A la izquierda. el moderno edificio de la casa de Tel‚îú¬Æfonos. A la derecha, el emboque a la calle de Bruil, con vista parcial del hotelito sede del Gobierno Civil. Sobre los soportales del paseo, el anuncio comercial luminoso que se‚îú‚ñíalaba la presencia de la reconocida sastrer‚îú¬°a de Justo Gimeno, con sus talleres de corte y confecci‚îú‚îÇn, almac‚îú¬Æn y tienda de ropa. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.64890700, -0.88377500, '0101000020E610000080B74082E247ECBF9F9273620FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36102859260.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36102859260.webp', 'https://www.flickr.com/photos/zaragozaantigua/36102859260/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21886, 'P.‚î¨‚ïë de la Independencia 1939', 'Imagen capturada durante un desfile militar por el paseo de la Independencia, posiblemente durante los actos de homenaje al Cuerpo de Ej‚îú¬Ærcito de Arag‚îú‚îÇn. A la izquierda, soportales o porches del paseo bajo el original edificio de Tel‚îú¬Æfonos. Al fondo y luminosa, la plaza de Arag‚îú‚îÇn, donde tuvieron lugar la misa de campa‚îú‚ñía y los discursos de homenaje.', 1939, 1939, 1939, 'Anos 30', 'CENTRO', 41.64918600, -0.88382000, '0101000020E6100000809F71E14048ECBFB282DF8618D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49666311411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49666311411.webp', 'https://www.flickr.com/photos/zaragozaantigua/49666311411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22120, 'Salvador Dal‚îú¬° 1956', 'Salvador Dal‚îú¬° (1904-1989) pernoct‚îú‚îÇ en el Gran Hotel de Zaragoza el 15 de mayo de 1956, procedente de Nueva York y acompa‚îú‚ñíado de su esposa Gala y de Gonzalo Serraclara, abogado y familiar del pintor. Al d‚îú¬°a siguiente, el periodista de Heraldo de Arag‚îú‚îÇn Marcial Buj le abord‚îú‚îÇ en el hall para hacerle una entrevista, que se public‚îú‚îÇ el jueves 17 de mayo. Su meta era Santiago de Compostela, tras pasar por Madrid y el sur de la pen‚îú¬°nsula. Seg‚îú‚ïën el catal‚îú√≠n, √î√á¬£Zaragoza es piramidal, s‚îú‚îÇlida, realista y eterna√î√á√ò. En la puerta del hotel (calle de Joaqu‚îú¬°n Costa 5), Miguel Mar‚îú¬°n Chivite les hizo unas fotos. En los cristales se ven reflejados los edificios de los n‚îú‚ïëmeros 2 y 4 de la calle Costa. Fuente visual: "Chas, de Salduba a las Vegas", Eduardo Laborda, 2015.', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.64898400, -0.88166400, '0101000020E6100000FAEFC16B9736ECBF4AD05FE811D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22537046801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22537046801.webp', 'https://www.flickr.com/photos/zaragozaantigua/22537046801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22214, 'Calle de Juan Bruil 1959', 'Imagen tomada en la calle de Juan Bruil y centrada en la fachada del Hotel Centenario, habilitado en 1940 donde estuviera originalmente el Gran Hotel Regina. Fue reformado en 1942, y derribado en 1966 para mayor aprovechamiento vertical del espacio. Al fondo, el inmueble del n‚î¨‚ïë 10 del paseo de Marina Moreno. En la puerta del hotel destaca un Renault 4/4 construido en la factor‚îú¬°a Fasa-Espa‚îú‚ñía de Valladolid. A la derecha e inmediato, el anexo hotelito del n‚î¨‚ïë 1 de la plaza de Arag‚îú‚îÇn que albergara hasta 1958 el Gobierno Civil. Fuente visual: AMZ.', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.64843700, -0.88361800, '0101000020E61000008E0585419946ECBF1842CEFBFFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46158723854.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46158723854.webp', 'https://www.flickr.com/photos/zaragozaantigua/46158723854/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22290, 'Plaza de Arag‚îú‚îÇn 1969', 'Cuatro funcionarios p‚îú‚ïëblicos recorren diariamente las calles de Zaragoza cumpliendo su importante misi‚îú‚îÇn: los carteros de Zaragoza. No son los "Fab Four", pero en tiempos en que la "net" era apenas una especulaci‚îú‚îÇn, el correo postal ordinario ten‚îú¬°a importancia capital. En la imagen, cargados con su labor del d‚îú¬°a, cuatro carteros cruzan el paseo de la Independencia en el linde con la plaza de Arag‚îú‚îÇn. A la derecha, en la esquina con la calle Bruil, vallas comerciales anuncian el piqueteo del antiguo hotelito que fuera sede del Gobierno Civil, y de las anexas edificaciones que fueran del antiguo hotel Regina, y la construcci‚îú‚îÇn de la actual y macizada manzana con viviendas, y nuevo hotel. Fuente: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.64882000, -0.88410200, '0101000020E61000008D800A47904AECBFD07EA4880CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15254348204.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15254348204.webp', 'https://www.flickr.com/photos/zaragozaantigua/15254348204/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22334, 'Avenida Independencia c.1962', '"Avenida de la Independencia". Postal. En 1961 se transform‚îú‚îÇ el paseo de la Independencia de Zaragoza en avenida, aunque acab‚îú‚îÇ conservando la denominaci‚îú‚îÇn anterior. Una vez terminadas las obras, el cenotafio "A los funcionarios muertos en agosto de 1920" permaneci‚îú‚îÇ all‚îú¬° por un tiempo, hasta que fue trasladado a su ubicaci‚îú‚îÇn actual, en el paseo de Marina Moreno. La foto est‚îú√≠ tomada desde la plaza de Arag‚îú‚îÇn. Fuente visual: www.todocoleccion.net/', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.64900800, -0.88419600, '0101000020E6100000E620E868554BECBFD36BB3B112D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19331723976.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19331723976.webp', 'https://www.flickr.com/photos/zaragozaantigua/19331723976/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22491, 'Paseo Independencia 1964', 'Vista nocturna del paseo de la Independencia desde la plaza de Arag‚îú‚îÇn. A la derecha, el Cenotafio "La ciudad honra a sus funcionarios" (1924). Fuente: Foto Mar‚îú¬°n Chivite. Revista Triunfo.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.64894200, -0.88433500, '0101000020E61000003FA9F6E9784CECBF1B800D8810D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46303011945.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46303011945.webp', 'https://www.flickr.com/photos/zaragozaantigua/46303011945/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22527, 'Plaza de Arag‚îú‚îÇn 1972', 'Un convoy del tranv‚îú¬°a de la l‚îú¬°nea 5 Plaza Espa‚îú‚ñía-Venecia atraviesa la plaza de Arag‚îú‚îÇn. Al fondo, el paseo de la Independencia. Interesante visual del antiguo hotelito de la plaza esquinado con la calle Albareda, previa a su piqueteo en el tr‚îú√≠nsito neodemocr‚îú√≠tico. Fuente visual: www.flickr.com/photos/jhm0284/5812546885/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.64879300, -0.88438800, '0101000020E6100000F4311F10E84CECBFD66F26A60BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14700732400.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14700732400.webp', 'https://www.flickr.com/photos/zaragozaantigua/14700732400/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22727, 'Plaza Arag‚îú‚îÇn 1972', 'Foto centrada en la unidad 325 de la l‚îú¬°nea 30 de los autobuses urbanos, "Casablanca". Est‚îú√≠ situado en la plaza de Arag‚îú‚îÇn. Tras el autob‚îú‚ïës, el edificio de Capitan‚îú¬°a. Fuente visual: foto J-H. Manara, en www.flickr.com/photos/jhm0284/5813113284/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.64848500, -0.88459400, '0101000020E6100000419C8713984EECBF2979758E01D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30566346233.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30566346233.webp', 'https://www.flickr.com/photos/zaragozaantigua/30566346233/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22730, 'P.‚î¨‚ïë de la Independencia 1972', 'Foto centrada en la unidad 162 de la l‚îú¬°nea 21 de los autobuses urbanos, "Plaza del Pilar-Barrio Oliver". Est‚îú√≠ a punto de entrar en la plaza de Arag‚îú‚îÇn. Tras el autob‚îú‚ïës, la entrada a la calle de Jos‚îú¬Æ Luis Albareda desde el paseo de la Independencia. Fuente visual: foto J-H. Manara, en www.flickr.com/photos/jhm0284/5812544705/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.64891800, -0.88443300, '0101000020E6100000F419506F464DECBF93E4B9BE0FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31004431580.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31004431580.webp', 'https://www.flickr.com/photos/zaragozaantigua/31004431580/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22850, 'Vista desde Santa Engracia 1987', 'Luis M‚îú¬°nguez. 1987. La torre de la iglesia de Santa Engracia desde la que se captura esta imagen se asienta sobre la cripta de los "Innumerables m‚îú√≠rtires de Zaragoza", que son 18 contados, as‚îú¬° que la visual tampoco da para mucho m‚îú√≠s que una miradica a la inmediata plaza de Santa Engracia, al paseo de la Independencia, y a la calle Marqu‚îú¬Æs de Casa Jim‚îú¬Ænez, donde el antiguo Gobierno Militar, y el reciente hotel de cinco estrellas, en cuyos bajos hab‚îú¬°a dos cines, dos, y en cuyos bajos m‚îú√≠s bajos, tal vez un anfiteatro romano, dicen. A la izquierda, el edificio de Correos y Tel‚îú¬Ægrafos.', 1987, 1987, 1987, 'Anos 80', 'CENTRO', 41.64905700, -0.88294000, '0101000020E610000053910A630B41ECBFB41EBE4C14D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15233392993.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15233392993.webp', 'https://www.flickr.com/photos/zaragozaantigua/15233392993/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22961, 'Jordi Pujol 1983', 'Imagen capturada en la puerta del Gran Hotel y centrada en Jordi Pujol Soley, presidente de la Generalitat de Catalunya, charla campechanamente con unos soldados de reemplazo que realizaban el Servicio Militar Obligatorio en Zaragoza. La presencia del "Molt Honorable" en la ciudad ten‚îú¬°a como objeto asistir a la final de la Copa del Rey de F‚îú‚ïëtbol que disputaron el s‚îú√≠bado 4 de junio de 1983 los equipos del F.C. Barcelona y del Real Madrid C.F. en el estadio municipal de la Romareda, y que finaliz‚îú‚îÇ con el resultado de 2 tantos (V‚îú¬°ctor Mu‚îú‚ñíoz y Marcos Alonso) a 1 (Santillana) a favor del F.C. Barcelona. De tel‚îú‚îÇn de fondo, el inmueble del n‚î¨‚ïë 3 de la calle de Joaqu‚îú¬°n Costa, chaflanero con la calle de Isaac Peral.', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.64903300, -0.88174900, '0101000020E610000087FBC8AD4937ECBF2C836A8313D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53248420638.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53248420638.webp', 'https://www.flickr.com/photos/zaragozaantigua/53248420638/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22965, 'Dispensario antituberculoso a‚îú‚ñíos 90', 'Calle Costa, 13 con plaza de los Sitios. Inaugurado en 1935 como dispensario antituberculoso, en 1952 se transform‚îú‚îÇ en t‚îú¬Ætrico dispensario para enfermedades del t‚îú‚îÇrax, hasta que se clausur‚îú‚îÇ en 1997. En 1999 fue propuesto como sede del Espacio Goya, proyecto que se desestim‚îú‚îÇ. Hoy es Ibercaja Zentrum, lugar de actividades culturales. Fuente: Ibercaja', 1990, 1990, 1999, 'Anos 90', 'CENTRO', 41.64855500, -0.88024900, '0101000020E610000047C66AF3FF2AECBF2254A9D903D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14831880089.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14831880089.webp', 'https://www.flickr.com/photos/zaragozaantigua/14831880089/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23050, 'Plaza de Arag‚îú‚îÇn 1991', 'Imagen capturada en la plaza de Arag‚îú‚îÇn con una vista parcial, a la izquierda, de las jardineras instaladas durante el reciente embellecimiento de este espacio urbano, que adem‚îú√≠s ejerc‚îú¬°an de estilosos quitamiedos decorados con azulejos que formaban los escudos de las tres provincias y capitales provinciales, por aquello de hacer honor a la plaza donde estaban radicados. As‚îú¬°, en esta escena aparece el tradicional escudo municipal de Zaragoza. Hacia el fondo que conduce al paseo de la Independencia, una de las paradas de autob‚îú‚ïës de la plaza, en las que se pod‚îú¬°an acumular varios veh‚îú¬°culos de las diferentes l‚îú¬°neas que por aqu‚îú¬° transitaban.', 1991, 1991, 1991, 'Anos 90', 'CENTRO', 41.64852000, -0.88454900, '0101000020E610000042B456B4394EECBFA5660FB402D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50441653682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50441653682.webp', 'https://www.flickr.com/photos/zaragozaantigua/50441653682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23649, 'Cuartel de Santa Engracia 1906', 'Dibujo de Ambrosio Ruste que representa la entrada del Cuartel de Infanter‚îú¬°a de Santa Engracia, antes aprobarse su derribo en 1906 (aunque s‚îú‚îÇlo se har‚îú√≠ efectivo un par de a‚îú‚ñíos despu‚îú¬Æs). A la izquierda, junto a la peque‚îú‚ñía casa de vecinos, el t‚îú‚ïënel que comunicaba con la Huerta de Santa Engracia. A la derecha, la iglesia de Santa Engracia. Fuente: ‚î¨√≠Aqu‚îú¬°... Zaragoza!, Jos‚îú¬Æ Blasco Ijazo, 1952.', 1906, 1906, 1906, 'Anos 1900', 'CENTRO', 41.64921700, -0.88268300, '0101000020E61000007F86376BF03EECBFED80EB8A19D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19644875760.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19644875760.webp', 'https://www.flickr.com/photos/zaragozaantigua/19644875760/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23664, 'Cuartel de Santa Engracia 1908', 'Imagen de Casta‚îú‚ñíer-O‚îú‚ñía realizada durante los festejos que celebraban el comienzo del derribo del antiguo cuartel de Santa Engracia. Aunque esto estaba previsto desde al menos 1906, tras importantes debates, su cesi‚îú‚îÇn al ayuntamiento por parte del Gobierno de Espa‚îú‚ñía s‚îú‚îÇlo fue aprobada a finales de enero de 1908, y el comienzo del derribo, a finales de marzo de ese a‚îú‚ñío. Tras el ceremonial que acompa‚îú‚ñí‚îú‚îÇ a la desmilitarizaci‚îú‚îÇn del lugar, y la reubicaci‚îú‚îÇn del regimiento "Arag‚îú‚îÇn", que all‚îú¬° se alojaba, en el cercano cuartel de Hern‚îú√≠n Cort‚îú¬Æs, la comparsa de gigantes y cabezudos, autoridades, y una multitud de personas, se citaron por la tarde del 30 de marzo para celebrar el hecho, a la zaragozana manera. La imagen, capturada desde cierta altura, captura esto. A la derecha, inmediata y fuera de plano, queda la iglesia de Santa Engracia y la calle de la Ronda. A la izquierda, un callej‚îú‚îÇn daba acceso a la huerta de Santa Engracia, en obras por la Expo de 1908. Tras el derribo de los edificios de la imagen, y durante el proceso de urbanizaci‚îú‚îÇn de los terrenos de la Exposici‚îú‚îÇn Hispano-Francesa, por aqu‚îú¬° se abrir‚îú√≠n las nuevas calles de Joaqu‚îú¬°n Costa y Don Hernando de Arag‚îú‚îÇn. Fuente: Revista "Nuevo Mundo"', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64904000, -0.88243700, '0101000020E6100000A5F8F884EC3CECBFDEE522BE13D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27014339404.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27014339404.webp', 'https://www.flickr.com/photos/zaragozaantigua/27014339404/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23674, 'Cuartel de Santa Engracia 1908', 'Interesante imagen capturada en uno de los tres grandes patios interiores del antiguo cuartel de Santa Engracia (el oriental), poco antes de su derribo, tras ser vendido al Ayuntamiento para incorporar este gran recinto al proyecto de urbanizaci‚îú‚îÇn de la antigua huerta de Santa Engracia. En primer plano, uno de los grandes pabellones cuarteleros. A la izquierda, acceso al patio noroeste, al que se ingresaba desde la plaza de Santa Engracia por la oscura puerta del fondo. M‚îú√≠s a la izquierda emerge la torre oriental de la iglesia parroquial de Santa Engracia. Fuente visual: revista "La Ilustraci‚îú‚îÇn Militar".', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64880900, -0.88217800, '0101000020E6100000A305685BCD3AECBFDC2C5E2C0CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33508601555.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33508601555.webp', 'https://www.flickr.com/photos/zaragozaantigua/33508601555/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24019, 'Calle Costa 1975', 'Entrada de la "Librer‚îú¬°a P‚îú‚îÇrtico" en la calle de Joaqu‚îú¬°n Costa n‚î¨‚ïë 2. En agosto de 1975, se produjo una explosi‚îú‚îÇn en este establecimiento, causando importantes da‚îú‚ñíos materiales. El propietario, Jos‚îú¬Æ Alcrudo, hubo de soportar ‚îú¬Æste y otros m‚îú√≠s en su Librer‚îú¬°a P‚îú‚îÇrtico de la plaza de San Francisco. Las sospechas apuntaron a grupos ultraderechistas interrelacionados, como la CEDADE, la editorial Fuerza Nueva o la Sociedad Cultural Covadonga. Casualmente, esta librer‚îú¬°a ten‚îú¬°a en sus escaparates libros sobre la Segunda Rep‚îú‚ïëblica y la guerra de 1936-39, tal vez algo desviados de la doctrina del R‚îú¬Ægimen, y d‚îú¬°as antes del atentado, dos j‚îú‚îÇvenes entraron a la librer‚îú¬°a para que distribuyera ejemplares del panfleto de Jorge Mota titulado "Hacia un socialismo europeo: ‚î¨‚îêFalange o comunismo?", a lo que el propietario les dijo: NO. La editora del panfleto era "BAU", as‚îú¬° denominada por el activista de al derecha extrema Ram‚îú‚îÇn Bau, primero de CEDADE, que luego deriv‚îú‚îÇ hacia el C‚îú¬°rculo de Estudios Indoeuropeos, y m‚îú√≠s recientemente, al apoyo a los c‚îú¬°rculos editoriales del nazismo europeo, como la cruzada de la Librer‚îú¬°a Europa, de Barcelona. Hasta bien entrados los a‚îú‚ñíos ochenta, los atentados fascistas continuaron en Zaragoza. Fuente: Agencia EFE.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.64911200, -0.88205000, '0101000020E610000044FAEDEBC039ECBF78B81D1A16D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24624011965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24624011965.webp', 'https://www.flickr.com/photos/zaragozaantigua/24624011965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24040, 'Asamblea Municipalista 1906', 'Entre el 9 y el 11 de febrero de 1906, en el teatro Pignatelli, tuvo lugar la Asamblea Municipalista de Zaragoza, donde se reunieron personalidades de la antigua corona de Arag‚îú‚îÇn vinculadas con la gesti‚îú‚îÇn de los ayuntamientos desde un punto de vista republicano. Por parte local, participaron activamente Marceliano Is‚îú√≠bal, y Jos‚îú¬Æ Gasc‚îú‚îÇn y Mar‚îú¬°n. Entre las conclusiones realizadas, destacaban la reivindicaci‚îú‚îÇn de la autonom‚îú¬°a municipal, de una hacienda municipal independiente de la provincial y nacional, de la municipalizaci‚îú‚îÇn de los servicios p‚îú‚ïëblicos, de la necesidad de un patrimonio municipal, de dar batalla al caciquismo, y de la jornada laboral de ocho horas para los trabajadores de los ayuntamientos. La medalla conmemorativa de la imagen, en bronce, fue esculpida por Parera/Rodr‚îú¬°guez, y en el anverso figura el busto aleg‚îú‚îÇrico de la Rep‚îú‚ïëblica, con una Marianne a la espa‚îú‚ñíola; en el reverso, una composici‚îú‚îÇn con las alegor‚îú¬°as de la Libertad, la Igualdad, y la Fraternidad. Fuente visual: www.museunacional.cat/', 1906, 1906, 1906, 'Anos 1900', 'CENTRO', 41.64914000, -0.88337800, '0101000020E61000003C3080F0A144ECBF4243FF0417D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30688545041.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30688545041.webp', 'https://www.flickr.com/photos/zaragozaantigua/30688545041/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24072, 'P.‚î¨‚ïë de la Independencia 1918', 'Posado de aristocr‚îú√≠ticas muchachas vestidas de gala a la usanza tradicionalista durante la celebraci‚îú‚îÇn del D‚îú¬°a de la Flor de ese a‚îú‚ñío, donde postulaban fondos para la asistencia a los tuberculosos pobres de la ciudad. La imagen ha sido capturada en el andador central del paseo de la Independencia, en la zona frontera ya con la plaza de Arag‚îú‚îÇn, donde se ha habilitado un ef‚îú¬°mera tribuna decorada con motivos vegetales, visible parcialmente a la derecha. Fuente visual: foto S‚îú√≠nchez Rom‚îú√≠n para diario ABC, en abcfoto.abc.es/', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.64896300, -0.88411900, '0101000020E61000000FB6D8EDB34AECBF33A8363811D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34400249342.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34400249342.webp', 'https://www.flickr.com/photos/zaragozaantigua/34400249342/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24086, 'Plaza Arag‚îú‚îÇn 1916', 'Vista de la plaza de Arag‚îú‚îÇn, con el Gobierno Civil en su n‚îú‚ïëmero 1 (centro). A la izquierda, calle de Bruil, y a la derecha, el hotelito con el n‚îú‚ïëmero 2. Hasta ah‚îú¬° llega una manifestaci‚îú‚îÇn "para entregar el mensaje de protesta de las clases productoras".', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.64878200, -0.88431300, '0101000020E61000004BAFCDC64A4CECBFE21DE0490BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43613097381.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43613097381.webp', 'https://www.flickr.com/photos/zaragozaantigua/43613097381/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24091, 'P.‚î¨‚ïë de la Independencia 1936', 'Imagen capturada en el paseo de la Independencia durante el desfile del Tercio de Do‚îú‚ñía Mar‚îú¬°a de las Nieves de requet‚îú¬Æs navarros reci‚îú¬Æn llegados desde Pamplona para reforzar en Zaragoza la sublevaci‚îú‚îÇn militar contra la Segunda Rep‚îú‚ïëblica Espa‚îú‚ñíola tras el 19 de julio de 1936. La llegada de estos combatientes se produjo el 23-24 de julio tras la iniciativa de Jes‚îú‚ïës Muro Sevilla, jefe local de Falange, que viaj‚îú‚îÇ a Pamplona y propici‚îú‚îÇ el env‚îú¬°o de un contingente de unos 1.200 requet‚îú¬Æs navarros, que llegaron a la ciudad en ferrocarril por la Estaci‚îú‚îÇn del Norte, y que luego fueron reubicados en funci‚îú‚îÇn de las necesidades de los sublevados. Fueron tambi‚îú¬Æn la base sobre la que se constituy‚îú‚îÇ la organizaci‚îú‚îÇn local del requet‚îú¬Æ aragon‚îú¬Æs. La escena tiene lugar en ‚îú‚ïëltimo tramo del antiguo paseo de la Independencia, llegando ya casi a la plaza de Arag‚îú‚îÇn. En el centro, la calle de Jos‚îú¬Æ Luis Albareda, flanqueada a la izquierda por el hotelito del n‚î¨‚ïë 13 de la plaza de Arag‚îú‚îÇn, y a la derecha por el gran inmueble del paseo en cuyos bajos estaba el Caf‚îú¬Æ Ambos Mundos (a la derecha, fuera de plano), el esquinero comercio Casa Polo de confecciones y tejidos, y la oficina donde entonces se ubicaba el "Institut Fran‚îú¬∫ais". En 1940 el Ayuntamiento decidi‚îú‚îÇ conmemorar estos hechos, redenominando la calle del Cinco de Marzo como Requet‚îú¬Æ Aragon‚îú¬Æs, y dando el nombre de Requet‚îú¬Æ Navarro a un vial en Las delicias que conectaba las avenidas de Madrid y de Navarra.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64894200, -0.88433500, '0101000020E61000003FA9F6E9784CECBF1B800D8810D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47268546201.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47268546201.webp', 'https://www.flickr.com/photos/zaragozaantigua/47268546201/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24101, 'Plaza de Santa Engracia c.1937', 'Ins‚îú‚îÇlita imagen capturada ante la puerta de la iglesia parroquial de Santa Engracia con un posado grupal realizado tras una ceremonia de boda celebrada en su interior, en el que destaca el jefe provincial de Falange, Jes‚îú‚ïës Muro Sevilla, que acompa‚îú‚ñía a la joven pareja reci‚îú¬Æn casada, falangista ella, falangista ‚îú¬Æl.', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.64910600, -0.88288600, '0101000020E6100000871403249A40ECBF96D1C8E715D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51178200016.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51178200016.webp', 'https://www.flickr.com/photos/zaragozaantigua/51178200016/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24106, 'Calle de Joaqu‚îú¬°n Costa 1937', 'Imagen capturada en la calle de Joaqu‚îú¬°n Costa y ante el Gran Hotel, durante la recepci‚îú‚îÇn que los jefes de Falange Espa‚îú‚ñíola Tradicionalista de las JONS organizaron con motivo de la visita a Zaragoza de una delegaci‚îú‚îÇn de las Juventudes Hitlerianas llegadas desde Alemania y que recorrieron diversas localidades de la Espa‚îú‚ñía nacionalista y algunos frentes de batalla. En el centro de la fotograf‚îú¬°a destaca la presencia de Jes‚îú‚ïës Muro, jefe territorial de FET-JONS, y a su lado Jes‚îú‚ïës Com‚îú¬°n, su Secretario de Organizaci‚îú‚îÇn. A la derecha, miembros de la colonia alemana en Zaragoza, del colegio y consulado alemanes. Detr‚îú√≠s de todos ellos, centurias de FET-JONS, Cadetes y Pelayos, que contaban con el acompa‚îú‚ñíamiento de bandas de m‚îú‚ïësica y la habitual parafernalia de emblemas y banderas falangistas y nacionalsocialistas. Al fondo, la calle de Isaac Peral.', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.64903300, -0.88174900, '0101000020E610000087FBC8AD4937ECBF2C836A8313D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51783816152.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51783816152.webp', 'https://www.flickr.com/photos/zaragozaantigua/51783816152/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24117, 'Paseo de la Independencia 1916', 'En el balc‚îú‚îÇn del primer piso del hotelito del n‚î¨‚ïë 13 de la plaza de Arag‚îú‚îÇn, una in‚îú¬Ædita captura para ilustrar la "manifestaci‚îú‚îÇn de las clases productoras" convocada el 10 de mayo de 1916 para protestar contra el Gobierno de la naci‚îú‚îÇn, en medio de una importante crisis de subsistencias agravada por la coyuntura b‚îú¬Ælica de la Gran Guerra. La manifestaci‚îú‚îÇn hab‚îú¬°a comenzado en la plaza de la Libertad y estaba prevista su finalizaci‚îú‚îÇn ante el Gobierno Civil sito en la plaza de Arag‚îú‚îÇn, donde se le entreg‚îú‚îÇ un mensaje al gobernador civil Juan Zab‚îú¬°a Bernad. En la imagen, el cortejo transita por el paseo de la Independencia, llegando a la altura de la calle de Jos‚îú¬Æ Luis Albareda, destacando cinco pancartas con una curiosa mezcolanza de mensajes: "El monopolio de los transportes anula la soberan‚îú¬°a popular", "Queremos ahora la unificaci‚îú‚îÇn de tarifas", "Exigiremos despu‚îú¬Æs la nacionalizaci‚îú‚îÇn de los ferrocarriles", "El arancel ha sido un seguro para la ineptitud de los sider‚îú‚ïërgicos" y "‚î¨√≠‚î¨√≠Quien paga manda, Se‚îú‚ñíor Conde, hay que gobernar!!" (referencia al Conde de Romanones, Presidente del Consejo de Ministros). Fuera de imagen y a la derecha quedaba la pancarta que abr‚îú¬°a la manifestaci‚îú‚îÇn: "‚î¨√≠‚î¨√≠Pol‚îú¬°ticos, escoged!! O las empresas explotadoras o el pueblo que no quiere explotadores". Hacia el fondo y a la derecha, luminosa presencia del gran inmueble del bar‚îú‚îÇn de la Rosa en el n‚î¨‚ïë 29 del paseo, esquinero con la plaza de Santa Engracia. En el contrastado fondo edilicio se destacan en altura las torres de la Seo y de la iglesia de San Gil Abad. En primer t‚îú¬Ærmino y a la izquierda, pegados en los porches del n‚î¨‚ïë 32 del paseo, dos carteles convocando junta general extraordinaria "A los alba‚îú‚ñíiles y peones asociados y no asociados" y "A los obreros pintores en general", reflejo tambi‚îú¬Æn de la conflictividad social que caracterizaba el mundo del trabajo, que el a‚îú‚ñío siguiente conocer‚îú¬°a la convocatoria de una Huelga General.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.64917000, -0.88414100, '0101000020E610000003B00111E24AECBFACC5A70018D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52777590061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52777590061.webp', 'https://www.flickr.com/photos/zaragozaantigua/52777590061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24152, '&quot;Expo 1908&quot;, 1907', 'Despejada imagen realizada por Casta‚îú‚ñíer-O‚îú‚ñía, que captura un instante de los trabajos preparatorios en los terrenos de la exposici‚îú‚îÇn Hispano-Francesa de 1908, en la que fuera huerta de Santa Engracia, as‚îú¬° denominada por formar parte del antiguo, Real y enorme monasterio jer‚îú‚îÇnimo de ese nombre. En este caso concreto, se trata de la obra de cimentaci‚îú‚îÇn del emblem‚îú√≠tico "Pabell‚îú‚îÇn Franc‚îú¬Æs", en la zona suroeste del recinto. Al fondo, traseras de los edificios de la calle San Miguel, entre los que destaca la chimenea de la el‚îú¬Æctrica ubicada entre las calles Porcell y Blancas. Fuente visual: Revista "Nuevo Mundo"', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64885900, -0.88124300, '0101000020E610000094861A852433ECBF8E5BCCCF0DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27617995885.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27617995885.webp', 'https://www.flickr.com/photos/zaragozaantigua/27617995885/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24270, 'Claustro de Santa Engracia 1844', 'Dibujo de Jenaro P‚îú¬Ærez Villaamil, sobre un croquis de Mariano Carderera, incluido luego en la obra "Espa‚îú‚ñía art‚îú¬°stica y monumental vistas y descripci‚îú‚îÇn de los sitios y monumentos m‚îú√≠s notables de Espa‚îú‚ñía". Fuente visual: Fondo Documental Hist‚îú‚îÇrico de las Cortes de Arag‚îú‚îÇn.', 1844, 1844, 1844, 'Siglo XIX', 'CENTRO', 41.64854400, -0.88261300, '0101000020E610000047C8409E5D3EECBF2E02637D03D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14691195229.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14691195229.webp', 'https://www.flickr.com/photos/zaragozaantigua/14691195229/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24275, 'Convento de Santa Engracia 1813', 'Ruinas del Real Monasterio de Santa Engracia, destruido parcialmente en los Sitios. En la imagen, aspecto visto desde la orilla derecha del r‚îú¬°o Huerva, al otro lado del puente de Santa Engracia. Fuente visual: Edward Hawke Locker, London, 1824', 1813, 1813, 1813, 'Siglo XIX', 'CENTRO', 41.64854400, -0.88261300, '0101000020E610000047C8409E5D3EECBF2E02637D03D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14874498102.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14874498102.webp', 'https://www.flickr.com/photos/zaragozaantigua/14874498102/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24283, 'Monasterio de Santa Engracia 1809', 'Episode du si‚îú¬øge de Saragosse : assaut du monast‚îú¬øre de San Engracia, le 8 f‚îú¬Ævrier 1809 (Asalto del Monasterio de Santa Engracia el 8 de febrero de 1809), Louis-Fran‚îú¬∫ois Lejeune, 1827. Desde 1808, Espa‚îú‚ñía hab‚îú¬°a establecido una compleja y amarga guerra contra los ocupantes franceses, animada por un fuerte sentido religioso (Napole‚îú‚îÇn fue se‚îú‚ñíalado como enemigo del catolicismo), din‚îú√≠stico (apego a los Borbones), y nacionalista (odio contra el ocupante extranjero) . Despu‚îú¬Æs de una victoria bastante f‚îú√≠cil sobre las tropas regulares espa‚îú‚ñíolas, los franceses toparon con la presencia de una fuerza expedicionaria brit‚îú√≠nica y los "guerrilleros" ind‚îú¬°genas, que les obligaron a mantener numerosas tropas de ocupaci‚îú‚îÇn. Despu‚îú¬Æs de un inicial fracaso, el ej‚îú¬Ærcito franc‚îú¬Æs conquist‚îú‚îÇ Zaragoza. En la imagen, Lejeune retrata el "Asalto del monasterio de San Engracia", donde captura la furia de la lucha entre el ej‚îú¬Ærcito franc‚îú¬Æs y los defensores de Zaragoza. Al fondo torre de la Enfermer‚îú¬°a conventual, y claustro grande del Monasterio de Santa Engracia, en la Huerta de Santa Engracia. Fuente: www.histoire-image.org/pleincadre/index.php?i=333', 1809, 1809, 1809, 'Siglo XIX', 'CENTRO', 41.64876200, -0.87993100, '0101000020E61000000892770E6528ECBF9B711AA20AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15176001446.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15176001446.webp', 'https://www.flickr.com/photos/zaragozaantigua/15176001446/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24286, 'Monasterio de Santa Engracia 1737', '"Descripci‚îú‚îÇn o mapa del Real Monasterio y Parroquia de Santa Engracia de Zaragoza", dibujo incluido en el libro "Origen y Antig‚îú‚ïùedades del Subterr‚îú√≠neo y celeb‚îú¬Ærrimo Santuario de Sta. Mar‚îú¬°a de las Santas Masas" (Le‚îú‚îÇn Benito Mart‚îú‚îÇn, Zaragoza, 1737). Vista de los terrenos del Monasterio de Santa Engracia de Zaragoza, con el r‚îú¬°o Huerva en primer plano y la inclusi‚îú‚îÇn de otros edificios conventuales cercanos, como el de las Madres Capuchinas, a la izquierda, o el de las Monjas de Santa Catalina, arriba a la derecha. En el centro, a la izquierda, la Puerta de Santa Engracia, situada en el entorno del actual paseo de la Independencia. Fuente: ifc.dpz.es/recursos/publicaciones/32/30/09morte.pdf', 1737, 1737, 1737, 'Siglo XIX', 'CENTRO', 41.64896100, -0.87984900, '0101000020E6100000BF620D17B927ECBF92B06F2711D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15458717915.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15458717915.webp', 'https://www.flickr.com/photos/zaragozaantigua/15458717915/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24289, 'Calle Joaqu‚îú¬°n Costa 1928', 'Postal, foto Jal‚îú‚îÇn, 1928. "Nueva Zaragoza. Calle de Costa". Esta imagen, en direcci‚îú‚îÇn al Paseo de la Independencia, no era tan contestada como la vista hacia el Paseo de la Mina, en que al final se ve‚îú¬°a el enorme dep‚îú‚îÇsito de "El Gas". Esa otra vista no ten‚îú¬°a tanta "clase". Fuente de la imagen: Foto Jal‚îú‚îÇn, en todocolecci‚îú‚îÇn.net.', 1928, 1928, 1928, 'Anos 20', 'CENTRO', 41.64911400, -0.88227400, '0101000020E61000002A8E03AF963BECBF18B0E42A16D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15640401851.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15640401851.webp', 'https://www.flickr.com/photos/zaragozaantigua/15640401851/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24292, 'Ruinas de Santa Engracia 1813', 'As‚îú¬° luc‚îú¬°an las ruinas del convento de Santa Engracia en una gu‚îú¬°a de viaje inglesa de 1880 titulada "Spanish pictures drawn with pen and pencil", si bien era una copia, con sus licencias y modificaciones, del dibujo que Eduard Hanke Locker hab‚îú¬°a realizado en 1813. Para los editores de la obra, ilustrar con im‚îú√≠genes de hac‚îú¬°a 67 a‚îú‚ñíos una obra actual, era normal. Como con la literatura oral, una copia de una copia puede acabar modificando bastante la realidad que pretende capturar. Las fuentes orales, y los dibujos, son as‚îú¬°.', 1813, 1813, 1813, 'Siglo XIX', 'CENTRO', 41.64854400, -0.88261300, '0101000020E610000047C8409E5D3EECBF2E02637D03D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15765993029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15765993029.webp', 'https://www.flickr.com/photos/zaragozaantigua/15765993029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24302, 'Espacio Goya 1999', 'Recreaci‚îú‚îÇn virtual del proyecto de Basilio Tob‚îú¬°as para instalar en 1999 el Espacio Goya en la antigua casa de Tom‚îú√≠s Castellano construida por Teodoro R‚îú¬°os en la Calle Costa 13 de Zaragoza. Fue desestimado por Ibercaja, la empresa promotora, que en 2015 redenomin‚îú‚îÇ con el nombre del pintor el Museo Cam‚îú‚îÇn Aznar, tras un intento fallido en 2006 de instalar el Espacio Goya en los edificios de la Escuela de Artes y el Museo de Zaragoza. Fuente visual: www.basiliotobias.com/', 1999, 1999, 1999, 'Anos 90', 'CENTRO', 41.64855500, -0.88024900, '0101000020E610000047C66AF3FF2AECBF2254A9D903D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19301307914.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19301307914.webp', 'https://www.flickr.com/photos/zaragozaantigua/19301307914/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24309, 'Santa Engracia 1737', '"Portada de Alabastro de la Yglesia de Sta. Engracia", dibujo incluido en el libro "Historia del subterr‚îú√≠neo Santuario oy Real Monasterio de Sta. Engracia de Zaragoza. Origen y Antig‚îú‚ïùedades del Subterr‚îú√≠neo y celeb‚îú¬Ærrimo Santuario de Sta. Mar‚îú¬°a de las Santas Masas", escrito por el Padre Fray Le‚îú‚îÇn Benito Mart‚îú‚îÇn y Aznar (Zaragoza, 1737). El notable inter‚îú¬Æs de este dibujo radica en que es una de las escasas representaciones de la original fachada del Monasterio, con sus "mud‚îú¬Æjares" torres y remate, adem‚îú√≠s de su renacentista portada, antes de convertirse en uno de los desastres de la guerra de 1808-1809 primero, y de la posguerra despu‚îú¬Æs. Fuente visual: Biblioteca Digital Hisp‚îú√≠nica bdh.bne.es/', 1737, 1737, 1737, 'Siglo XIX', 'CENTRO', 41.64908500, -0.88268800, '0101000020E6100000F14A92E7FA3EECBF7EA99F3715D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19779039645.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19779039645.webp', 'https://www.flickr.com/photos/zaragozaantigua/19779039645/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24312, 'Claustro de Santa Engracia 1808', '"Ruinas del patio de Santa Engracia, causadas por la explosi‚îú‚îÇn del 13 de agosto de 1808". Serie Ruinas de Zaragoza, de Juan G‚îú√≠lvez (dibujo) y Fernando Brambila (grabado), C‚îú√≠diz, 1812. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.64854400, -0.88261300, '0101000020E610000047C8409E5D3EECBF2E02637D03D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20550964379.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20550964379.webp', 'https://www.flickr.com/photos/zaragozaantigua/20550964379/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24316, 'Santa Engracia 1866', 'Iglesia de Santa Engracia. A la izquierda, garita del cuartel hom‚îú‚îÇnimo. Fuente: Mariano J‚îú‚ïëdez y Ortiz. Colecci‚îú‚îÇn Boisset-Ib‚îú√≠‚îú‚ñíez. Libro Primeros tiempos de la fotograf‚îú¬°a en Zaragoza.', 1866, 1866, 1866, 'Siglo XIX', 'CENTRO', 41.64916800, -0.88288700, '0101000020E61000009E08E23C9C40ECBF0CCEE0EF17D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27966267604.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27966267604.webp', 'https://www.flickr.com/photos/zaragozaantigua/27966267604/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24318, 'Educaci‚îú‚îÇn y Descanso 1976', 'La Obra Sindical Educaci‚îú‚îÇn y Descanso, versi‚îú‚îÇn patria inspirada en la fascista e italiana ‚îú√¥pera Nazionale Dopolavoro ("Obra nacional post-trabajo"), y en la nazi y alemana Kraft Durch Freude ("La fuerza por la alegr‚îú¬°a"), desde 1940 se propuso, mediante la programaci‚îú‚îÇn de actividades recreativas y de ocio, ganarse al obrero e integrar a los trabajadores en el r‚îú¬Ægimen impuesto tras el 1 de abril de 1939. Como otros tantos asuntos relacionados con el franquismo y el fascismo sociol‚îú‚îÇgico en su local desarrollo, y dado el nivel de conocimiento e informaci‚îú‚îÇn sobre esta organizaci‚îú‚îÇn, parecer‚îú¬°a que hubiera tenido lugar hace muchos siglos, cuando fue desmontada formalmente en 1976-77. En la imagen, la sede zaragozana del Club Educaci‚îú‚îÇn y Descanso, en la calle de Costa n‚î¨‚ïë 4. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.64880900, -0.88217800, '0101000020E6100000A305685BCD3AECBFDC2C5E2C0CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30924750986.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30924750986.webp', 'https://www.flickr.com/photos/zaragozaantigua/30924750986/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24321, 'Santa Engracia c.1930', 'Imagen centrada en una vista parcial de la fachada de la iglesia de Santa Engracia, que permite un breve vistazo, a la izquierda, en la calle Don Hernando de Arag‚îú‚îÇn, al convento y casa de las Religiosas de Mar‚îú¬°a Inmaculada, realizado con proyecto de Federico Arias Rey en 1913, y con acceso desde el paseo de la Mina. Las titulares perduran en esa ubicaci‚îú‚îÇn (luego, avenida de Marina Moreno), aunque en un edificio distinto, m‚îú√≠s moderno, ya en tiempos del paseo de la Constituci‚îú‚îÇn. Fuente visual: Foto Estudio Coyne, AHPZ.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64916800, -0.88288700, '0101000020E61000009E08E23C9C40ECBF0CCEE0EF17D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31524126312.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31524126312.webp', 'https://www.flickr.com/photos/zaragozaantigua/31524126312/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24326, 'Baptisterio siglo IV', 'Foto: Oliver Duch. Durante las excavaciones arqueol‚îú‚îÇgicas de 2008 que buscaban encontrar el primitivo pozo martirial de Santa Engracia (sin resultado), se hallaron los restos de un baptisterio del siglo IV. Se trata del vestigio arquitect‚îú‚îÇnico m‚îú√≠s antiguo del cristianismo encontrado en Zaragoza. En la foto, el yacimiento, a los pies de las escaleras que llevan a la cripta, en la iglesia de Santa Engracia. Fuente: Heraldo de Arag‚îú‚îÇn.', 350, 300, 399, 'Siglo XIX', 'CENTRO', 41.64889400, -0.88286700, '0101000020E6100000D7F6764B7240ECBF0A4966F50ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32835734406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32835734406.webp', 'https://www.flickr.com/photos/zaragozaantigua/32835734406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24327, 'Imperio Argentina 1998', 'La actriz Magdalena Nile del R‚îú¬°o, conocida como Imperio Argentina (1910-2003), saluda en la puerta del Gran Hotel en 1998. Hab‚îú¬°a sido pregonera de las fiestas en 1996. Fuente: Heraldo de Arag‚îú‚îÇn.', 1998, 1998, 1998, 'Anos 90', 'CENTRO', 41.64898400, -0.88166400, '0101000020E6100000FAEFC16B9736ECBF4AD05FE811D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33119272181.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33119272181.webp', 'https://www.flickr.com/photos/zaragozaantigua/33119272181/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24333, 'Gran Hotel 1928', 'Acci‚îú‚îÇn emitida en 1928 por la empresa Gran Hotel Zaragoza S A, cuyo presidente era Manuel de Escoriaza y Fabro. El establecimiento ser‚îú¬°a inaugurado en 1929, en el marco de la urbanizaci‚îú‚îÇn de la Huerta de Santa Engracia posterior a la Exposici‚îú‚îÇn Hispano-Francesa de 1908. El dibujo del edificio lo muestra desde la calle de Isaac Peral, con la entrada principal a la derecha, esquinera con la calle de Joaqu‚îú¬°n Costa. Fuente: www.todocoleccion.net', 1928, 1928, 1928, 'Anos 20', 'CENTRO', 41.64917400, -0.88148100, '0101000020E6100000B87361A41735ECBFEEB4352218D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39086135311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39086135311.webp', 'https://www.flickr.com/photos/zaragozaantigua/39086135311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24336, 'Plaza de Santa Engracia c.1927', 'Imagen centrada en la portada de la iglesia parroquial de Santa Engracia sita en la hom‚îú‚îÇnima plaza. A la izquierda, la calle de Don Hernando de Arag‚îú‚îÇn, donde destaca el solar del n‚î¨‚ïë 2 de la calle de Joaqu‚îú¬°n Costa, previo a la construcci‚îú‚îÇn del inmueble dise‚îú‚ñíado por Francisco Albi‚îú‚ñíana para albergar la sede del peri‚îú‚îÇdico La Voz de Arag‚îú‚îÇn. Detr‚îú√≠s, medianera del convento de las Religiosas de Mar‚îú¬°a Inmaculada, con ingreso principal por el paseo de la Mina. A la derecha, entrada a la calle de Tom‚îú√≠s Castellano.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64909800, -0.88283300, '0101000020E6100000D28BDAFD2A40ECBF13F3ACA415D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49923195407.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49923195407.webp', 'https://www.flickr.com/photos/zaragozaantigua/49923195407/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24338, 'Exposici‚îú‚îÇn 1908', 'Imagen de la Exposici‚îú‚îÇn Hispano-Francesa de 1908 centrada en la gran avenida central que con orientaci‚îú‚îÇn este-oeste estaba delimitada entre los pabellones de Tracci‚îú‚îÇn y de M‚îú√≠quinas, y las instalaciones especiales del Acumulador Tudor y de las Destiler‚îú¬°as Benedictinas, a la izquierda, y el pabell‚îú‚îÇn central de Alimentaci‚îú‚îÇn, a la derecha y fuera de plano. La multitud de sillas de primer t‚îú¬Ærmino estaban dispuestas para descanso de visitantes, y la avenida desemboca hacia la derecha en la plaza central donde destaca el Quiosco de la M‚îú‚ïësica, y tras ‚îú¬Æl el Pabell‚îú‚îÇn Franc‚îú¬Æs. Fuera del recinto emerge al fondo la iglesia de Santa Engracia.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64844800, -0.87992500, '0101000020E61000007FD93D795828ECBF0C94145800D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50023010682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50023010682.webp', 'https://www.flickr.com/photos/zaragozaantigua/50023010682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24507, 'P‚î¨‚ïë Independencia c.1955', 'Fachada de la tienda que la empresa de muebles y artes decorativas Sim‚îú‚îÇn Loscertales Bona manten‚îú¬°a en el paseo de la Independencia n‚î¨‚ïë 34 desde el comienzo de la d‚îú¬Æcada de los a‚îú‚ñíos 50, en los bajos del "Edificio Ambos Mundos", as‚îú¬° denominado por la imponente presencia (a la derecha, fuera de plano) del Gran Caf‚îú¬Æ Ambos Mundos, abierto en 1881, y cerrado en septiembre de 1955. Al fondo, la calle de Albareda, con vista parcial del antiguo y desaparecido hotelito correspondiente al n‚î¨‚ïë 13 de la plaza de Arag‚îú‚îÇn. En la inmediata parte trasera del edificio "Ambos Mundos", recayente a la calle de Ponzano, estaba emplazado un cuartel de la Polic‚îú¬°a Armada. Fuente visual: Archivo familiar Sim‚îú‚îÇn Loscertales Bona, en la exposici‚îú‚îÇn "Sim‚îú‚îÇn Loscertales Bona. Una firma emblem‚îú√≠tica", Centro de Historias de Zaragoza. Del 2 de febrero al 2 de abril de 2017.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64922000, -0.88437600, '0101000020E6100000E4C0ABE5CE4CECBF5EF415A419D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31992764283.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31992764283.webp', 'https://www.flickr.com/photos/zaragozaantigua/31992764283/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25106, 'Plaza de Arag‚îú‚îÇn 1929', 'Imagen capturada en el ingreso al hotelito del n‚î¨‚ïë 1 de la plaza de Arag‚îú‚îÇn donde estaba residenciado el Gobierno civil, con un posado colectivo durante uno de los actos organizados por los Ayuntamientos de la provincia, la Diputaci‚îú‚îÇn provincial, el partido pol‚îú¬°tico Uni‚îú‚îÇn Patri‚îú‚îÇtica y el Cuerpo de secretarios municipales, en homenaje al gobernador civil de la provincia, general Juan Cant‚îú‚îÇn Salazar con motivo del segundo aniversario de su designaci‚îú‚îÇn para tal cargo, el 16 de mayo de 1927, por la dictadura de Primo de Rivera. En la imagen, posado colectivo de una representaci‚îú‚îÇn de los Ayuntamientos de la provincia donde destaca en primer t‚îú¬Ærmino el alcalde de Zaragoza, Miguel Allu‚îú¬Æ Salvador, a la derecha de un art‚îú¬°stico ‚îú√≠lbum contenedor de las firmas de los alcaldes de todos los pueblos de la provincia, y tras ‚îú¬Æl el presidente de la Diputaci‚îú‚îÇn provincial, Patricio Borobio D‚îú¬°ez. El homenajeado figura a la izquierda del ‚îú√≠lbum. Como no pod‚îú¬°a ser de otra forma, el acto se convirti‚îú‚îÇ en una manifestaci‚îú‚îÇn de adhesi‚îú‚îÇn al gobernador civil, al Rey y al Gobierno.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.64866500, -0.88405600, '0101000020E610000076A4FACE2F4AECBFA987687407D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52441458110.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52441458110.webp', 'https://www.flickr.com/photos/zaragozaantigua/52441458110/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25282, 'Boda de los Foranos 1916', 'El peri‚îú‚îÇdico Heraldo de Arag‚îú‚îÇn public‚îú‚îÇ en su edici‚îú‚îÇn del 12 de octubre de 1916 una noticia con fotograf‚îú¬°a muy propia de la Zaragoza del siglo XIX... XX, acerca de la celebraci‚îú‚îÇn de la boda de dos de los "cabezudos" de la comparsa de Zaragoza: la Forana y el Forano, con el titular de "Los Foranos reci‚îú¬Æn casados y su comitiva nupcial". En la imagen la calesa en la que viajan los dos mo‚îú‚ñíacos tras sus imaginarias nupcias, son paseados por la ciudad, ahora saliendo de la calle de Juan Bruil y entrando en la de Independencia, para acercarse al Hotel Oriente, en el Coso 11-13, a que coman los humanos que hay debajo de los cabezudos. El edificio de la esquina de los porches se corresponde con el n‚î¨‚ïë 37 del paseo, realizado en ecl‚îú¬Æctico estilo radicalmente "reformado" en el a‚îú‚ñío 1952, cuando se instale en sus bajos la sede de una entidad local bancaria.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.64882000, -0.88410200, '0101000020E61000008D800A47904AECBFD07EA4880CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15273868718.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15273868718.webp', 'https://www.flickr.com/photos/zaragozaantigua/15273868718/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25290, 'Remolacheros 1914', 'Manifestaci‚îú‚îÇn en el paseo de la Independencia, frente al Gobierno Civil (plaza de Arag‚îú‚îÇn 1), reivindicando la apertura del ferrocarril de Canfranc por parte de los remolacheros zaragozanos. A‚îú‚ïën quedaban otros 14 a‚îú‚ñíos para la inauguraci‚îú‚îÇn.', 1914, 1914, 1914, 'Anos 10', 'CENTRO', 41.64882000, -0.88410200, '0101000020E61000008D800A47904AECBFD07EA4880CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15717513868.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15717513868.webp', 'https://www.flickr.com/photos/zaragozaantigua/15717513868/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25292, 'Antiguo Hotel Regina 1936', 'AHPZ. Manuel Coyne Buil. 1936. "Grupo de gente de Acci‚îú‚îÇn Ciudadana con otros paisanos junto a un cami‚îú‚îÇn de suministros a las tropas procedente del barrio de Casetas." Imagen capturada en la calle Bruil, ante la fachada del antiguo Hotel Regina, que desde 1919 ven‚îú¬°a siendo utilizado como local de una Academia Preparatoria militar. Improvisado "castellet" de facciosos nacionalistas de la ciudad y la periferia, tras el fallido golpe de Estado de julio de 1936.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64854400, -0.88349800, '0101000020E6100000E59A02999D45ECBF2E02637D03D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15921436161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15921436161.webp', 'https://www.flickr.com/photos/zaragozaantigua/15921436161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25318, 'P.‚î¨‚ïë de la Independencia 1928', 'Paseo de la Independencia. A la izquierda, la calle de Albareda. En el centro del bulevar, el cenotafio "A los funcionarios muertos en agosto de 1920", en esa ubicaci‚îú‚îÇn hasta 1961. Fuente visual: Foto Conrado Barl‚îú¬Æs, donada por Daniel Barl‚îú¬Æs y digitalizada por Jos‚îú¬Æ Luis Cintora para www.rafaelcastillejo.com', 1928, 1928, 1928, 'Anos 20', 'CENTRO', 41.64899200, -0.88430300, '0101000020E6100000672618CE354CECBFCDAE7B2B12D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23245809555.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23245809555.webp', 'https://www.flickr.com/photos/zaragozaantigua/23245809555/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25327, '8 de marzo de 1936', 'Arenga feminista frente al Gobierno Civil cuando ‚îú¬Æste se ubicaba en el n‚î¨‚ïë 1 de la plaza de Arag‚îú‚îÇn, durante la manifestaci‚îú‚îÇn de la Jornada Internacional de la Mujer, convocada por las organizaciones de la izquierda frentepopulista zaragozana el 8 de marzo de 1936, que con gran afluencia de p‚îú‚ïëblico, se convirti‚îú‚îÇ de facto en el primer "8 de marzo" celebrado en la ciudad como D‚îú¬°a Internacional de la Mujer y ‚îú‚ïëltimo hasta finales de los a‚îú‚ñíos 70. Tras la sublevaci‚îú‚îÇn mon‚îú√≠rquica, militar y fascista respaldada por el r‚îú¬Ægimen de Mussolini en julio de ese mismo a‚îú‚ñío y durante muchas d‚îú¬Æcadas, la presencia de la mujer en puestos destacados en la sociedad civil fue reducida a algunos elementos cosm‚îú¬Æticos. En la imagen, Josefina L‚îú‚îÇpez, de las Juventudes Comunistas, en uno de los m‚îú¬°tines al p‚îú‚ïëblico asistente. Al fondo y a la derecha, calle de Jos‚îú¬Æ Luis Albareda en su confluencia con el paseo de la Independencia, con detalle de la fachada del esquinero "hotelito" del n‚î¨‚ïë 13 de la plaza de Arag‚îú‚îÇn.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64894400, -0.88429300, '0101000020E6100000849D62D5204CECBFBC77D49810D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24102074002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24102074002.webp', 'https://www.flickr.com/photos/zaragozaantigua/24102074002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25351, 'Vista a‚îú¬Ærea Independencia c.1968', 'Vista a‚îú¬Ærea del paseo de la Independencia. Abajo, avenida de Calvo Sotelo. Arriba, plaza de Espa‚îú‚ñía. Fuente visual: foto Pedro Marco.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64901900, -0.88433900, '0101000020E61000009A79724D814CECBFC7BDF90D13D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33313932290.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33313932290.webp', 'https://www.flickr.com/photos/zaragozaantigua/33313932290/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25518, 'Arco Triunfal 1903', 'Imagen del primero de los tres arcos triunfales construidos en la calle de la Independencia, con motivo de la visita del rey Alfonso XIII durante las fiestas del Pilar del a‚îú‚ñío 1903. Esta muestra de arquitectura ef‚îú¬°mera y festiva fue costeada por la Quinta Regi‚îú‚îÇn Militar del ej‚îú¬Ærcito, realiz‚îú√≠ndose en las instalaciones de Pontoneros con dise‚îú‚ñío de dos capitanes del cuerpo de ingenieros, y otro del de artiller‚îú¬°a. El resultado final fue un liviano portal ornado con motivos castrenses varios, y un estilo muy en l‚îú¬°nea con el "art nouveau" entonces en moda. Este arco fue instalado en las inmediaciones de la glorieta de Pignatelli, entre el caf‚îú¬Æ "Ambos Mundos", a la izquierda, y el teatro Pignatelli, a la derecha. Al fondo, el segundo de los arcos triunfales construidos para la ocasi‚îú‚îÇn: el costeado por el Ayuntamiento, con dise‚îú‚ñío de Ricardo Magdalena, levantado a la altura de la calle Zurita. M‚îú√≠s al fondo, ya casi en la plaza de la Constituci‚îú‚îÇn, fue instalado el tercero y ‚îú‚ïëltimo de los arcos, de la Maestranza. Fuente visual: www.todocoleccion.net/', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.64918800, -0.88402200, '0101000020E610000071395E81E849ECBF537AA69718D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27757280490.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27757280490.webp', 'https://www.flickr.com/photos/zaragozaantigua/27757280490/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25858, 'Teatro Pignatelli 1889', '"Saragosse. Th‚îú¬Æ‚îú√≥tre de Pignatelli et Promenade de Sta. Engracia". J. L‚îú¬Ævy et Cie, 1889. Agence Roger-Viollet, Par‚îú¬°s. Fuente: Zaragoza en la memoria ajena.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.64921800, -0.88363400, '0101000020E6100000FA4674CFBA46ECBFBDFC4E9319D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14701173560.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14701173560.webp', 'https://www.flickr.com/photos/zaragozaantigua/14701173560/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25859, 'Teatro Pignatelli 1878', 'Fondo Documental Hist‚îú‚îÇrico de las Cortes de Arag‚îú‚îÇn. 1878. Zaragoza: exterior del "Teatro de Pignatelli", construido en la calle de la Independencia bajo la direcci‚îú‚îÇn del arquitecto F‚îú¬Ælix Navarro.', 1878, 1878, 1878, 'Siglo XIX', 'CENTRO', 41.64892100, -0.88367500, '0101000020E61000009E5E29CB1047ECBF0458E4D70FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14854429926.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14854429926.webp', 'https://www.flickr.com/photos/zaragozaantigua/14854429926/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25904, 'Glorieta de Pignatelli 1902', 'Un tranv‚îú¬°a de San Sebasti‚îú√≠n que fue desplazado a Zaragoza para la inauguraci‚îú‚îÇn de la electrificaci‚îú‚îÇn del tranv‚îú¬°a de Torrero llega a la glorieta de Pignatelli (hoy plaza de Arag‚îú‚îÇn) en 1902. Al fondo, edificio anexo al de Capitan‚îú¬°a (fuera de plano). Fuente: www.facebook.com/photo.php?fbid=1656961051213358&set=...', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.64899200, -0.88430300, '0101000020E6100000672618CE354CECBFCDAE7B2B12D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21295133555.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21295133555.webp', 'https://www.flickr.com/photos/zaragozaantigua/21295133555/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25923, 'Plaza de Arag‚îú‚îÇn 1968', 'Imagen centrada en la trolebusera unidad n‚î¨‚ïë 51 (adquirida a la British Union Transport) en servicio en la l‚îú¬°nea "Ciudad Jard‚îú¬°n", camino de la terminal de la plaza de Santa Engracia. La captura se ha realizado entre la plaza de Arag‚îú‚îÇn, y el desemboque en ella del paseo de la Independencia. Tras el trolebus, la mutante manzana entre las calles Juan Bruil y Agustina Sim‚îú‚îÇn, con el obraje del moderno bloque n‚î¨‚ïë 4 de Juan Bruil, levantado donde estuviera el antiguo hotel Regina. El que fuera hotelito sede del antiguo y derribado Gobierno Civil, ahora era solar del que ya emergen pilares encofrados que soportar‚îú√≠n el nuevo n‚î¨‚ïë 1 de la plaza de Arag‚îú‚îÇn. A la derecha, imagen del hotelito del n‚î¨‚ïë 2 de la plaza, sustituido m‚îú√≠s tarde por otra colmena moderna.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64896300, -0.88411900, '0101000020E61000000FB6D8EDB34AECBF33A8363811D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33369244030.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33369244030.webp', 'https://www.flickr.com/photos/zaragozaantigua/33369244030/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26079, 'Vista desde Santa Engracia c.1902', 'Vista capturada desde la altura de las torres de la iglesia de Santa Engracia, con orientaci‚îú‚îÇn hacia el norte.', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.64910600, -0.88288600, '0101000020E6100000871403249A40ECBF96D1C8E715D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53817472928.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53817472928.webp', 'https://www.flickr.com/photos/zaragozaantigua/53817472928/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21193, 'Calle de Puigcerd‚îú√≠ 1893', 'Impagable imagen de un coche de caballos descubierto y estacionado en la calle de Puigcerd‚îú√≠ ante los talleres de la Sociedad Bastos y Laguna, formada por los industriales Atilano Bastos y Amado Laguna de Rins, y constructora de instrumentos de precisi‚îú‚îÇn, matem‚îú√≠ticos, topogr‚îú√≠ficos y geod‚îú¬Æsicos desde 1883. En esta ubicaci‚îú‚îÇn, sita en el hotelito del n‚î¨‚ïë 5 de la plaza de Arag‚îú‚îÇn donde resid‚îú¬°a Atilano, antes estuvieron los talleres de Bastos y Compa‚îú‚ñí‚îú¬°a, y pocos a‚îú‚ñíos despu‚îú¬Æs y tras la adquisici‚îú‚îÇn por parte de Laguna de Rins de la parte de la sociedad de Bastos, esta empresa se trasladar‚îú¬°a al camino de los Cubos, al terreno ocupado por la Torre de Laguna, desarrollando una exitosa carrera empresarial. A la izquierda, muro de cierre de la calle tras el que flu‚îú¬°a al aire el r‚îú¬°o Huerva. Por encima sobresale el gran colegio del Salvador, al otro lado del r‚îú¬°o.', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64798300, -0.88417400, '0101000020E6100000F226BF45274BECBF97AE601BF1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50130741077.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50130741077.webp', 'https://www.flickr.com/photos/zaragozaantigua/50130741077/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21206, 'Exposici‚îú‚îÇn 1908', 'AHPZ. Archivo Coyne. 1908. Exposici‚îú‚îÇn Hispano-Francesa de 1908. Monumental puerta de acceso principal, situada en el antiguo paseo de la Mina, donde hoy confluyen las calles de Mariano Escar con paseo de la Constituci‚îú‚îÇn.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64787900, -0.88053700, '0101000020E6100000DD5F3DEE5B2DECBFF261F6B2EDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14834912587.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14834912587.webp', 'https://www.flickr.com/photos/zaragozaantigua/14834912587/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21224, 'Expo 1908', 'Imagen de una placa met‚îú√≠lica conmemorativa de la Exposici‚îú‚îÇn Hispano-Francesa de 1908, realizada por el escultor franc‚îú¬Æs Dautel Pierre-Victor. Entre los aleg‚îú‚îÇricos motivos de la imagen, de fondo, la puerta de acceso a la Exposici‚îú‚îÇn, situada en el antiguo paseo de la Mina, donde hoy confluyen las calles de Mariano Escar con el paseo de la Constituci‚îú‚îÇn. Fuente visual: Minist‚îú¬øre de la Culture (France) - M‚îú¬Ædiath‚îú¬øque de l''architecture et du patrimoine - diffusion RMN', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64787900, -0.88053700, '0101000020E6100000DD5F3DEE5B2DECBFF261F6B2EDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16281568145.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16281568145.webp', 'https://www.flickr.com/photos/zaragozaantigua/16281568145/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21237, 'Exposici‚îú‚îÇn Hispano Francesa 1908', '"Exposici‚îú‚îÇn de Zaragoza". Serie de catorce tarjetas postales que reproducen acuarelas de F‚îú¬Ælix Lafuente con motivos de la Exposici‚îú‚îÇn Hispano Francesa de 1908, celebrada en la Huerta de Santa Engracia. Fuente: paisajesviajados.com', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64787900, -0.88053700, '0101000020E6100000DD5F3DEE5B2DECBFF261F6B2EDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19587060776.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19587060776.webp', 'https://www.flickr.com/photos/zaragozaantigua/19587060776/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21238, 'Salida Exposici‚îú‚îÇn Hispano Francesa 1908', 'Foto: Ignacio Coyne, 1908. "Pabell‚îú‚îÇn de El‚îú¬Æctricas Reunidas". En realidad, puerta de acceso a la Exposici‚îú‚îÇn Hispano Francesa de Zaragoza, vista desde dentro del recinto. Fuente: dara.aragon.es/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64787900, -0.88053700, '0101000020E6100000DD5F3DEE5B2DECBFF261F6B2EDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19614562941.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19614562941.webp', 'https://www.flickr.com/photos/zaragozaantigua/19614562941/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21294, 'Exposici‚îú‚îÇn 1908', 'Imagen de la puerta de ingreso a la Exposici‚îú‚îÇn Hispano-Francesa de 1908 capturada desde el exterior del recinto, en el terroso paseo de la Mina. Bajo el arco rebajado de entrada (en el que aparece rotulada la indicaci‚îú‚îÇn "EXPOSICI‚îú√¥N HISPANO FRANCESA") se atisba en furioso contraste lum‚îú¬°nico el jard‚îú¬°n central y la fuente art‚îú¬°stica realizada por el escultor Dionisio Lasu‚îú¬Æn y, al fondo, el Pabell‚îú‚îÇn de Alimentaci‚îú‚îÇn o pabell‚îú‚îÇn destinado a exposici‚îú‚îÇn de productos alimenticios. En primer t‚îú¬Ærmino, un lujoso coche de caballos (posiblemente un "Victoria") con el conductor aguardando el regreso de su se‚îú‚ñíor. Fuente visual: Archivo fotogr‚îú√≠fico hist‚îú‚îÇrico del SIPA, en AHPZ.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64775300, -0.88020300, '0101000020E610000031EA5A7B9F2AECBF6571FF91E9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30160461757.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30160461757.webp', 'https://www.flickr.com/photos/zaragozaantigua/30160461757/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21296, 'Expo 1908', 'Imagen de la Exposici‚îú‚îÇn Hispano Francesa de 1908 obtenida, posiblemente, desde la circular terracilla que culminaba el Pabell‚îú‚îÇn de la Alimentaci‚îú‚îÇn, con el objetivo orientado hacia el sur, y centrado en la puerta principal de acceso a la muestra expositiva, habilitada en la antigua Huerta de Santa Engracia. A la izquierda, el pabell‚îú‚îÇn de Maquinaria, y a la derecha, el de Tracci‚îú‚îÇn, junto al que destaca, en primer plano, el pabell‚îú‚îÇn particular de la TUDOR. Tras la puerta de ingreso, el arbolado paseo de la Mina y el cauce al aire del Huerva. Al fondo, a la izquierda, la chimenea de una de las harineras ubicadas en la gran curva del r‚îú¬°o previa a las instalaciones del Gas‚îú‚îÇmetro. Fuente visual: Ignacio Coyne, en www.todocoleccion.net/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64775300, -0.88020300, '0101000020E610000031EA5A7B9F2AECBF6571FF91E9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31513921262.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31513921262.webp', 'https://www.flickr.com/photos/zaragozaantigua/31513921262/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21321, 'Exposici‚îú‚îÇn de 1908', 'Imagen capturada en la Gran Plaza de ingreso a la Exposici‚îú‚îÇn Hispano-Francesa de 1908 y centrada en la ef‚îú¬°mera y art‚îú¬°stica fuente proyectada por el escultor Dionisio Lasu‚îú¬Æn en formas naturalistas y ornada con motivos simb‚îú‚îÇlicos y mitol‚îú‚îÇgicos. Esta fuente estaba situada en el centro de la Gran Plaza de la muestra, entre peque‚îú‚ñíos jardines de factura inglesa realizados por la Secci‚îú‚îÇn de Jardiner‚îú¬°a del Ayuntamiento. Al fondo, gran fachada del Pabell‚îú‚îÇn de Alimentaci‚îú‚îÇn rematado por las banderas nacionales del Reino de Espa‚îú‚ñía y de la Rep‚îú‚ïëblica de Francia. Entre las naturalizadas columnas de la fuente, vista parcial de la instalaci‚îú‚îÇn del Acumulador Tudor, y de la chimenea de la central el‚îú¬Æctrica secundaria de la Compa‚îú‚ñí‚îú¬°a Aragonesa de Electricidad ubicada en la calle de San Miguel. A la izquierda, el Pabell‚îú‚îÇn de Maquinaria. Fuente visual: foto Ignacio Coyne (Archivo Coyne), en AHPZ.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64792900, -0.87996700, '0101000020E61000003BE5D18DB028ECBFA3906456EFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44242483485.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44242483485.webp', 'https://www.flickr.com/photos/zaragozaantigua/44242483485/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21322, 'Exposici‚îú‚îÇn 1908', 'Imagen de la puerta de ingreso a la Exposici‚îú‚îÇn Hispano-Francesa de 1908, capturada desde el interior del recinto, junto al arranque del jard‚îú¬°n central donde fue emplazada la llamativa fuente art‚îú¬°stica realizada por el escultor Dionisio Lasu‚îú¬Æn. Al fondo, el arbolado paseo de La Mina paralelo al cauce al aire del r‚îú¬°o Huerva. Esta puerta fue proyectada con aires modernistas por el arquitecto Ricardo Magdalena al modo de los ef‚îú¬°meros arcos triunfales construidos para conmemorar temporalmente un evento. Fuente visual: Archivo fotogr‚îú√≠fico hist‚îú‚îÇrico del SIPA, en AHPZ.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64775300, -0.88020300, '0101000020E610000031EA5A7B9F2AECBF6571FF91E9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45022523842.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45022523842.webp', 'https://www.flickr.com/photos/zaragozaantigua/45022523842/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21433, 'P.‚î¨‚ïë de los Pl‚îú√≠tanos 1911', 'Imagen capturada entre las humeantes ruinas de la f‚îú√≠brica de camas de la viuda de Daroca sita en el paseo de los Pl‚îú√≠tanos, devastada por un incendio que se hab‚îú¬°a iniciado en el vecino taller de ebanister‚îú¬°a de Garc‚îú¬°a y Vald‚îú¬Æs, se propag‚îú‚îÇ a la f‚îú√≠brica de tintes de Cea, y lleg‚îú‚îÇ hasta la referida f‚îú√≠brica de camas, donde los bomberos e ingenieros pontoneros pudieron finalmente extinguirlo y evitar que se extendiera a la f‚îú√≠brica de clari‚îú‚îÇn de Victoriano Casanada. Fuente visual: El fot‚îú‚îÇgrafo Luis Gand‚îú‚ïë Mercadal. Una cr‚îú‚îÇnica visual 1910-1930.', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.64702300, -0.88093200, '0101000020E6100000F4FE3F4E9830ECBF416150A6D1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37034196870.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37034196870.webp', 'https://www.flickr.com/photos/zaragozaantigua/37034196870/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21488, 'Huerva al aire 1926', 'Aspecto del Huerva fluyendo por la ciudad antes del cubrimiento. La imagen captura el puente de paso que se‚îú‚ñíalaba el punto, en las traseras de la iglesia de Santa Engracia, donde arrancaba el Paseo de la Mina hacia la derecha. A la izquierda, cruzando el puente, comenzaba el Camino de los Pl‚îú√≠tanos, a la sombra del colegio de los Jesuitas.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.64814400, -0.88273600, '0101000020E6100000340F60915F3FECBFA08CF161F6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15136358486.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15136358486.webp', 'https://www.flickr.com/photos/zaragozaantigua/15136358486/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21645, 'Plaza de Castelar c.1923', 'Imagen de la plaza de Castelar durante su etapa como estacional recinto de ferias y atracciones de la ciudad durante el verano, bajo la denominaci‚îú‚îÇn de Saturno Park. La captura se ha realizado sobre la despejada manzana sin urbanizar al sur de la prolongaci‚îú‚îÇn de la calle de Joaqu‚îú¬°n Costa, donde pocos a‚îú‚ñíos despu‚îú¬Æs se barajar‚îú¬°a la posibilidad de construir el nuevo edificio del ayuntamiento. Al fondo, el arbolado paseo de la Mina y chimeneas emergentes del otro lado del r‚îú¬°o Huerva.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.64801500, -0.88012900, '0101000020E61000009F5BE84A042AECBFA228D027F2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51250000040.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51250000040.webp', 'https://www.flickr.com/photos/zaragozaantigua/51250000040/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21777, 'Plaza Castelar 1934', 'Solar sin construir de la Plaza de Castelar, en el que estaba previsto construir el nuevo edificio del Ayuntamiento. Al fondo, el edificio del Museo Provincial. A la derecha, continuaci‚îú‚îÇn de la calle de Costa. Fuente visual: Foto Conrado Barl‚îú¬Æs, donada por Daniel Barl‚îú¬Æs y digitalizada por Jos‚îú¬Æ Luis Cintora para www.rafaelcastillejo.com', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.64817400, -0.87986200, '0101000020E6100000E7C75F5AD427ECBF0A0F9A5DF7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22950781010.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22950781010.webp', 'https://www.flickr.com/photos/zaragozaantigua/22950781010/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21812, 'Av. Gal‚îú√≠n y Garc‚îú¬°a Hern‚îú√≠ndez 1933', '"Urbanizaci‚îú‚îÇn de la Gran V‚îú¬°a sobre el cubrimiento del r‚îú¬°o Huerva (secci‚îú‚îÇn 2‚î¨¬¨)", Miguel ‚îú√ºngel Navarro, mayo de 1933. Plano del proyecto de urbanizaci‚îú‚îÇn del cubrimiento del r‚îú¬°o Huerva en el tramo de la "Gran V‚îú¬°a" luego llamado avenida de Gal‚îú√≠n y Garc‚îú¬°a Hern‚îú√≠ndez, denominaci‚îú‚îÇn sustituida en el franquismo por la de Marina Moreno. En rojo, las manzanas que habr‚îú√≠n de construirse en el entorno del antiguo paseo de los Pl‚îú√≠tanos. Fuente visual: Archivo Municipal de Zaragoza.', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.64816900, -0.88255800, '0101000020E610000064575A46EA3DECBFF9A3A833F7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30485451106.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30485451106.webp', 'https://www.flickr.com/photos/zaragozaantigua/30485451106/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21914, 'C.‚î¨‚ïë de las Torres c.1935', 'In‚îú¬Ædita imagen centrada en las instalaciones de la Industria Lanera S.A. localizada en el n‚îú‚ïëmero 121 del camino de las Torres. En primer t‚îú¬Ærmino, la huerta del gran recinto del convento-colegio de los PP. Agustinos, desde donde se ha tomado la fotograf‚îú¬°a. Esta f‚îú√≠brica y la huerta se abastec‚îú¬°an del agua proporcionada por la acequia de las Adulas o de San Jos‚îú¬Æ que flu‚îú¬°a al aire en paralelo por el camino de las Torres (leve vista de este camino a la izquierda). Tras la f‚îú√≠brica, edificio que esquinaba la desembocadura del paseo de Sasera (actual paseo de las Damas) donde destaca una vista parcial del antiguo convento-noviciado de la Congregaci‚îú‚îÇn de las Hermanas Oblatas del Sant‚îú¬°simo Redentor. En el centro y al fondo se perfilan algunas torres de las iglesias y las dos catedrales del centro de la ciudad.', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.64272400, -0.88169500, '0101000020E6100000BB7EC16ED836ECBF5A2DB0C744D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53198982460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53198982460.webp', 'https://www.flickr.com/photos/zaragozaantigua/53198982460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21995, 'Av. Marina Moreno 1941', 'Bajo una intensa solanera, y mientras la Uni‚îú‚îÇn Sovi‚îú¬Ætica estaba siendo invadida por la Alemania nazi, la 10‚î¨¬¨ etapa de la III‚î¨¬¨ Vuelta Ciclista a Espa‚îú‚ñía, con salida en Barcelona, lleg‚îú‚îÇ a la l‚îú¬°nea de meta establecida en Zaragoza. En la imagen, en la avenida de Marina Moreno, el vencedor de la etapa, Delio Rodr‚îú¬°guez (a la izquierda), tras casi 11 apalizantes horas y cuarto al pedal, junto a otros destacados corredores, como Ferm‚îú¬°n Trueba "el Mini", l‚îú¬°der provisional de la clasificaci‚îú‚îÇn general. En la tribuna del fondo, para autoridades y jerarqu‚îú¬°as locales, entusiastas se‚îú‚ñíoritas de la Secci‚îú‚îÇn Femenina de Falange posan con sus impecables camisas azules, tras su desempe‚îú‚ñío en la ofrenda floral a los velocipedistas. Organiz‚îú‚îÇ el evento la Obra Sindical Educaci‚îú‚îÇn y Descanso. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1941, 1941, 1941, 'Anos 40', 'CENTRO', 41.64809200, -0.88222300, '0101000020E6100000A2ED98BA2B3BECBF4D66BCADF4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32082434553.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32082434553.webp', 'https://www.flickr.com/photos/zaragozaantigua/32082434553/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22107, 'Convento Oblatas c.1957', 'En 1865 comenz‚îú‚îÇ sus andanzas mundanales la "Congregaci‚îú‚îÇn de las Hermanas Oblatas del Sant‚îú¬°simo Redentor", que llegaron a la ciudad unos a‚îú‚ñíos despu‚îú¬Æs, y en 1887 fundaron su convento-noviciado en los terrenos de la hasta entonces "Torre de Ponte", al final de un antiguo camino que entonces empezaba a ser conocido como "Paseo de las Damas". All‚îú¬° se levant‚îú‚îÇ un conjunto conventual destacable, con sus huertos y campos de cultivo, con una capilla provisional y un asilo para "desamparadas". En 1909 inauguraron all‚îú¬° unos locales para enfermer‚îú¬°a, y en 1910 abrieron un nuevo edificio para el noviciado y una nueva capilla. Desde 1939 ejerci‚îú‚îÇ de "asilo" de mujeres que eran all‚îú¬° recluidas a la espera de juicio por no apoyar el golpe militar de julio de 1936. A finales de los a‚îú‚ñíos 40, su estado de ruina llev‚îú‚îÇ a la Congregaci‚îú‚îÇn a construir un nuevo noviciado en Pamplona. El presente edificio fue derribado y, tras vender algo m‚îú√≠s de la mitad del original terreno, fue construido uno nuevo a comienzos de la prodigiosa d‚îú¬Æcada de los 60, ahora como una estructura achaflanada con el Camino de las Torres, que a su vez tambi‚îú¬Æn fue derribada tras venderla a buen postor, y no alcanz‚îú‚îÇ a ver el no menos atractivo siglo XXI. En la imagen, el convento-noviciado capturado desde la atalaya de la torre capuchino-italiana de San Antonio. El color amarillo es un a‚îú‚ñíadido no original. Justo a la izquierda de la iglesia conventual, el actual n‚î¨‚ïë 27 de la calle de la Paz. Delante, las curiosas edificaciones de la calle Vista Alegre, restos del "Barrio de los Chiflaos", que parecen tener continuidad en el colegio-convento de los PP. Agustinos. A su derecha, la chimenea de la f‚îú√≠brica textil "Lanera Aragonesa". Fuente visual: "Los tranv‚îú¬°as de Zaragoza", J. Pe‚îú‚ñía-J.M. Valero, 1985, DPZ.', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.64357400, -0.88263900, '0101000020E61000009692E524943EECBF284701A260D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21442159240.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21442159240.webp', 'https://www.flickr.com/photos/zaragozaantigua/21442159240/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22129, 'Av. Marina Moreno 1951', 'Imagen de la avenida de Marina Moreno a la altura de la nueva calle de San Ignacio de Loyola, en torno a la cual se estaba produciendo, poco a poco, la urbanizaci‚îú‚îÇn de la antigua zona residencial y fabril del paseo de los Pl‚îú√≠tanos (tras los edificios). Unos pocos a‚îú‚ñíos antes hab‚îú¬°a sido inaugurado el edificio pionero de la nueva sede de la Delegaci‚îú‚îÇn Provincial de Sindicatos (centro de la imagen). Al fondo, a la izquierda, el antiguo edificio del colegio del Sagrado Coraz‚îú‚îÇn, en el paseo de la Mina, en cuyas inmediaciones finalizaba el cubrimiento del r‚îú¬°o Huerva. Fuente visual: Archivo Construcciones y Auxiliar de Ferrocarriles (DARA-AHPZ)', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64781500, -0.88258600, '0101000020E6100000E109BDFE243EECBFDB6D179AEBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23353348304.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23353348304.webp', 'https://www.flickr.com/photos/zaragozaantigua/23353348304/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22142, 'P.‚î¨‚ïë de Marina Moreno c.1955', 'Vista nocturna del paseo de Marina Moreno, con la plaza de Basilio Para‚îú¬°so al fondo. A la izquierda, chafl‚îú√≠n de la Residencia Universitaria de los PP. Jesuitas, como parte de su gran complejo de formaci‚îú‚îÇn. A la derecha, luminoso chaflancillo del antiguo antiguo Hotel Regina, Hotel Centenario en el momento de la captura fotogr‚îú√≠fica, en la calle de Juan Bruil. Fuente visual: zaragozabuenasnoticias.com/', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64783600, -0.88397200, '0101000020E6100000008DD2A57F49ECBFF295404AECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25087622531.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25087622531.webp', 'https://www.flickr.com/photos/zaragozaantigua/25087622531/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22260, 'Marina Moreno 1968', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 25/11/1968. Vista desde el Paseo de Marina Moreno de las traseras de los hotelitos de la Plaza de Arag‚îú‚îÇn, un poco antes de que alguien ideara una alternativa m‚îú√≠s atractiva econ‚îú‚îÇmicamente que ser mero soporte de vallas publicitarias: piquetearlos y construir nuevos y enormes bloques de viviendas y oficinas. La callecita por la que se mete un 600 es Agustina Sim‚îú‚îÇn.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64798300, -0.88319200, '0101000020E6100000B6D782DE1B43ECBF97AE601BF1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14762647828.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14762647828.webp', 'https://www.flickr.com/photos/zaragozaantigua/14762647828/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22266, 'Cine Par‚îú¬°s 1968', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/diciembre 1968. Inaugurado en 1957, el Cine Par‚îú¬°s estaba ubicado en el Paseo de las Damas n‚î¨‚ïë 11, anterior y terroso "Paseo de Sasera", que escoltado entre el colegio y el convento de los jesu‚îú¬°tas, conduc‚îú¬°a desde la Plaza Para‚îú¬°so hacia el rural Camino de las Torres. Este cine era ya de un tama‚îú‚ñío considerable, con 750 butacas, orientado inicialmente a pel‚îú¬°culas familiares y toleradas para menores. Cerr‚îú‚îÇ en enero de 1984. En la imagen, salida de una sesi‚îú‚îÇn de cine en versi‚îú‚îÇn original de la pel‚îú¬°cula espa‚îú‚ñíola "Las cicatrices", sobre toreros, y protagonizada por el Alfredo Landa de los 60-70. El cine de toreros tambi‚îú¬Æn era considerado como cine para p‚îú‚ïëblico infantil, porque parece que al se‚îú‚ñíor del sombrero no le ha terminado de entretener lo suficiente.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64565800, -0.88458100, '0101000020E6100000193735D07C4EECBF4C33DDEBA4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14850665475.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14850665475.webp', 'https://www.flickr.com/photos/zaragozaantigua/14850665475/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22312, 'Calle de Bruil 1966', 'Tras la Exposici‚îú‚îÇn Aragonesa de 1868, los terrenos de la Glorieta de Pignatelli, cerca del Huerva, se parcelaron y comenzaron a urbanizarse. La denominada "Manzana D" qued‚îú‚îÇ delimitada por la Glorieta, la nueva calle Bruil, el r‚îú¬°o Huerva, y la nueva calle Puigcerd‚îú√≠. En el solar n‚î¨‚ïë 1 de la manzana se edific‚îú‚îÇ el hotelito de la familia Bayl‚îú¬°n (1887), que pronto pas‚îú‚îÇ a manos de Tom‚îú√≠s Castellano (1890). Con motivo de la Expo de 1908, se levant‚îú‚îÇ al lado un inmueble con idea de explotarlo como hotel durante la muestra. Al nuevo edificio se le dio el nombre de "Gran Hotel Regina", ten‚îú¬°a entrada por la calle Bruil, y era considerado el primer hotel de traza moderna de la ciudad. Tras la Expo, el hotelito de la plaza fue alquilado para sede del Gobierno Civil (1911), y el Hotel fue colegio de los Hermanos del Sagrado Coraz‚îú‚îÇn (1913-1919). De 1919 a 1939 aqu‚îú¬° se instal‚îú‚îÇ una Academia Preparatoria Militar que entre 1936-39 fue reconvertida en centro de represi‚îú‚îÇn contra republicanos. Recuper‚îú‚îÇ su original funci‚îú‚îÇn (Hotel) durante los festejos del XIX Centenario de la Venida de la Virgen del Pilar (en carne mortal) a Zaragoza. Fue reformado seg‚îú‚ïën proyecto de Teodoro R‚îú¬°os, y se le denomin‚îú‚îÇ "Hotel Centenario", que en 1942 fue nuevamente reformado. En 1966 una inmobiliaria-constructora lo derrib‚îú‚îÇ, y levant‚îú‚îÇ sobre su solar en macizada verticalidad un nuevo Hotel, viviendas, y locales comerciales. Hacia la plaza de Arag‚îú‚îÇn, el antiguo Gobierno Civil era piqueteado sincronizadamente. En la imagen, chafl‚îú√≠n entre la calle Bruil (derecha) y Marina Moreno (izquierda), con visual del antiguo Hotel Regina-Hotel Centenario de la calle Bruil. A continuaci‚îú‚îÇn, los jardines del antiguo Gobierno Civil. Al fondo, pasando el Paseo de la Independencia, el correspondiente hotelito esquinado con la calle Albareda (piqueteado en 1977). Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.64824000, -0.88314400, '0101000020E61000007313B534B742ECBFC2FA3F87F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15735355718.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15735355718.webp', 'https://www.flickr.com/photos/zaragozaantigua/15735355718/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22362, 'P.‚î¨‚ïë de las Damas 1969', 'Foto: Colecci‚îú‚îÇn Jos‚îú¬Æ Ignacio Lorenzo. 15 de mayo de 1969. Comitiva familiar procedente de una comuni‚îú‚îÇn celebrada en el convento de las Oblatas, caminando direcci‚îú‚îÇn plaza de Para‚îú¬°so, a la altura del n‚îú‚ïëmero 38 (izquierda) del paseo de las Damas. Fuente: www.facebook.com/photo.php?fbid=1027709830613781&set=...', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.64366100, -0.88290900, '0101000020E610000093020B60CA40ECBFF75AD07B63D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21060922748.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21060922748.webp', 'https://www.flickr.com/photos/zaragozaantigua/21060922748/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22416, 'C.‚î¨‚ïë de las Torres 1969', 'Imagen del hist‚îú‚îÇrico camino de las Torres, con los bloques de viviendas recayentes a las calles de Pedro Mar‚îú¬°a Ric, General Sueiro, y Madre Vedruna, a la izquierda. A la derecha, restos de tradicionales edificaciones de la periferia de la ciudad, junto a la textil f‚îú√≠brica "Lanera Aragonesa", cuya destacada chimenea queda fuera de campo. El cauce al aire de la acequia de las Adulas, o de San Jos‚îú¬Æ, se curvaba hacia la derecha en este punto para dar riego a los campos de esa parte de Miraflores. Esta vital acequia fue el origen del camino, como antigua v‚îú¬°a de comunicaci‚îú‚îÇn con Cuarte. Las mutaciones posteriores de la zona han sido remarcables, hasta el punto de convertir este camino en una moderna trinchera, o autov‚îú¬°a, para tr‚îú√≠fico rodado. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal Zaragoza. Referencia: ES. 50297. AM 04.01.02.13 Sobre 118208', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.64309500, -0.88111500, '0101000020E6100000357BA0151832ECBF4E9CDCEF50D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25802294063.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25802294063.webp', 'https://www.flickr.com/photos/zaragozaantigua/25802294063/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25636, 'Calle de Jerusal‚îú¬Æn 1973', 'Imagen capturada desde el estadio municipal de La Romareda y centrada en algunos de los recientes bloques que configuraban el Pol‚îú¬°gono Romareda, originalmente de la Gran V‚îú¬°a. Centra la escena el bloque del n‚î¨‚ïë 4 de la calle de Juan II de Arag‚îú‚îÇn, cuya sombra se proyecta junto a la del n‚î¨‚ïë 6, a la izquierda y fuera de plano. De derecha a izquierda, los bloques de los n‚îú‚ïëmeros 15, 17, 21 y 23 de la calle de As‚îú¬°n y Palacios. A‚îú‚ñíos despu‚îú¬Æs, entre estos bloques de la imagen se construir‚îú√≠ el moderno colegio p‚îú‚ïëblico, actual CEIP, Eliseo Godoy. En primer t‚îú¬Ærmino y a la izquierda, un veh‚îú¬°culo aparece estacionado en la solera de la calle de Jerusal‚îú¬Æn.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63614900, -0.90421500, '0101000020E61000003AAFB14B54EFECBF0A3197546DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47929781208.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47929781208.webp', 'https://www.flickr.com/photos/zaragozaantigua/47929781208/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22437, 'Marina Moreno 1968', 'Era conocida como la "se‚îú‚ñíora del doctor Barnard", y su nombre era Aletta Gertruida Louw, enfermera de profesi‚îú‚îÇn. En 1948 cas‚îú‚îÇ con Christiaan Neethling Barnard, que como m‚îú¬Ædico cirujano realiz‚îú‚îÇ en 1967 el primer transplante de coraz‚îú‚îÇn en un humano, lo que le convirti‚îú‚îÇ en un fen‚îú‚îÇmeno medi‚îú√≠tico. Tras ser portada en la revista Time, el "Dr. Barnard" ascendi‚îú‚îÇ a la talla de personaje internacional, con aut‚îú¬Ænticas "giras" mundiales y entrevistas en las TV de muchos pa‚îú¬°ses, y fue equiparado a las grandes estrellas del cine, la m‚îú‚ïësica, y la cultura de masas. Durante su paso por Zaragoza en una de esas giras mundiales, la "Sra. Barnard" ejerci‚îú‚îÇ de devota esposa del famoso doctor, escenificando las funciones que la sociedad patriarcal ha impuesto como propias de su sexo, como ir de compras. En la imagen, Aletta sale sonriente y cargada de g‚îú¬Æneros de la tienda de decoraci‚îú‚îÇn y jugueter‚îú¬°a denominada "Children''s", en el paseo de Marina Moreno. Un par de a‚îú‚ñíos despu‚îú¬Æs, Aletta y Christiaan firmaron el divorcio. Fuente visual: Fernando Sancho Ramo, AMZ.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64755200, -0.88134000, '0101000020E6100000320395F1EF33ECBFCD3AE3FBE2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30580559545.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30580559545.webp', 'https://www.flickr.com/photos/zaragozaantigua/30580559545/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22470, 'Camino de las Torres 1969', 'Imagen del camino de las Torres en el comienzo de su mutaci‚îú‚îÇn a avenida, o v‚îú¬°a r‚îú√≠pida para tr‚îú√≠fico rodado. La anchura original hab‚îú¬°a aguantado varios siglos, pero parece ser que ya no compaginaba con la modernidad requerida, ni con el debido embellecimiento de un entorno edilicio hasta hac‚îú¬°a poco pr‚îú√≠cticamente inexistente. La captura se ha realizado casi en la esquina con la calle del General Sueiro (a la espalda del fot‚îú‚îÇgrafo). A la izquierda, restos de parcelas anexas a la textil f‚îú√≠brica "Lanera Aragonesa", con su referente y destacada chimenea. Al fondo, nuevos bloques de la reciente plaza de Albert Schweitzer. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.64325500, -0.88088900, '0101000020E610000022FFCC203E30ECBF87FE092E56D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33231150311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33231150311.webp', 'https://www.flickr.com/photos/zaragozaantigua/33231150311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22598, 'Residencia PP Jesuitas 1976', 'El arquitecto Jos‚îú¬Æ Romero, junto a su hermano Manuel, firman en 1952 el proyecto de Residencia Universitaria de los PP. Jesuitas en Zaragoza, integrado en la enorme manzana del colegio de la misma orden, y chaflaneando entre la avenida de Marina Moreno y la reciente calle denominada "Arquitecto Yarza". Esta Residencia fue ideada para dar servicio a los antiguos alumnos del Colegio de El Salvador, y de otros colegios situados en localidades sin universidad. Es levantado en cuatro plantas, m‚îú√≠s unos locales comerciales de alquiler, en formas racionalistas. El chafl‚îú√≠n articula las dos alas del edificio, y el material fundamental es el ladrillo, reservando la piedra para la planta baja y el chafl‚îú√≠n, culminado con un altorrelieve como ‚îú‚ïënica concesi‚îú‚îÇn ornamental. En la imagen, vista de la Residencia desde Marina Moreno. A la izquierda, la calle Arquitecto Yarza. Tiempo despu‚îú¬Æs, este edificio perdi‚îú‚îÇ su funci‚îú‚îÇn original, y fue muy transformado, tanto en funciones, formas, como en tama‚îú‚ñío, ganando entre una y tres alturas extra. Conserva los bajos comerciales, aunque sin misiones en tierra de indios. Fuente: Archivo P‚îú‚ïëblico Municipal, Gerardo Sancho Ramo..', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.64754200, -0.88374400, '0101000020E6100000BF28417FA147ECBFAA6400A8E2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18567831093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18567831093.webp', 'https://www.flickr.com/photos/zaragozaantigua/18567831093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22649, 'Marcelino Camacho 1979', 'La Organizaci‚îú‚îÇn Sindical Espa‚îú‚ñíola, o "Sindicato Vertical", fue la ‚îú‚ïënica central tolerada en toda Espa‚îú‚ñía entre 1940 y 1976, aunque ya desde 1936 el nuevo r‚îú¬Ægimen franquista iba aniquilando los sindicatos de clase conforme avanzaba militarmente para recuperar la hegemon‚îú¬°a de la Espa‚îú‚ñía profunda. El 1‚î¨‚ïë de abril de 1977, tras la legalizaci‚îú‚îÇn de algunos partidos pol‚îú¬°ticos, fue reconocido el derecho de asociaci‚îú‚îÇn sindical, y las Comisiones Obreras, la protag‚îú‚îÇnica organizaci‚îú‚îÇn de trabajadores y trabajadoras, dejaron de ser clandestinas. Marcelino Camacho fue uno de sus principales impulsores y referentes, y desde 1976 era su Secretario General. En las elecciones constituyentes de 1977 fue elegido diputado por Madrid en la lista del PCE, siendo reelegido en las elecciones generales de 1979. Dimitir‚îú√≠ en 1981 como diputado por desacuerdo con el trabajo institucional del PCE, y continuar‚îú√≠ como Secretario General de CCOO hasta 1987, protagonizando intensas movilizaciones contra la pol‚îú¬°tica econ‚îú‚îÇmica de los primeros gobiernos socialistas. En la imagen, Marcelino Camacho en el sal‚îú‚îÇn de actos del original edificio de la "Casa Sindical", inaugurada en 1945 en el Paseo de Marina Moreno, y que tras la disoluci‚îú‚îÇn del mismo fue cedido a CCOO, manteniendo el Estado Central su titularidad. Fuente visual: Archivo P‚îú‚ïëblico Municipal, Gerardo Sancho Ramo.', 1979, 1979, 1979, 'Anos 70', 'CENTRO', 41.64781500, -0.88258600, '0101000020E6100000E109BDFE243EECBFDB6D179AEBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20999869744.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20999869744.webp', 'https://www.flickr.com/photos/zaragozaantigua/20999869744/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22675, 'P.‚î¨‚ïë del General Mola 1976', 'Imagen capturada en el solar resultante tras el derribo del gran complejo de los PP. Jesuitas formado por el antiguo colegio del Salvador y la modern‚îú¬°sima iglesia de la Madre del Salvador, en el arranque del paseo del General Mola. Al fondo, a la izquierda, el referencial edificio El‚îú¬°seos con su publicitaria peineta, chaflanero con el paseo de Calvo Sotelo. En el centro, el edificio de la antigua facultad de Medicina y Ciencias. A la derecha, edificios del paseo de Pamplona y ‚îú√≠rboles de la avenida de Marina Moreno. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.64693500, -0.88461200, '0101000020E6100000DAC534D3BD4EECBFA2D11DC4CED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24628438698.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24628438698.webp', 'https://www.flickr.com/photos/zaragozaantigua/24628438698/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22816, 'Av. de Marina Moreno 1973', 'In‚îú¬Ædita imagen capturada durante las "obras de embellecimiento" del paseo de Marina Moreno, que seg‚îú‚ïën la moda de la ‚îú¬Æpoca supusieron tambi‚îú¬Æn su redenominaci‚îú‚îÇn como "avenida", en tiempos en que los viales que comenzaban por "camino de...", o "paseo de..." eran considerados reliquias de un pasado a eliminar. Vivir en una avenida parece que ser que daba m‚îú√≠s prestigio social. De esta forma y al m‚îú‚îÇdico precio de unos diez millones de pesetas, este paseo fue objeto de una intervenci‚îú‚îÇn suntuaria en una zona bien c‚îú¬Æntrica, que ya en su momento fue tibiamente cuestionada por innecesaria. Entre otras actuaciones, se reubic‚îú‚îÇ aqu‚îú¬° la estatua del Buen Pastor, desde el Macelo municipal. En la fotograf‚îú¬°a, capturada poco antes del cruce con las calle de San Ignacio de Loyola y de Isaac Peral, terroso aspecto en obras del paseo con el fondo del moderno bloque construido en la esquina con la calle de Juan Bruil. A la derecha, traseras de la iglesia de Santa Engracia. Centra la escena una solitaria cabina telef‚îú‚îÇnica, especialmente ic‚îú‚îÇnica tras el impactante mediometraje dirigido poco antes por Antonio Mercero.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.64820800, -0.88188800, '0101000020E6100000E083D72E6D38ECBFB680D07AF8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51599494585.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51599494585.webp', 'https://www.flickr.com/photos/zaragozaantigua/51599494585/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22867, 'Charlton Heston 1989', 'Foto: ‚îú√ºngel de Castro. El actor estadounidense Charlton Heston (1923-2008) visit‚îú‚îÇ Zaragoza en febrero de 1989 para rodar localizaciones aragonesas de dos episodios de una serie de reportajes titulada "Opera Stories", en los que se situaban fragmentos oper‚îú¬°sticos en los lugares en que se desarrollaba la trama. En la ciudad, estuvo en la Aljafer‚îú¬°a y visit‚îú‚îÇ el Patio de la Infanta, momento que recoge la foto. Fuente visual: Heraldo de Arag‚îú‚îÇn.', 1989, 1989, 1989, 'Anos 80', 'CENTRO', 41.64660300, -0.88451800, '0101000020E6100000812557B1F84DECBF6C3F19E3C3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15740641416.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15740641416.webp', 'https://www.flickr.com/photos/zaragozaantigua/15740641416/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22917, 'P.‚î¨‚ïë Constituci‚îú‚îÇn c.1984', 'Vista del paseo de la Constituci‚îú‚îÇn, con la entrada de la calle Le‚îú‚îÇn XIII en el centro de la imagen. Al fondo, avenida de Ces‚îú√≠reo Alierta. Fuente: Foto para postal de Comercial Josan. Cesi‚îú‚îÇn de la familia de Jos‚îú¬Æ Mar‚îú¬°a Sanz Gonz‚îú√≠lez a Rafael Castillejo. Dataci‚îú‚îÇn y procesado:', 1984, 1984, 1984, 'Anos 80', 'CENTRO', 41.64742100, -0.88034400, '0101000020E6100000B85A272EC72BECBF2FDFFAB0DED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27143509820.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27143509820.webp', 'https://www.flickr.com/photos/zaragozaantigua/27143509820/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22972, 'Jos‚îú¬Æ Saramago 1992', 'El 10 de marzo de 1992, el escritor Jos‚îú¬Æ Saramago, afiliado desde 1969 al Partido Comunista Portugu‚îú¬Æs, visit‚îú‚îÇ Zaragoza para impartir una conferencia en el Centro de Exposiciones y Congresos de Ibercaja, donde est‚îú√≠ hecha la fotograf‚îú¬°a. Seis a‚îú‚ñíos despu‚îú¬Æs le fue concedido el Premio Nobel de Literatura. Fuente: Ibercaja', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.64665700, -0.88457100, '0101000020E610000036AE7FD7674EECBF5F5D15A8C5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15014687401.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15014687401.webp', 'https://www.flickr.com/photos/zaragozaantigua/15014687401/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23679, 'Calle Bruil 1930', 'Imagen capturada desde el arranque del paseo de la Mina y centrada en el edificio del antiguo Gran Hotel Regina de la calle Bruil, habilitado en 1919 como Gran Polit‚îú¬Æcnica Torres o centro preparatorio para el ingreso a la Academia General Militar de Zaragoza. Tras el 18 de julio de 1936 y hasta 1939 este fue uno de los destacados escenarios de represi‚îú‚îÇn antirrepublicana en la ciudad. Fuente visual: foto Mart‚îú¬°nez, en www.bne.es/', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64830100, -0.88327500, '0101000020E610000016FBCBEEC943ECBF677BF486FBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39621373222.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39621373222.webp', 'https://www.flickr.com/photos/zaragozaantigua/39621373222/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24110, 'Calle de Juan Bruil 1936', 'Imagen capturada desde la avenida de Gal‚îú√≠n y Garc‚îú¬°a Hern‚îú√≠ndez, y centrada en los veh‚îú¬°culos provenientes de Mall‚îú¬Æn con abastos para las tropas sublevadas en Zaragoza el 19 de julio de 1936 contra la democracia parlamentaria. Durante esas primeras semanas de conflicto era habitual la llegada de convoyes organizados desde los pueblos de la provincia que tambi‚îú¬Æn secundaron la sublevaci‚îú‚îÇn, con v‚îú¬°veres y provisiones para abastecer a la V‚î¨¬¨ Divisi‚îú‚îÇn Org‚îú√≠nica, que militariz‚îú‚îÇ la Gran Polit‚îú¬Æcnica Torres, sita en la calle de Juan Bruil n‚î¨‚ïë 2, como dep‚îú‚îÇsito y almac‚îú¬Æn habilitado al efecto. En la imagen, posado de veh‚îú¬°culos, malleneros y animales ante la Polit‚îú¬Æcnica Torres. Tras ellos, carteles con los vivas y arribas de rigor.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64829600, -0.88311100, '0101000020E6100000849CF7FF7142ECBF5610035DFBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51879128036.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51879128036.webp', 'https://www.flickr.com/photos/zaragozaantigua/51879128036/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24137, 'Feria de Muestras 1935', 'Plano de la II Feria de Muestras Aragonesa, octubre de 1935. En 1934 se celebr‚îú‚îÇ la I Feria de Muestras Aragonesa, en la Lonja de Zaragoza. Al a‚îú‚ñío siguiente se busc‚îú‚îÇ un recinto m‚îú√≠s amplio para esa muestra comercial, y se ubic‚îú‚îÇ en las traseras del colegio de los jesuitas (derecha), en lo que despu‚îú¬Æs ser‚îú¬°a el paseo Marina Moreno (abajo). Hubo que esperar hasta 1941 para que se inaugurara la siguiente, en un recinto estable junto al parque Primo de Rivera. Fuente visual: Revista Arag‚îú‚îÇn, diciembre de 1935.', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.64751800, -0.88431200, '0101000020E610000034BBEEAD484CECBF21C9ACDEE1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20030530523.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20030530523.webp', 'https://www.flickr.com/photos/zaragozaantigua/20030530523/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24139, 'Feria de Muestras 1935', 'En 1934 se celebr‚îú‚îÇ la I Feria de Muestras Aragonesa, en la Lonja de Zaragoza. Al a‚îú‚ñío siguiente se busc‚îú‚îÇ un recinto m‚îú√≠s amplio para esa muestra comercial, y se ubic‚îú‚îÇ en las traseras del colegio de los jesuitas. Hubo que esperar hasta 1941 para que se inaugurara la siguiente, en un recinto estable junto al parque Primo de Rivera. En la foto, acceso a la II Feria de Muestras Aragonesa, en la avenida de Gal‚îú√≠n y Garc‚îú¬°a Hern‚îú√≠ndez (poco despu‚îú¬Æs paseo de Marina Moreno). Al fondo, el colegio del Salvador de los padres jesuitas, en la actual plaza de Para‚îú¬°so (a la derecha). Fuente visual: Instant‚îú√≠neas zaragozanas, CAZAR, 1982.', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.64751800, -0.88431200, '0101000020E610000034BBEEAD484CECBF21C9ACDEE1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20076691098.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20076691098.webp', 'https://www.flickr.com/photos/zaragozaantigua/20076691098/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24140, 'Expo Av‚îú¬°cola 1932', 'Imagen del "stand" de la Granja Agr‚îú¬°cola en la Exposici‚îú‚îÇn Nacional de Avicultura, Colombofilia y Cuniculicultura, celebrada en Zaragoza del 8 al 16 de octubre de 1932 en el patio-jard‚îú¬°n y galer‚îú¬°a cubierta del colegio del Salvador. En la imagen, aspecto del arbolado patio interior del colegio del Salvador habilitado como marco expositivo de gallin‚îú√≠ceas de la Granja Agr‚îú¬°cola. Al fondo, el muro norte del colegio, recayente a la avenida de Gal‚îú√≠n y Garc‚îú¬°a Hern‚îú√≠ndez. Fuente visual: exposici‚îú‚îÇn √î√á¬£La investigaci‚îú‚îÇn agroalimentaria en Arag‚îú‚îÇn. Sus inicios con Rodr‚îú¬°guez Ayuso√î√á√ò. Centro de Investigaci‚îú‚îÇn y Tecnolog‚îú¬°a Agroalimentaria de Arag‚îú‚îÇn (CITA).', 1932, 1932, 1932, 'Anos 30', 'CENTRO', 41.64732000, -0.88413000, '0101000020E610000009336DFFCA4AECBFFB05BB61DBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20110630690.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20110630690.webp', 'https://www.flickr.com/photos/zaragozaantigua/20110630690/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24148, 'II Feria de Muestras 1935', 'Cartel anunciador de la II Feria de Muestras Oficial Aragonesa, cuyo dise‚îú‚ñío fue ganado en concurso por Guillermo P‚îú¬Ærez Bailo, como en el certamen del a‚îú‚ñío anterior. Organizado por la C‚îú√≠mara de Comercio de Zaragoza, se celebr‚îú‚îÇ entre el 6 y el 21 de octubre de ese a‚îú‚ñío en un provisional recinto ideado por Regino Borobio, en el tramo recientemente cubierto del r‚îú¬°o Huerva entre la plaza de Para‚îú¬°so, el colegio de los PP. Jesuitas, y la plaza de Arag‚îú‚îÇn, y que fue denominado "avenida de Gal‚îú√≠n y Garc‚îú¬°a Hern‚îú√≠ndez". Por diversas circunstancias, hasta 1941 no habr‚îú¬°a m‚îú√≠s ferias de muestras, que en 1943 recibieron la denominaci‚îú‚îÇn de "nacional". Fuente visual: www.todocoleccion.net/', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.64811300, -0.88292800, '0101000020E610000043209738F240ECBF658EE55DF5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25613549536.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25613549536.webp', 'https://www.flickr.com/photos/zaragozaantigua/25613549536/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24149, 'Expo Av‚îú¬°cola 1932', 'Del 8 al 16 de octubre de 1932 tuvo lugar en Zaragoza la "Exposici‚îú‚îÇn Nacional de Avicultura, Colombofilia y Cuniculicultura", organizada por la Asociaci‚îú‚îÇn Av‚îú¬°cola Aragonesa con el respaldo, entre otros, del Ayuntamiento, y la Universidad. Paralelamente, se celebr‚îú‚îÇ la Asamblea de Avicultores con car‚îú√≠cter estatal. La exposici‚îú‚îÇn tuvo como escenario el patio-jard‚îú¬°n y galer‚îú¬°a cubierta del colegio del Salvador, cont‚îú‚îÇ con la muestra de m‚îú√≠s de 500 selectos ejemplares de gallin‚îú√≠ceas, palm‚îú¬°pedas, palomas, y conejos, adem‚îú√≠s de materiales, alimentos y accesorios relacionados con el sector. Al final, el jurado de la Exposici‚îú‚îÇn concedi‚îú‚îÇ varios premios de honor entre lo m‚îú√≠s destacado de las diversas categor‚îú¬°as a concurso. La Asamblea, y las conferencias de la Exposici‚îú‚îÇn, se celebraron en dependencias de la cercana Facultad de Medicina. En la imagen, aspecto del arbolado patio interior del colegio del Salvador habilitado como marco expositivo de lotes de gallin‚îú√≠ceas. Al fondo, el muro norte del colegio, recayente a la avenida de Gal‚îú√≠n y Garc‚îú¬°a Hern‚îú√≠ndez. Fuente: "Mundo Av‚îú¬°cola", Barcelona, 1932.', 1932, 1932, 1932, 'Anos 30', 'CENTRO', 41.64732000, -0.88413000, '0101000020E610000009336DFFCA4AECBFFB05BB61DBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25789855713.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25789855713.webp', 'https://www.flickr.com/photos/zaragozaantigua/25789855713/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24164, 'Pl. de Castelar c.1923', 'Imagen de la plaza de Castelar cuando en ella se ubicaban las ferias y atracciones durante las fiestas mayores para divertimento de chicos y chacos. La captura se ha realizado en la zona sur de la plaza, sobre la despejada manzana a‚îú‚ïën sin urbanizar de la prolongaci‚îú‚îÇn de la calle de Joaqu‚îú¬°n Costa, donde pocos a‚îú‚ñíos despu‚îú¬Æs se barajar‚îú¬°a temporalmente la construcci‚îú‚îÇn del nuevo edificio del Ayuntamiento de la ciudad. Al fondo, entre atracciones, vista parcial del ala sur del Museo Provincial.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.64817400, -0.87986200, '0101000020E6100000E7C75F5AD427ECBF0A0F9A5DF7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45616915291.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45616915291.webp', 'https://www.flickr.com/photos/zaragozaantigua/45616915291/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24299, 'Gran Casino 1908', 'Foto: Ignacio Coyne, 1908. Gran Casino de la Exposici‚îú‚îÇn Hispano Francesa de Zaragoza. Fuente: dara.aragon.es/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64819800, -0.88125600, '0101000020E6100000BCEB6CC83F33ECBF93AAED26F8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18990276864.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18990276864.webp', 'https://www.flickr.com/photos/zaragozaantigua/18990276864/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24300, 'Pabell‚îú‚îÇn de Reales Patrimonios 1908', 'Foto: Ignacio Coyne, 1908. Pabell‚îú‚îÇn de los Reales Patrimonios, o posesiones de la Corona de Espa‚îú‚ñía. Estaba adosado al interior de la tapia de la Exposici‚îú‚îÇn Hispano Francesa de Zaragoza. Fuente. ‚îú√ºlbum oficial de la Exposici‚îú‚îÇn Hispano-Francesa, 1908.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64783800, -0.88019400, '0101000020E61000006555849B8C2AECBF938D075BECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18995465313.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18995465313.webp', 'https://www.flickr.com/photos/zaragozaantigua/18995465313/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24329, 'Pl. de Castelar 1930', 'Imagen capturada en la plaza de Castelar desde el cruce de las calles de Costa y del Arquitecto Magdalena, para ilustrar el gran solar en el que estaba prevista la construcci‚îú‚îÇn de la nueva Casa del Ayuntamiento. Al fondo, de fachada, los nuevos bloques de vivienda de la calle Sancho y Gil. El ‚îú‚ïëltimo de ellos, con el n‚î¨‚ïë 13, hab‚îú¬°a sido dise‚îú‚ñíado por el arquitecto Francisco Albi‚îú‚ñíana. Tras ellos estaba prevista la construcci‚îú‚îÇn de la Casa del Pueblo de la UGT, proyecto estancado y no realizado. A la izquierda, un provisional quiosco frente al Museo provincial. A la derecha, alboleda del paseo de la Mina, junto al punto l‚îú¬°mite donde terminaba el cubrimiento del r‚îú¬°o Huerva. Fuente visual: www.mecd.gob.es/.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64817400, -0.87986200, '0101000020E6100000E7C75F5AD427ECBF0A0F9A5DF7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34471873023.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34471873023.webp', 'https://www.flickr.com/photos/zaragozaantigua/34471873023/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24341, 'Memoria h‚îú¬Æroes c.1850', 'Dibujo firmado por el arquitecto Mat‚îú¬°as Lavi‚îú‚ñía Blasco con el t‚îú¬°tulo "proyecto de un monumento para perpetuar la memoria de los h‚îú¬Æroes de 1808 con arreglo a lo acordado por las Cortes de C‚îú√≠diz". Representa de forma idealista una localizaci‚îú‚îÇn de la periferia urbana centrada en una estructura de planta cuadrada con un p‚îú‚îÇrtico y escaleras de acceso en cada uno de los lados, del que emerge un espacio abovedado apoyado en un tambor octogonal y rematado por un aleg‚îú‚îÇrico bulto redondo. La influencia de los a‚îú‚ñíos de estancia del autor en Roma aprendiendo el oficio se refleja tanto en las formas del edificio como en las vestimentas propias de la antig‚îú‚ïùedad cl‚îú√≠sica romana que portan las figuras que pasean por el entorno. Las ruinas del fondo a la izquierda podr‚îú¬°an estar inspiradas de alguna forma en las del monasterio de santa Engracia. Este proyecto no fue realizado.', 1850, 1850, 1850, 'Siglo XIX', 'CENTRO', 41.64798300, -0.88417400, '0101000020E6100000F226BF45274BECBF97AE601BF1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52244985479.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52244985479.webp', 'https://www.flickr.com/photos/zaragozaantigua/52244985479/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24458, 'Fundici‚îú‚îÇn Mart‚îú¬°n Rod‚îú‚îÇn 1885', 'Dibujo de cabecera de factura de la empresa "Grandes talleres de fundici‚îú‚îÇn y construcci‚îú‚îÇn de m‚îú√≠quinas de Mart‚îú¬°n Rod‚îú‚îÇn y Hermano"; en 1885. Estaba situada en el Paseo de las Damas, tramo comprendido entre las actuales calles de San Ignacio de Loyola (antigua de Rod‚îú‚îÇn) y Le‚îú‚îÇn XIII. Fuente: M‚î¨¬¨ Pilar Biel Ib‚îú√≠‚îú‚ñíez, Zaragoza y la industrializaci‚îú‚îÇn: la arquitectura industrial 1875-1936, IFC, 2004.', 1885, 1885, 1885, 'Siglo XIX', 'CENTRO', 41.64578400, -0.88427200, '0101000020E6100000A69718CBF44BECBFD923D40CA9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19626693852.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19626693852.webp', 'https://www.flickr.com/photos/zaragozaantigua/19626693852/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24715, 'P.‚î¨‚ïë de los Pl‚îú√≠tanos c.1953', 'El paseo de los Pl‚îú√≠tanos, llamado as‚îú¬° por los ‚îú√≠rboles que lo flanqueaban, comenzaba en la avenida de Marina Moreno y llegaba hasta el camino de las Torres. La actual calle de Francisco de Vitoria coincide aproximadamente con parte del trazado del antiguo camino o paseo de los Pl‚îú√≠tanos. Fuente: "Zaragoza. Instant‚îú√≠neas grises", CAZAR, 1972.', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.64662000, -0.88015800, '0101000020E610000032022A1C412AECBF4278B471C4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15409559845.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15409559845.webp', 'https://www.flickr.com/photos/zaragozaantigua/15409559845/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24716, 'Casa Sindical 1945', 'El Delegado nacional de Sindicatos, Ferm‚îú¬°n Sanz Olmo, inaugura la Casa Sindical, el nuevo edificio de la Delegaci‚îú‚îÇn Provincial de Sindicatos, en la avenida de Marina Moreno 12, esquina con la nueva calle de San Ignacio de Loyola. Fuente: Foto Lozano, Agencia EFE', 1945, 1945, 1945, 'Anos 40', 'CENTRO', 41.64781500, -0.88258600, '0101000020E6100000E109BDFE243EECBFDB6D179AEBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21145262544.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21145262544.webp', 'https://www.flickr.com/photos/zaragozaantigua/21145262544/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24717, 'P.‚î¨‚ïë de los Pl‚îú√≠tanos 1948', 'Imagen en altura, desde el n‚î¨‚ïë 9 de la nueva calle Madre Vedruna, del entorno del antiguo camino de los Pl‚îú√≠tanos entre Marina Moreno, el nuevo vial denominado S. Ignacio de Loyola (izquierda), y la propia Madre Vedruna. Se trataba de uno de los espacios entre lo agr‚îú¬°cola, industrial y residencial difuso que, hasta ese momento, la expansi‚îú‚îÇn urbana hab‚îú¬°a dejado atr‚îú√≠s, para dirigir su crecimiento en otras direcciones. En el momento de realizar la imagen, la urbanizaci‚îú‚îÇn de la zona, y la construcci‚îú‚îÇn de los primeros bloques, como los de la izquierda, se‚îú‚ñíalaba el camino de transformaci‚îú‚îÇn radical que este lugar conocer‚îú¬°a a partir de ese momento, si bien no se completar‚îú¬°a hasta bien entrados los a‚îú‚ñíos 70, cuando lo que hasta entonces hab‚îú¬°an sido apenas terrenos de labor, una densa red de acequias y riegos, caminos de tierra, y unas parcelas vertebradas por el camino de los Pl‚îú√≠tanos y el peculiar callej‚îú‚îÇn de Rod‚îú‚îÇn, se configur‚îú‚îÇ como una selecta y muy exclusiva zona habitacional. En la imagen, al fondo, los bloques de la avenida de Marina Moreno recayentes a la plaza de Jos‚îú¬Æ Antonio, con la calle Mariano Escar como ingreso a la misma. Entre ellos destaca, posiblemente, una de las pocas im‚îú√≠genes de la antigua casa unifamiliar proyectada para Marcos Samper por el arquitecto Mariano Blasco y Taula, luego desaparecida por provinciana. Muy cerca y en la margen derecha del r‚îú¬°o Huerva estaba ubicada la f‚îú√≠brica de harinas de la que era propietario. A la izquierda, el reciente edificio de la Delegaci‚îú‚îÇn Provincial de Sindicatos, y el pionero bloque del 12 de Marina Moreno, en lo que hasta entonces hab‚îú¬°a sido el principio del camino de los Pl‚îú√≠tanos. Las naves se corresponden a los talleres industriales que, como muebles Loscertales, all‚îú¬° estuvieron ubicados. Fuente visual: Archivo Construcciones y Auxiliar de Ferrocarriles (DARA-AHPZ).', 1948, 1948, 1948, 'Anos 40', 'CENTRO', 41.64711900, -0.88174800, '0101000020E61000007007EA944737ECBF64CF9ECBD4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23642295589.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23642295589.webp', 'https://www.flickr.com/photos/zaragozaantigua/23642295589/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24718, 'Av. Marina Moreno c.1951', 'Vista de la avenida de Marina Moreno, con las traseras de la iglesia de Santa Engracia a la derecha. Al fondo, la calle de Juan Bruil. A la izquierda, edificio del arranque de la nueva calle de San Ignacio de Loyola que confrontaba conla Casa Sindical. Fuente: Colecci‚îú‚îÇn particular.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64824500, -0.88256600, '0101000020E61000001AF8510DFB3DECBFD46531B1F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32413352913.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32413352913.webp', 'https://www.flickr.com/photos/zaragozaantigua/32413352913/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24719, 'C.‚î¨‚ïë de los Pl‚îú√≠tanos 1931', 'Imagen de los restos del front‚îú‚îÇn del camino de los Pl‚îú√≠tanos, que se vino abajo tras el notable temporal de viento y lluvias que sacudi‚îú‚îÇ a la ciudad. Este front‚îú‚îÇn estaba ubicado al principio del paseo, junto a los talleres de muebles de Luciano Loscertales. Al fondo, la calle de Juan Bruil, con el chaflanero y antiguo Hotel Regina, reconvertido en Academia Preparatoria Militar. Fuente visual: foto Mar‚îú¬°n Chivite, en diario "Ahora".', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.64778500, -0.88195200, '0101000020E61000008F899466F338ECBF70EB6E9EEAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32821167385.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32821167385.webp', 'https://www.flickr.com/photos/zaragozaantigua/32821167385/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24720, 'Colegio del Salvador c.1951', 'A‚îú¬Ærea visual centrada en la rotunda estructura del colegio del Salvador, entre el despejado paseo de Marina Moreno (izquierda) y el callej‚îú‚îÇn de Rod‚îú‚îÇn (derecha). Al fondo, viviendas de la calle del arquitecto Yarza y de Madre Vedruna, adem‚îú√≠s de algunas naves del antiguo paseo de los Pl‚îú√≠tanos. Fuente visual: A.A.A. Jesuitas Zaragoza', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64693500, -0.88461200, '0101000020E6100000DAC534D3BD4EECBFA2D11DC4CED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34418405152.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34418405152.webp', 'https://www.flickr.com/photos/zaragozaantigua/34418405152/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24721, 'C.‚î¨‚ïë de los Pl‚îú√≠tanos 1931', 'Imagen capturada en la gran finca de Yarza del camino de los Pl‚îú√≠tanos, marco incomparable para la celebraci‚îú‚îÇn de la verbena de la Asociaci‚îú‚îÇn de la Prensa de ese a‚îú‚ñío. Posan un grupo de se‚îú‚ñíoritas asistentes, en un espacio preparado para la ocasi‚îú‚îÇn por diversas brigadas municipales que se encargaron del ornato y la iluminaci‚îú‚îÇn de un evento por el que pasaron miles de personas. Este feraz entorno de la ciudad, en pleno centro, fue muy remodelado tiempo despu‚îú¬Æs mediante una progresiva urbanizaci‚îú‚îÇn que la fue consolidando como una de las zonas residenciales m‚îú√≠s selectas de la moderna Zaragoza. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.64755200, -0.88277800, '0101000020E6100000EF1AF4A5B73FECBFCD3AE3FBE2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35343290086.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35343290086.webp', 'https://www.flickr.com/photos/zaragozaantigua/35343290086/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24722, 'Av. de Marina Moreno 1939', 'Imagen del chaflanero y nuevo edificio de vivienda para casas de renta ubicado en el n‚î¨‚ïë 8 de la avenida de Gal‚îú√≠n y Garc‚îú¬°a Hern‚îú√≠ndez (desde 1938, de Marina Moreno), con dise‚îú‚ñío de Jos‚îú¬Æ de Yarza Garc‚îú¬°a junto a Alejandro Allanegui F‚îú¬Ælez. Su construcci‚îú‚îÇn se inici‚îú‚îÇ en 1935, y la guerra de 1936-39 retras‚îú‚îÇ su finalizaci‚îú‚îÇn hasta 1939. Supuso el comienzo de la urbanizaci‚îú‚îÇn de la antigua y gran torre "Campos El‚îú¬°seos" de la familia Yarza, como pionera inversi‚îú‚îÇn inmobiliaria en una zona residencial muy c‚îú¬Æntrica y orientada a familias de alto poder adquisitivo. La captura visual se ha realizado desde la referida avenida, sobre un tramo cubierto del r‚îú¬°o Huerva. A la derecha, el antiguo muro que delimitaba el l‚îú¬°mite m‚îú√≠s septentrional del gran colegio de El Salvador, y que poco despu‚îú¬Æs ser‚îú¬°a derribado para abrir aqu‚îú¬° un nuevo vial que conectar‚îú√≠ con el callej‚îú‚îÇn de Rod‚îú‚îÇn y con el camino de los Pl‚îú√≠tanos a trav‚îú¬Æs de la nueva calle de San Ignacio de Loyola. A‚îú‚ñíos despu‚îú¬Æs, el vial de la imagen ser‚îú√≠ denominado calle del Arquitecto Yarza. Fuente visual: arch. J. de Yarza', 1939, 1939, 1939, 'Anos 30', 'CENTRO', 41.64766500, -0.88356100, '0101000020E61000007EACE0B72146ECBFC6E1CCAFE6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35542918031.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35542918031.webp', 'https://www.flickr.com/photos/zaragozaantigua/35542918031/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24723, 'Calle Nueva de las Torres 1932', 'Imagen centrada en el n‚î¨‚ïë 205 de la calle Nueva de las Torres, inmediata al camino de las Torres o del Gas (hacia la derecha, fuera de plano), con motivo del hallazgo de armas y explosivos por parte de efectivos del Cuerpo de Seguridad y Asalto. Otros explosivos fueron hallados en el huerto del cercano n‚î¨‚ïë 209 de la misma calle (hacia la izquierda). Este vial surgi‚îú‚îÇ a finales del siglo XIX tras la parcelaci‚îú‚îÇn y urbanizaci‚îú‚îÇn particular de la antigua Torre de Rubio. En 1953 fue redenominado como calle del General Sueiro en homenaje al africanista y golpista teniente general hom‚îú‚îÇnimo. En 2009 la calle recibi‚îú‚îÇ su actual denominaci‚îú‚îÇn: Jos‚îú¬Æ Mar‚îú¬°a Lacarra y de Miguel. Los edificios de la imagen ya hab‚îú¬°an sido derribados con bastante antelaci‚îú‚îÇn, sustituidos por otros m‚îú√≠s acordes a la categor‚îú¬°a socioecon‚îú‚îÇmica de la zona. Fuente visual: www.mecd.gob.es/.', 1932, 1932, 1932, 'Anos 30', 'CENTRO', 41.64358800, -0.88082700, '0101000020E6100000A0E1CD1ABC2FECBF8D0C721761D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35548645942.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35548645942.webp', 'https://www.flickr.com/photos/zaragozaantigua/35548645942/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24724, 'P.‚î¨‚ïë de Marina Moreno c.1951', 'Desde la altura del Hotel Centenario, antes sede la academia Polit‚îú¬Æcnica Torres, una vista muy interesante, con varios puntos de singular inter‚îú¬Æs, del paseo de Marina Moreno que alcanza al fondo al colegio de los Corazonistas del paseo de la Mina, por encima del cual incluso emerge la torre del internado de las Hermanitas de los Ancianos Desamparados. A la derecha, el emboque a la calle de San Ignacio de Loyola. flanqueado por la Delegaci‚îú‚îÇn Provincial de Sindicatos, y un poco m‚îú√≠s adelante restos edilicios del paseo de los Pl‚îú√≠tanos en proceso de extinci‚îú‚îÇn. Vertebra la escena el urbanizado paseo, cuyos jardines en proceso de modelado alcanzan hasta donde lleg‚îú‚îÇ el cubrimiento del r‚îú¬°o Huerva, a la altura de la calle de Mefisto. Los a‚îú¬Æreos cables soportados por postes de hormig‚îú‚îÇn que jalonan el lado de los impares, desde el primer t‚îú¬Ærmino inmediato y hasta el paseo de la Mina, se‚îú‚ñíalan el paso del troleb‚îú‚ïës de la nov‚îú¬°sima l‚îú¬°nea del Terminillo, que originalmente en su recorrido de regreso transitaban el paseo de Marina Moreno hasta la calle de Isaac Peral, por donde se internaban hasta la de Jer‚îú‚îÇnimo Zurita para dar la vuelta y acceder a la terminal de inicio de ruta ubicada en el paseo de la Independencia, que luego fue trasladada a la plaza de Santa Engracia. El resto del tendido que al fondo del paseo de la Mina se prolongaba hasta la plaza de San Miguel era utilizado para el acceso a la ruta que por la calle de Miguel Servet conduc‚îú¬°a y proven‚îú¬°a de las cocheras. A la izquierda, tramo de los impares del paseo de Marina Moreno comprendido entre la calle de Don Hernando de Arag‚îú‚îÇn, Isaac Peral, Mariano Escar, y Mefisto, con el desarrollo edilicio del momento. En el centro de la escena, posiblemente una de las pocas im‚îú√≠genes, siquiera parciales como esta, de la antigua casa unifamiliar proyectada para el industrial Marcos Samper por el arquitecto Mariano Blasco y Taula, luego desaparecida por provinciana. Muy cerca y en la margen derecha del r‚îú¬°o Huerva estaba ubicada la f‚îú√≠bri', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64822400, -0.88218900, '0101000020E61000009D82FC6CE43AECBFBC3D0801F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50097711728.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50097711728.webp', 'https://www.flickr.com/photos/zaragozaantigua/50097711728/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24725, 'P.‚î¨‚ïë de Marina Moreno c.1952', 'Imagen capturada en el paseo de Marina Moreno, con la calle de Agustina Sim‚îú‚îÇn a la espalda, y orientado el objetivo hacia la reciente manzana urbanizada entre las calles del Arquitecto Yarza y de San Ignacio de Loyola. La foto casi se centra en el pionero inmueble del n‚î¨‚ïë 8 del paseo, proyectado por los arquitectos Jos‚îú¬Æ de Yarza Garc‚îú¬°a y Alejandro Allanegui F‚îú¬Ælez, cuya construcci‚îú‚îÇn se inici‚îú‚îÇ en 1935, aunque la guerra de 1936-39 retras‚îú‚îÇ su finalizaci‚îú‚îÇn hasta 1939. Supuso el comienzo de la urbanizaci‚îú‚îÇn de la antigua y gran torre "Campos El‚îú¬°seos" de la familia Yarza, y de la gran zona delimitada entre el paseo de las Damas y el de Marina Moreno. Al fondo, provisional vac‚îú¬°o edilicio en el entorno rururbano del antiguo callej‚îú‚îÇn de Rod‚îú‚îÇn y del paseo de los Pl‚îú√≠tanos, donde en la imagen incluso se intuye un jinete a caballo. A la derecha, ‚îú√≠rboles de los patios traseros del colegio del Salvador.', 1952, 1952, 1952, 'Anos 50', 'CENTRO', 41.64779100, -0.88383000, '0101000020E6100000632827DA5548ECBF52D2C3D0EAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50800408278.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50800408278.webp', 'https://www.flickr.com/photos/zaragozaantigua/50800408278/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24726, 'Calle de Madre Vedruna, 1948', 'Imagen capturada desde la altura del inmueble del n‚î¨‚ïë 9 de la calle de Madre Vedruna, con aspecto de c‚îú‚îÇmo estaba empezando a cambiar la zona vertebrada por el callej‚îú‚îÇn de Rod‚îú‚îÇn y el paseo de los Pl‚îú√≠tanos. A la izquierda, la calle del Arquitecto Yarza, y en el centro de la escena la nueva manzana delimitada adem‚îú√≠s por la nueva calle de San Ignacio de Loyola y el paseo de Marina Moreno. En primer t‚îú¬Ærmino, el callej‚îú‚îÇn de Rod‚îú‚îÇn jalona un espacio entre lo agr‚îú¬°cola, industrial y residencial difuso. En el momento de realizar la imagen, la urbanizaci‚îú‚îÇn de la zona, y la construcci‚îú‚îÇn de los primeros bloques se‚îú‚ñíalaba el camino de transformaci‚îú‚îÇn radical que este lugar conocer‚îú¬°a a partir de ese momento, si bien no se completar‚îú¬°a hasta bien entrados los a‚îú‚ñíos 70, cuando lo que hasta entonces hab‚îú¬°an sido apenas terrenos de labor, una densa red de acequias y riegos, caminos de tierra, y unas parcelas vertebradas por el camino de los Pl‚îú√≠tanos y el callej‚îú‚îÇn de Rod‚îú‚îÇn, se configur‚îú‚îÇ como una selecta y muy exclusiva zona habitacional.', 1948, 1948, 1948, 'Anos 40', 'CENTRO', 41.64714100, -0.88258600, '0101000020E6100000E109BDFE243EECBF4B732B84D5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50807141043.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50807141043.webp', 'https://www.flickr.com/photos/zaragozaantigua/50807141043/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24727, 'Vista Expo 1908', 'Imagen capturada posiblemente desde la altura del colegio del Salvador y orientada en direcci‚îú‚îÇn hacia el luminoso recinto de la Exposici‚îú‚îÇn Hispano-Francesa de 1908, donde la antigua huerta de Santa Engracia. En primer t‚îú¬Ærmino, el feraz entorno de la huerta colegial y de las vecinas torres de Antonio Ardid y de los Yarza, estas dos limitando con el paseo de los Pl‚îú√≠tanos y sus talleres fabriles hacia la derecha. Al otro lado de la ribera del r‚îú¬°o Huerva, el recinto de la exposici‚îú‚îÇn donde destacan por su altura el Palacio de los Museos y la torrecilla del Pabell‚îú‚îÇn Mariano. El tel‚îú‚îÇn de fondo urbano aparece interrumpido por la emergencia de la torre de la iglesia de San Miguel de los Navarros, y aparentemente juntas, la de San Carlos Borromeo y la de Santa Mar‚îú¬°a Magdalena.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64820800, -0.88067600, '0101000020E610000036E84B6F7F2EECBFB680D07AF8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51568870129.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51568870129.webp', 'https://www.flickr.com/photos/zaragozaantigua/51568870129/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24728, 'P‚î¨‚ïë. de las Damas 1909', 'Imagen capturada durante la ceremonia de bendici‚îú‚îÇn del solar y de la primera piedra de la nueva iglesia, capilla y noviciado de las RR. Madres Oblatas del Sant‚îú¬°simo Redentor, as‚îú¬° como la inauguraci‚îú‚îÇn del edificio de los locales para la enfermer‚îú¬°a terminado poco antes y que en la foto queda justo tras el tabern‚îú√≠culo decorado con motivos vegetales. La escena tiene lugar en el patio de este convento inaugurado en 1887 en la antigua Torre de Ponte en el paseo de las Damas, antes paseo de Sasera. A la izquierda destaca el arzobispo Juan Soldevila durante la ceremonia. En primer t‚îú¬Ærmino, autoridades locales y entre ellas, el gobernador civil Sr. Tej‚îú‚îÇn y el alcalde Sr. Fleta. Adem‚îú√≠s, la Madre General del Instituto de Oblatas, los directores espirituales de la Comunidad, las asiladas ("en su mayor‚îú¬°a muchachas abandonadas y de vida licenciosa", seg‚îú‚ïën el lenguaje de la ‚îú¬Æpoca utilizado en publicaciones cat‚îú‚îÇlicas sometidas a la censurada eclesi‚îú√≠stica), la Junta de Damas recaudatoria de fondos para la obra, y otros invitados "de las clases m‚îú√≠s elevadas de la sociedad" (sic) zaragozana. Al fondo y desde la distancia, la Comunidad de las Oblatas observa la ceremonia junto al edificio conventual.', 1909, 1909, 1909, 'Anos 1900', 'CENTRO', 41.64357400, -0.88263900, '0101000020E61000009692E524943EECBF284701A260D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53245666157.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53245666157.webp', 'https://www.flickr.com/photos/zaragozaantigua/53245666157/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24887, 'El Buen Pastor 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 27/02/1974. Remodelaci‚îú‚îÇn del Paseo de marina Moreno, que inclu‚îú¬°a la instalaci‚îú‚îÇn de la estatua "El Buen Pastor", trasvasada desde su original ubicaci‚îú‚îÇn en el patio del macelo de Miguel Servet. La estatua s‚îú‚îÇlo regresar‚îú¬°a cuando el Matadero se hubiera convertido en Centro C‚îú¬°vico Salvador Allende, y ya en el siglo XXI. Para ello tendr‚îú√≠ que sufrir una agresi‚îú‚îÇn que la deje demediada.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.64736600, -0.88024100, '0101000020E61000009225732CEF2AECBF6B459BE3DCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14947312432.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14947312432.webp', 'https://www.flickr.com/photos/zaragozaantigua/14947312432/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24918, 'Paseo Constituci‚îú‚îÇn 2005', 'Foto: Esther Casas. Obras de desmantelamiento de la fuente del Buen Pastor en el paseo de la Constituci‚îú‚îÇn (al fondo, calle de Le‚îú‚îÇn XIII). Estuvo all‚îú¬° desde 1974 y en 2005 fue trasladada a su ubicaci‚îú‚îÇn original, en el Matadero, entonces ya Centro C‚îú¬°vico Salvador Allende. Fuente: Heraldo de Arag‚îú‚îÇn.', 2005, 2005, 2005, 'Siglo XXI', 'CENTRO', 41.64738700, -0.88024900, '0101000020E610000047C66AF3FF2AECBF836DC493DDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31684725196.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31684725196.webp', 'https://www.flickr.com/photos/zaragozaantigua/31684725196/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25020, 'Calle del Arte 1907', 'El primer taller del escultor muelino Dionisio Lasu‚îú¬Æn estuvo ubicado, en 1881, en la calle de los Huertos, hasta que se dise‚îú‚ñí‚îú‚îÇ su propia casa-taller en un vial particular y perpendicular al Paseo de Torrero, que fue bautizado por el propio escultor como Calle del Arte. El edificio, en estilo modernista, ten‚îú¬°a el n‚îú‚ïëmero 15, y estaba al final de la calle, que no ten‚îú¬°a salida, cerca del enlace con la calle del Progreso. Fue derribado cuando comenzaba la d‚îú¬Æcada de los a‚îú‚ñíos 60, tal vez porque era una casa demasiado ins‚îú‚îÇlita para esta ciudad. En la imagen, la nuera de Dionisio se asoma por la ventana, y es capturada inopinadamente. Fuente visual: Foto Freudenthal.', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64307300, -0.88417800, '0101000020E61000004DF73AA92F4BECBF66F84F3750D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15349816560.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15349816560.webp', 'https://www.flickr.com/photos/zaragozaantigua/15349816560/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25028, 'Dionisio Lasu‚îú¬Æn 1907', 'Imagen del escultor Dionisio Lasu‚îú¬Æn Ferrer, su hijo, y su nuera, posando en su casa-taller de la calle del Arte, un excepcional edificio modernista dise‚îú‚ñíado por el propio Lasu‚îú¬Æn, y que fue derrumbado cuando comenzaba la d‚îú¬Æcada de los a‚îú‚ñíos 60. Lasu‚îú¬Æn padre posa junto al modelado en arcilla de la sedente alegor‚îú¬°a de la "Arqueolog‚îú¬°a", de 190 cent‚îú¬°metros de altura, identificada con los atributos de un libro, unas medallas y una figurilla del antiguo Egipto (tal vez un ushebti votivo). Esta obra estaba destinada a decorar la fachada principal del nuevo edificio denominado provisionalmente "Palacio de Museos", como parte de la Exposici‚îú‚îÇn Hispano-Francesa de 1908 en la antigua huerta de Santa Engracia. Esta escultura, en su prevista ubicaci‚îú‚îÇn palaciega, estar‚îú¬°a cobijada bajo templete adosado, a la izquierda de la fachada principal de ingreso, entre los medallones con los retratos en altorrelieve de Dami‚îú√≠n Forment, y de Francisco Goya, esculpidos en el taller de Carlos Palao y Pascual Salaberri. A su derecha, su hijo modela un busto de su mujer, que posa para la ocasi‚îú‚îÇn. Fuente: Foto Freudenthal.', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64307300, -0.88417800, '0101000020E61000004DF73AA92F4BECBF66F84F3750D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24050507374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24050507374.webp', 'https://www.flickr.com/photos/zaragozaantigua/24050507374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25038, 'Calle del Arte 1936', 'Imagen de la antigua calle del Arte, cuando terminaba bruscamente a la altura del n‚î¨‚ïë 27, con una valla tras la que extend‚îú¬°an huertos hasta el paseo de Sasera y el camino de las Torres, al fondo. La captura se ha realizado desde el arranque de la calle del Progreso (a la derecha, fuera de plano). A la izquierda, y luminosa, la fachada de la casa-taller que fuera del escultor Dionisio Lasu‚îú¬Æn, a‚îú‚ïën en pie, un poco antes del desemboque de la calle del doctor Casas. Casi enfrente, a la derecha, y en penumbra, la casa n‚î¨‚ïë 16, dise‚îú‚ñíada recientemente por Alberto Huerta Mar‚îú¬°n, que perdura, como los n‚îú‚ïëmeros 20, 25 y 27. El resto, es de nueva planta. Fuente visual: diario "El Noticiero". Archivo Jos‚îú¬Æ Mar‚îú¬°a Ballest‚îú¬°n Miguel.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64307300, -0.88417800, '0101000020E61000004DF73AA92F4BECBF66F84F3750D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32478284526.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32478284526.webp', 'https://www.flickr.com/photos/zaragozaantigua/32478284526/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25046, 'Colegio El Salvador c.1900', 'Imagen capturada desde cierta altura, posiblemente desde el cuartel de Santa Engracia, con una vista de las traseras del gran colegio El Salvador, con entrada principal desde el paseo de Sagasta, cuya planta en forma de "U" se manifiesta bien visible. Por encima sobresale levemente la estructura del colegio del Sagrado Coraz‚îú‚îÇn. En primer t‚îú¬Ærmino, muros delimitadores de los jardines traseros del hotelito del n‚î¨‚ïë 1 de la plaza de Arag‚îú‚îÇn, y de la trinchera que encajonaba el cauce al aire del r‚îú¬°o Huerva. A la izquierda, vista parcial de la torre de los Campos El‚îú¬°seos y arranque del paseo de los Pl‚îú√≠tanos.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64753400, -0.88311100, '0101000020E6100000849CF7FF7142ECBF2786E464E2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49909332956.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49909332956.webp', 'https://www.flickr.com/photos/zaragozaantigua/49909332956/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25047, 'Colegio El Salvador 1908', 'Imagen capturada desde cierta altura de la fachada principal del gran colegio El Salvador, precedido por la ajardinada zona de ingreso desde el paseo de Sagasta. A la derecha de la escena, inmediato y fuera de plano, el callej‚îú‚îÇn de Rod‚îú‚îÇn entre el colegio y la hom‚îú‚îÇnima fundici‚îú‚îÇn.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64671600, -0.88442000, '0101000020E6100000CCB4FD2B2B4DECBF64E60297C7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49912056238.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49912056238.webp', 'https://www.flickr.com/photos/zaragozaantigua/49912056238/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25099, 'Saramago 1990', 'El escritor portugu‚îú¬Æs Jos‚îú¬Æ Saramago (1922-2010), Premio Nobel de Literatura en 1998, posa junto a Ram‚îú‚îÇn Ac‚îú¬°n, coordinador del ciclo pedag‚îú‚îÇgico "Invitaci‚îú‚îÇn a la lectura" del Ministerio de Educaci‚îú‚îÇn y Ciencia, celebrado en la sede central de Ibercaja. Es la primera de las tres visitas de Saramago a la ciudad. La toma se ha realizado junto a la entrada del aparcamiento de la calle de San Ignacio de Loyola, con el edificio de Ibercaja al fondo.', 1990, 1990, 1990, 'Anos 90', 'CENTRO', 41.64679300, -0.88405600, '0101000020E610000076A4FACE2F4AECBF1024EF1CCAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49128020041.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49128020041.webp', 'https://www.flickr.com/photos/zaragozaantigua/49128020041/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25229, 'P.‚î¨‚ïë de Marina Moreno c.1960', 'Imagen capturada desde la altura inmueble del n‚î¨‚ïë 8 del paseo de Marina Moreno. A la izquierda e inmediata, fachada de la Residencia Universitaria de los padres jesuitas. A la derecha, traseras al paseo de los "hotelitos" de la plaza de Arag‚îú‚îÇn correspondientes a los n‚îú‚ïëmeros 4 a 8, entre los que emerge el edificio de Capitan‚îú¬°a General y el moderno inmueble chaflanero con la calle del Doctor Cerrada. Hacia el fondo y tras la plaza de Basilio Para‚îú¬°so, el arranque del paseo de Calvo Sotelo flanqueado por el Edificio El‚îú¬°seos y la Facultad de Medicina y Ciencias.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.64770300, -0.88388400, '0101000020E61000002FA52E19C748ECBFB34291EEE7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49506727006.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49506727006.webp', 'https://www.flickr.com/photos/zaragozaantigua/49506727006/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25580, 'Marina Moreno 1960', 'Imagen en altura del Paseo de Marina Moreno, hasta el arranque del Paseo de la Mina. A la izquierda, los edificios de la entrada a la calle Mefisto y a la plaza de Jos‚îú¬Æ Antonio. Al fondo, el antiguo edificio del colegio del Sagrado Coraz‚îú‚îÇn, junto al Huerva. M‚îú√≠s al fondo, a la izquierda, visual de las instalaciones de la f‚îú√≠brica de Gas del Camino de las Torres. Fuente: Archivo Municipal. Gerardo Sancho Ramo. 1960.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.64720100, -0.88015600, '0101000020E6100000051A6CEA3C2AECBF21787C7BD7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15710838161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15710838161.webp', 'https://www.flickr.com/photos/zaragozaantigua/15710838161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25902, 'P.‚î¨‚ïë de Marina Moreno c.1974', 'Esquina de la calle de Agustina Sim‚îú‚îÇn con el paseo de Marina Moreno de Zaragoza. En el centro, un troleb‚îú‚ïës de dos pisos de la l‚îú¬°nea Ciudad Jard‚îú¬°n. Fuente: dp-foto.blogspot.com', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.64791800, -0.88388500, '0101000020E610000046990D32C948ECBFAF3E1EFAEED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20515487658.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20515487658.webp', 'https://www.flickr.com/photos/zaragozaantigua/20515487658/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25995, 'Miraflores 1961', 'Una mirada en altura al sureste de la ciudad, con el Camino de las Torres en primer t‚îú¬Ærmino (hasta los tejados de teja de las inmediatas parcelas), los campos de herb‚îú√≠ceas de Miraflores, las tapias del convento-colegio de los PP Agustinos, el Colegio de San Jos‚îú¬Æ de Calasanz, las parcelas de la calle Lobera, Tenor Fleta en progresi‚îú‚îÇn constructiva, la f‚îú√≠brica de "La Zaragozana" (con su chimenea a‚îú‚ïën en pie) junto al antiguo Camino de las Alcachoferas... La imagen est‚îú√≠ capturada desde la terraza del n‚î¨‚ïë 46 de la calle General Sueiro. El vecino n‚î¨‚ïë 54 recayente al Camino de las Torres est‚îú√≠ en construcci‚îú‚îÇn. Fuente visual: www.facebook.com/photo.php?fbid=10205721956156450&set...', 1961, 1961, 1961, 'Anos 60', 'CENTRO', 41.64227500, -0.87994600, '0101000020E61000005DDF87838428ECBFEA04341136D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20454695486.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20454695486.webp', 'https://www.flickr.com/photos/zaragozaantigua/20454695486/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26047, 'Vista panor‚îú√≠mica c.1904', 'Postal panor‚îú√≠mica coloreada que muestra el arbolado curso del r‚îú¬°o Huerva, con las traseras de la iglesia de Santa Engracia. Al fondo, la torre del Pilar, la Seo, la Magdalena, San Carlos y San Miguel. Fuente: www.todocoleccion.net', 1904, 1904, 1904, 'Anos 1900', 'CENTRO', 41.64809200, -0.88222300, '0101000020E6100000A2ED98BA2B3BECBF4D66BCADF4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31682760194.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31682760194.webp', 'https://www.flickr.com/photos/zaragozaantigua/31682760194/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26062, 'Av. de Marina Moreno c.1963', 'Imagen capturada desde la altura del Edificio El‚îú¬°seos y centrada en el arranque de la avenida de Marina Moreno. A la izquierda, interesante vista de las traseras de los hotelitos de la plaza de Arag‚îú‚îÇn recayentes a la frondosa avenida, ya con el hueco dejado por el pionero derribo del edificio del antiguo Gobierno Civil. A la derecha, la mole del colegio del Salvador y la Residencia Universitaria de los PP. Jesuitas. En el centro de la escena, la iglesia de Santa Engracia y el convento de las Religiosas de Mar‚îú¬°a Inmaculada, tras el que destaca el cartel‚îú‚îÇn del Gran Hotel. Hacia el fondo, y de izquierda a derecha, emergen diversas torres de la ciudad: la de la Seo, de la Caja de Previsi‚îú‚îÇn Social, las de San Pedro Nolasco, de Santa Mar‚îú¬°a Magdalena, y de San Carlos Borromeo.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.64693500, -0.88461200, '0101000020E6100000DAC534D3BD4EECBFA2D11DC4CED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49080041646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49080041646.webp', 'https://www.flickr.com/photos/zaragozaantigua/49080041646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21316, 'Pabell‚îú‚îÇn Mariano 1908', 'Dibujo del "Pabell‚îú‚îÇn Mariano a vista de p‚îú√≠jaro" incluido en la serie de postales editadas por la revista religiosa "Anales del Pilar". En este ef‚îú¬°mero edificio, proyectado por el arquitecto Jos‚îú¬Æ Mar‚îú¬°a Peric‚îú√≠s Morros dentro del recinto de la Exposici‚îú‚îÇn Hispano-Francesa de 1908, tuvo lugar la denominada "Exposici‚îú‚îÇn Mariana Universal de Zaragoza", que inclu‚îú¬°a una antropol‚îú‚îÇgica selecci‚îú‚îÇn de objetos relacionados con el culto mariano y artesan‚îú¬°as asociadas a sus ritos y ceremoniales. En esta idealizada escena "a vista de p‚îú√≠jaro", el Pabell‚îú‚îÇn Mariano aparece flanqueado a la izquierda por los trazos esbozados del Pabell‚îú‚îÇn de Tracci‚îú‚îÇn, y a la derecha por el Palacio de Bellas Artes. Al fondo, el Pabell‚îú‚îÇn de Alimentaci‚îú‚îÇn. Fuente visual: Litograf‚îú¬°a Mar‚îú¬°n, en www.delcampe.net/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64772100, -0.87886200, '0101000020E6100000124F7633A31FECBF59F78F85E8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40224270183.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40224270183.webp', 'https://www.flickr.com/photos/zaragozaantigua/40224270183/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21334, 'P.‚î¨‚ïë de la Mina 1903', 'Imagen capturada en el antiguo paseo de Ronda, nuevo de la Mina y calle del Asalto (en el tramo comprendido entre la Puerta Quemada y la Puerta del Sol), con motivo del ferial de ganados de abasto y caballer‚îú¬°as aqu‚îú¬° instalado en octubre al hilo de las Fiestas del Pilar. Centra la escena un puesto donde se anuncia "carruajes venta- nuevos y usados- ay mas donde elejir".', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.64855200, -0.87727500, '0101000020E610000018265305A312ECBFB1E07EC003D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51700381115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51700381115.webp', 'https://www.flickr.com/photos/zaragozaantigua/51700381115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21336, 'Palacio de Museos 1908', '"Palacio de Museos", pabell‚îú‚îÇn permanente de la Exposici‚îú‚îÇn Hispano-Francesa de 1908 en la huerta de Santa Engracia, seg‚îú‚ïën proyecto de Ricardo Magdalena y Julio Bravo. Desde su apertura en 1911, funciona como museo de la ciudad.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64820800, -0.87860500, '0101000020E61000003D44A33B881DECBFB680D07AF8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53757128962.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53757128962.webp', 'https://www.flickr.com/photos/zaragozaantigua/53757128962/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21338, 'Interior Pabell‚îú‚îÇn Mariano 1908', 'Interior del Pabell‚îú‚îÇn Mariano en la Exposici‚îú‚îÇn Hispano-Francesa de 1908, huerta de Santa Engracia.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64780700, -0.87964600, '0101000020E6100000B7D4415E0F26ECBF588FFB56EBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53816044442.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53816044442.webp', 'https://www.flickr.com/photos/zaragozaantigua/53816044442/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21340, 'Arte Retrospectivo Sala de la Casa Real 1908', 'Sala de la Casa Real dentro de la muestra de Arte Retrospectivo en la Exposici‚îú‚îÇn Hispano-Francesa de 1908, huerta de Santa Engracia.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64820800, -0.87860500, '0101000020E61000003D44A33B881DECBFB680D07AF8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53816964866.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53816964866.webp', 'https://www.flickr.com/photos/zaragozaantigua/53816964866/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21343, 'Interior Industrias Art‚îú¬°sticas 1908', 'Interior del Pabell‚îú‚îÇn de Industrias Art‚îú¬°sticas en la Exposici‚îú‚îÇn Hispano-Francesa de 1908, huerta de Santa Engracia.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64820800, -0.87860500, '0101000020E61000003D44A33B881DECBFB680D07AF8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53817198898.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53817198898.webp', 'https://www.flickr.com/photos/zaragozaantigua/53817198898/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21344, 'Comensales Pab Mariano 1908', 'Comensales reunidos en el interior del Pabell‚îú‚îÇn Mariano en la Exposici‚îú‚îÇn Hispano-Francesa de 1908, huerta de Santa Engracia.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64792700, -0.87914200, '0101000020E6100000F1475167EE21ECBF03999D45EFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53817223098.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53817223098.webp', 'https://www.flickr.com/photos/zaragozaantigua/53817223098/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21689, 'Club de Tenis 1938', 'AHPZ. Estudio Coyne. Manuel Coyne. 1938. El ch‚îú‚îÇfer de un alto mando del ej‚îú¬Ærcito nacionalista en posici‚îú‚îÇn de espera con faria, a la puerta del "Real Zaragoza Club de Tenis", mientras su superior termina el partido. Este Club estaba ubicado en el Paseo de la Mina, junto al colegio de los Corazonistas, a la altura de La Caridad. Al otro lado del Huerva estaba el "Gas", cuyo identitario dep‚îú‚îÇsito se vislumbra borroso al fondo de la imagen.', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.64753400, -0.87774700, '0101000020E6100000063065E08016ECBF2786E464E2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15002472506.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15002472506.webp', 'https://www.flickr.com/photos/zaragozaantigua/15002472506/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21893, 'Hospital musulm‚îú√≠n 1938', 'Imagen centrada en la parte superior del chafl‚îú√≠n del inmueble del n‚î¨‚ïë 7 de la plaza de Castelar, redenominada de Jos‚îú¬Æ Antonio, proyectado en 1934 por Antonio Merlo Garc‚îú¬°a de Pruneda para acoger la Delegaci‚îú‚îÇn de Hacienda, y habilitado como hospital musulm‚îú√≠n durante la guerra de 1936-39. Con motivo de la visita de diversas autoridades la v‚îú¬°spera del "glorioso alzamiento", enfermeras y algunos enfermos saludan brazo al aire, mientras ondean las banderas de la Espa‚îú‚ñía nacionalista, de FET y JONS, y la jalifiana del territorio colonial de Marruecos.', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.64792700, -0.87914200, '0101000020E6100000F1475167EE21ECBF03999D45EFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49921560763.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49921560763.webp', 'https://www.flickr.com/photos/zaragozaantigua/49921560763/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21920, 'Plaza de Castelar 1938', 'Imagen capturada durante el recital de guitarra que Regino S‚îú√≠inz de la Maza ofreci‚îú‚îÇ de buena tarde en el Saloncillo de visitas del Hospital Musulm‚îú√≠n, con presencia de su director, Joaqu‚îú¬°n de Benito, el personal facultativo y auxiliar, las "se‚îú‚ñíoritas enfermeras", as‚îú¬° como los heridos y enfermos all‚îú¬° hospitalizados. El reconocido guitarrero interpret‚îú‚îÇ fragmentos de "nuestra m‚îú‚ïësica cl‚îú√≠sica, exquisita, magna e imperial del siglo XVI en tiempos de Carlos I y Felipe II"... compuesta por Isaac Alb‚îú¬Æniz, Enrique Granados y Joaqu‚îú¬°n Malats a finales del siglo XIX y comienzos del XX. Adem‚îú√≠s de ser portavoz de aquella "gloriosa Espa‚îú‚ñía Imperial", era considerado tambi‚îú¬Æn "portavoz de la m‚îú‚ïësica Imperial de la Espa‚îú‚ñía Una, Grande y Libre". Este recital fue seguido de otro en el Grupo Escolar Joaqu‚îú¬°n Costa, tambi‚îú¬Æn para tropas heridas, adem‚îú√≠s de un concierto ben‚îú¬Æfico a favor del Auxilio Social que tuvo como escenario el Teatro Parisiana, ya que este int‚îú¬Ærprete "desinteresadamente se ha puesto a la disposici‚îú‚îÇn del Caudillo para toda obra patri‚îú‚îÇtica".', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.64792700, -0.87914200, '0101000020E6100000F1475167EE21ECBF03999D45EFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54237675965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54237675965.webp', 'https://www.flickr.com/photos/zaragozaantigua/54237675965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22005, 'Jefatura del Aire 1941', 'Dibujo del proyecto de nuevo edificio para la Jefatura del Aire del ej‚îú¬Ærcito, por Lorenzo Moncl‚îú‚ïës, 1941. Se inaugur‚îú‚îÇ en 1949, en la calle Mefisto 2, notablemente modificado respecto al proyecto que se muestra. Fuente: www.ebay.es', 1941, 1941, 1941, 'Anos 40', 'CENTRO', 41.64803600, -0.87938900, '0101000020E6100000E2C96E66F423ECBFB950F9D7F2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36756237876.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36756237876.webp', 'https://www.flickr.com/photos/zaragozaantigua/36756237876/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22098, 'P.‚î¨‚ïë de la Mina 1951', 'Vista a‚îú¬Ærea del paseo de la Mina y y su entorno, hacia 1950. Abajo, el solar de los futuros bloques de la calle Concepci‚îú‚îÇn, propiedad de una mutualidad aseguradora, y el gas‚îú‚îÇgeno. En el centro, el colegio Corazonistas y el Club de Tenis. Arriba a la derecha, la plaza de Jos‚îú¬Æ Antonio. Fuente: www.facebook.com/photo.php?fbid=519637008191327&set=p...', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64818900, -0.87708400, '0101000020E61000002009FB761211ECBF40506EDBF7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20349410738.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20349410738.webp', 'https://www.flickr.com/photos/zaragozaantigua/20349410738/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22281, 'Quiosco de la M‚îú‚ïësica 1968', 'Andamios alrededor del Quiosco de la M‚îú‚ïësica en su ubicaci‚îú‚îÇn de la Plaza de los Sitios a finales del mes de enero, cuando se estaba procediendo a desmontarlo y trasladarlo despu‚îú¬Æs al Parque Primo de Rivera. Llevaba casi 44 a‚îú‚ñíos en esa ubicaci‚îú‚îÇn (en su Segunda ‚îú√´poca). Fuente visual: Gerardo Sancho Ramo, en AMZ', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64840000, -0.87963500, '0101000020E6100000BC57AD4CF825ECBFFB5C6DC5FED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15013034895.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15013034895.webp', 'https://www.flickr.com/photos/zaragozaantigua/15013034895/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22294, 'Huerva 1965', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 26/03/1965. "Ni‚îú‚ñíos jugando en la margen del Huerva." El r‚îú¬°o Huerva a su paso por la ciudad, y en algunos de los tramos a‚îú‚ïën al aire, presentaba importantes pendientes que hac‚îú¬°an complicado deambular por su ribera (calles Manuel Lasala, Alf‚îú¬Ærez Provisional, Coimbra...). El r‚îú¬°o aparec‚îú¬°a "encajonado" de forma natural, aisl‚îú√≠ndolo de su entorno, salvo para los osados. En la imagen, algunos de los osados que encontraban en este lugar una prolongaci‚îú‚îÇn de las calles y caminos en que jugar y socializarse. Entorno de la calle Coimbra.', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.64807100, -0.87657800, '0101000020E61000002D944C4EED0CECBF363E93FDF3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15391825761.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15391825761.webp', 'https://www.flickr.com/photos/zaragozaantigua/15391825761/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22333, 'Huerva 1968', 'Imagen de la brusca curva del Huerva en el paseo de la Mina, una captura un poco antes del cubrimiento de este tramo del cauce del r‚îú¬°o, que llegar‚îú√≠ justo hasta la pasarela de hierro. A la derecha quedan las antiguas instalaciones de la harinera de los Hermanos Solsona, funcional entre 1900 y 1922, que junto a la cercana de Marcos Samper conformaba uno de los n‚îú‚ïëcleos urbanos de este sector industrial de transformaci‚îú‚îÇn. Varias d‚îú¬Æcadas despu‚îú¬Æs, y tras su derribo, sobre ella ser‚îú√≠ construido el p‚îú‚ïëblico IES "Medina Albaida". Al fondo, el ic‚îú‚îÇnico dep‚îú‚îÇsito del "Gas" del Camino de las Torres, y los bloques de viviendas de la calle Co‚îú¬°mbra. La pasarela sobre el r‚îú¬°o era denominada "de Corazonistas", pues conectaba directamente con el colegio que al otro lado del r‚îú¬°o ten‚îú¬°an los Hermanos del Sagrado Coraz‚îú‚îÇn desde finales de los a‚îú‚ñíos 20. Tras el cubrimiento, la continua y tolerada invasi‚îú‚îÇn privada del Dominio P‚îú‚ïëblico Hidr‚îú√≠ulico en este sector del r‚îú¬°o, hace que el Huerva siga siendo un extra‚îú‚ñío canal de agua, visible, pero lejano, como ajeno. Fuente visual: AMZ.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64636400, -0.87781100, '0101000020E6100000B53522180717ECBFE7A7380EBCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19259677283.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19259677283.webp', 'https://www.flickr.com/photos/zaragozaantigua/19259677283/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25982, 'La H‚îú¬°pica y El Huevo 1975', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 27/07/1975. Imagen desde altura del estado de las cosas en la Romareda, en la zona cercana a la H‚îú¬°pica (muros, ‚îú√≠rboles, instalaciones deportivas varias, piscina...) Los camiones est‚îú√≠n aparcados en lo que luego ser‚îú√≠ denominado "Calle Violante de Hungr‚îú¬°a", y en el enorme descampado de primer t‚îú¬Ærmino se edificar‚îú√≠ el municipal equipamiento deportivo conocido como "El Huevo", por su oval dise‚îú‚ñío. El enorme bloque de viviendas de la derecha anuncia la cercana presencia del pol‚îú¬°gono Romareda. Detr‚îú√≠s de ‚îú¬Æl, la nueva calle de As‚îú¬°n y Palacios, continuaci‚îú‚îÇn de la "vieja" Francisco de Borja.', 1975, 1975, 1975, 'Anos 70', 'UNIVERSIDAD', 41.63981300, -0.90404300, '0101000020E6100000F3AFE595EBEDECBF1F477364E5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15279998311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15279998311.webp', 'https://www.flickr.com/photos/zaragozaantigua/15279998311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22465, 'Huerva 1968', 'Imagen capturada desde el cauce al aire del Huerva, justo antes de la gran curva que lo conduce al puente de San Jos‚îú¬Æ, aguas abajo, con parte del tramo pendiente de recubrimiento que, desde el fondo, se iba a acometer poco despu‚îú¬Æs. A la izquierda, conjunci‚îú‚îÇn visual del antiguo entorno del paseo de los Pl‚îú√≠tanos, con las industriosas construcciones de primer t‚îú¬Ærmino (harinera de Marcos Samper), y los grandes bloques emergentes, detr‚îú√≠s, recayentes a la calle de Leon XIII n‚î¨‚ïë 1, 3 y 5. En el centro, al fondo, las traseras de la iglesia parroquial de Santa Engracia, y la pasarela peatonal que conectaba ambas m‚îú√≠rgenes fluviales. A la derecha, muro perimetral y ‚îú√≠rboles del colegio del Sagrado Coraz‚îú‚îÇn del paseo de la Mina. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64597100, -0.87840100, '0101000020E61000001EC2F869DC1BECBF0C957F2DAFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32749892084.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32749892084.webp', 'https://www.flickr.com/photos/zaragozaantigua/32749892084/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22718, 'Parque Miraflores 1979', 'Urbanizaci‚îú‚îÇn Parque de Miraflores desde la calle de Uncastillo, con el colegio Miraflores a la izquierda. Algunos bloques est‚îú√≠n en construcci‚îú‚îÇn, y otros solares esperan ser urbanizados. El hex‚îú√≠gono central ser‚îú√≠ ocupado despu‚îú¬Æs por la iglesia del Sagrado Coraz‚îú‚îÇn de Jes‚îú‚ïës, sustituyendo a la advocaci‚îú‚îÇn de la plaza de San Pedro Nolasco, cerrada al culto. Al fondo, prolongaci‚îú‚îÇn de la avenida de Marina Moreno, ya redenominada de Ces‚îú√≠reo Alierta.', 1979, 1979, 1979, 'Anos 70', 'CENTRO', 41.64105300, -0.87802800, '0101000020E6100000FC1C1F2DCE18ECBF580053060ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30136070683.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30136070683.webp', 'https://www.flickr.com/photos/zaragozaantigua/30136070683/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22784, 'P.‚î¨‚ïë de Marina Moreno 1979', 'Imagen capturada en el Pol‚îú¬°gono 12 del barrio de San Jos‚îú¬Æ, una interesante zona de actuaci‚îú‚îÇn urban‚îú¬°stica delimitada por la prolongaci‚îú‚îÇn del paseo de Marina Moreno, la calle de Miguel Servet, la avenida de San Jos‚îú¬Æ y el camino de las Torres que fue iniciada por el sector inmobiliario antes de que estuviera redactado el Plan Parcial que rigiera su ordenaci‚îú‚îÇn. Este Pol‚îú¬°gono formaba parte del Plan General de Ordenaci‚îú‚îÇn Urbana del a‚îú‚ñío 1969. El Pol‚îú¬°gono fue cogiendo forma al ritmo que marcaban los emprendedores privados sin previsi‚îú‚îÇn de equipamientos escolares, deportivos ni sanitarios, y las zonas verdes quedaron constre‚îú‚ñíidas en la zona interior de las densas manzanas de bloques, a modo de los antiguos patios o corralas comunes. Este modelo de urbanismo a la carta supuso, adem‚îú√≠s, el exponencial crecimiento de la circulaci‚îú‚îÇn automovil‚îú¬°stica en la zona. En la imagen, vista parcial del sector del Pol‚îú¬°gono 12 entre la prolongaci‚îú‚îÇn del paseo de Marina Moreno (izquierda), el camino de las Torres (tras los modernos bloques del n‚î¨‚ïë 15 de Marina Moreno y el 27-29 de ese camino) y la calle de Lorenzo Pardo (derecha). En primer plano, solar habilitado como provisional aparcamiento en superficie donde a‚îú‚ñíos despu‚îú¬Æs se levantar‚îú¬°a el edificio Los Arcos de CIUVASA. Fuente visual: Andal‚îú√≠n, peri‚îú‚îÇdico semanal aragon‚îú¬Æs, 1979.', 1979, 1979, 1979, 'Anos 70', 'CENTRO', 41.64431300, -0.87615800, '0101000020E6100000DE1E84807C09ECBF9EB12FD978D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38399599026.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38399599026.webp', 'https://www.flickr.com/photos/zaragozaantigua/38399599026/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22803, 'Pol‚îú¬°gono Miraflores 1975', 'Imagen capturada en el Pol‚îú¬°gono Miraflores durante el montaje de algunas de las atracciones que conformaban el recinto ferial habilitado durante las Fiestas del Pilar en esta zona, antes de su urbanizaci‚îú‚îÇn. Al fondo, muro perimetral tras el que destaca el volumen del colegio de los Agustinos y la parroquia de Santa Rita de Casia. A continuaci‚îú‚îÇn, bloques de viviendas del camino de las Torres, la torre que culminaba el moderno convento de la Congregaci‚îú‚îÇn de las Hermanas Oblatas del Sant‚îú¬°simo Redentor, en la chaflanera esquina de la plaza del doctor Albert Schweitzer, y la chimenea de la f‚îú√≠brica textil Lanera Aragonesa junto a la acequia de las Adulas del Huerva, o de San Jos‚îú¬Æ.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.64120000, -0.87789700, '0101000020E610000059350873BB17ECBFFC1873D712D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48099409518.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48099409518.webp', 'https://www.flickr.com/photos/zaragozaantigua/48099409518/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22897, 'C.‚î¨‚ïë de las Torres 1983', 'El camino de las Torres, en una escena nevada de su confluencia con la avenida de Ces‚îú√≠reo Alierta, al fondo, con el tel‚îú‚îÇn de sus grandes bloques del lado de los pares en el tramo hasta la calle de San Vicente M‚îú√≠rtir. A la izquierda e inmediato, tramo al aire de la acequia de San Jos‚îú¬Æ, y arqueol‚îú‚îÇgica vista del viejo y unidireccional camino de las Torres. A la derecha, la antigua f‚îú√≠brica de Gas, durante el proceso de su derribo, donde destaca un cartel indicador de la empresa.', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.64568800, -0.87693400, '0101000020E6100000CD0358E4D70FECBFB7B585E7A5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20563238384.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20563238384.webp', 'https://www.flickr.com/photos/zaragozaantigua/20563238384/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22898, 'Ces‚îú√≠reo Alierta 1983', 'Vista nevada de la avenida de Ces‚îú√≠reo Alierta en una imagen capturada en altura desde el inmueble del n‚î¨‚ïë 15 del camino de las Torres. Inmediatas, dependencias de la f‚îú√≠brica de Gas. A la derecha, torre y pabellones del colegio Sagrado Coraz‚îú‚îÇn del paseo de la Mina, tras el r‚îú¬°o Huerva. El gran solar de primer t‚îú¬Ærmino ser‚îú√≠ urbanizado luego con edificaciones residenciales, hoteleras, comerciales y trazado urbano, adem‚îú√≠s del IES Medina Albaida. Al fondo, la mole del edificio central de Ibercaja.', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.64568800, -0.87693400, '0101000020E6100000CD0358E4D70FECBFB7B585E7A5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20565824553.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20565824553.webp', 'https://www.flickr.com/photos/zaragozaantigua/20565824553/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22964, 'Av. de Ces‚îú√≠reo Alierta 1985', 'Imagen capturada en el primer tramo de los impares de la avenida de Ces‚îú√≠reo Alierta y a espaldas del camino de las Torres. Esta foto, centrada originalmente en el asunto de uno de los anunciantes publicitarios de la derecha, nos da pie para traspasar figuradamente el muro perimetral que soporta los cartelones. Tras este muro se encontraba en situaci‚îú‚îÇn de barbecho expectante el enorme solar de la antigua huerta de la f‚îú√≠brica de harinas de Solsona, que hacia el fondo continuaba donde esta empresa tuvo los edificios fabriles en una ubicaci‚îú‚îÇn junto al cauce del r‚îú¬°o Huerva. Hacia la derecha y fuera de cuadro quedaba tambi‚îú¬Æn el vecino solar de la antigua Torre de Baselga y sus recordadas piscinas, seguido a continuaci‚îú‚îÇn por el solar que ocupara la F‚îú√≠brica de Gas de Zaragoza S.A. En primer t‚îú¬Ærmino, marquesina correspondiente a la parada "Av. Ces‚îú√≠reo Alierta- Cn. Torres" de la l‚îú¬°nea 25 de autob‚îú‚ïës "B‚î¨‚ïë de La Cartuja-Miralbueno" de los Transportes Urbanos de Zaragoza, S.A. Unos a‚îú‚ñíos m‚îú√≠s tarde comenzar‚îú¬°a el proceso de urbanizaci‚îú‚îÇn de esta zona, con la construcci‚îú‚îÇn de varios modernos inmuebles de uso residencial, comercial, recreativo, hotelero, ministerial y educativo p‚îú‚ïëblico, una zona verde, adem‚îú√≠s del tendido de un nuevo puente sobre el r‚îú¬°o Huerva que supondr‚îú¬°a la apertura de una nueva calle denominada de Jos‚îú¬Æ Luis Pomar‚îú‚îÇn que comunica desde entonces el paseo de la Mina y el camino de las Torres.', 1985, 1985, 1985, 'Anos 80', 'CENTRO', 41.64550800, -0.87790700, '0101000020E61000003CBEBD6BD017ECBF37A79201A0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53261657282.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53261657282.webp', 'https://www.flickr.com/photos/zaragozaantigua/53261657282/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23067, 'Plaza de los Sitios 1997', 'Imagen capturada en el interior del Museo de Zaragoza durante la clausura de la exposici‚îú‚îÇn "Permanencia de la memoria. Cartones para tapiz y dibujos de Goya" con que se dio por clausurado el denominado "A‚îú‚ñío de Goya" que en 1996 y 1997 conmemor‚îú‚îÇ el aniversario 250 del nacimiento del pintor Francisco Goya. Para tal ocasi‚îú‚îÇn Zaragoza recibi‚îú‚îÇ la visita de Fabiola de Mora y Arag‚îú‚îÇn, arist‚îú‚îÇcrata madrile‚îú‚ñía y reina consorte de los belgas tras su boda en 1960 con el rey Balduino de ese pa‚îú¬°s. As‚îú¬°, la fotograf‚îú¬°a se centra en esta ilustre invitada flanqueada por altos representantes institucionales de la Espa‚îú‚ñía, el Arag‚îú‚îÇn y la Zaragoza de la ‚îú¬Æpoca: a la derecha, Santiago Lanzuela Marina, presidente del Gobierno de Arag‚îú‚îÇn junto a su esposa Magdalena G‚îú√≠rate y Luis Antonio Rosel Onde, delegado del Gobierno en Arag‚îú‚îÇn. A la izquierda, Francisco ‚îú√ºlvarez Cascos, vicepresidente primero del Gobierno de Espa‚îú‚ñía, seguido por su segunda esposa Gema Ruiz; Luisa Fernanda Rudi ‚îú√úbeda, alcaldesa de Zaragoza y Vicente Bielza de Ory, consejero de Educaci‚îú‚îÇn y Cultura del Gobierno de Arag‚îú‚îÇn. Tras el grupo y de tel‚îú‚îÇn de fondo, el tapiz de Goya titulado "La boda", prestado por la Casa Real de B‚îú¬Ælgica para formar parte de la referida exposici‚îú‚îÇn. Este tapiz fue regalado en 1865 por la reina Isabel II de Espa‚îú‚ñía al nuevo rey de los belgas Leopoldo II con motivo de su coronaci‚îú‚îÇn, que a‚îú‚ñíos despu‚îú¬Æs se coronar‚îú¬°a de pleno derecho como el genocida "carnicero del Congo".', 1997, 1997, 1997, 'Anos 90', 'CENTRO', 41.64820800, -0.87860500, '0101000020E61000003D44A33B881DECBFB680D07AF8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54867683871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54867683871.webp', 'https://www.flickr.com/photos/zaragozaantigua/54867683871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23260, 'Camino de las Torres 1897', 'Imagen promocional de la que comenz‚îú‚îÇ siendo f‚îú√≠brica de cors‚îú¬Æs de Pilar Lana en el camino de las Torres n‚î¨‚ïë 191, ya como f‚îú√≠brica de chocolates, caf‚îú¬Æs y t‚îú¬Æs, aqu‚îú¬° ubicada durante un breve lapso de tiempo (1897-1901), antes de trasladarse a la calle del Cinco de Marzo, primero, y luego a la antigua huerta de Santa Engracia. Destaca el acceso a trav‚îú¬Æs de un paso que salva la caudalosa acequia de las Adulas, del Penal, o de San Jos‚îú¬Æ, en su tr‚îú√≠nsito hacia Miguel Servet (por la izquierda). A la derecha, la caseta que derivaba para la f‚îú√≠brica una parte del caudal de la acequia, y de la que sal‚îú¬°a un riego con agua sobrante hacia la huerta de Miraflores. Fuente visual: www.todocoleccion.net/', 1897, 1897, 1897, 'Siglo XIX', 'CENTRO', 41.64430500, -0.87808900, '0101000020E610000067463F1A4E19ECBF1CD3139678D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30562832100.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30562832100.webp', 'https://www.flickr.com/photos/zaragozaantigua/30562832100/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23268, 'R‚îú¬°o Huerva 1808', '"Bater‚îú¬°a de Santa Engracia: arruinada el 4 de Agosto de 1808". Serie Ruinas de Zaragoza, de Juan G‚îú√≠lvez (dibujo) y Fernando Brambila (grabado), C‚îú√≠diz, 1812. La bater‚îú¬°a de Santa Engracia fue situada en las proximidades del convento e iglesia del mismo nombre, apoyada drectamente en el pretil del r‚îú¬°o Huerva cuyo cauce al natural ejerc‚îú¬°a de natural trinchera defensiva. En la otra ribera, m‚îú√≠s elevada, merodean los soldados franceses. A la derecha, quedaba el puente de Santa Engracia, pronto destruido. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.64702400, -0.87760500, '0101000020E610000068CBB9145715ECBF12DDB3AED1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15244837956.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15244837956.webp', 'https://www.flickr.com/photos/zaragozaantigua/15244837956/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24087, 'Av. de Ces‚îú√≠reo Alierta 1984', 'Imagen capturada junto a la entrada de "El Urbano", pabell‚îú‚îÇn habilitado durante las fiestas del Pilar por las pe‚îú‚ñías Forca y El Rebullo en la v‚îú¬°a p‚îú‚ïëblica del paso a desnivel sito en la avenida de Ces‚îú√≠reo Alierta bajo el camino de las Torres. Aunque ese mismo a‚îú‚ñío se hab‚îú¬°a constituido la federaci‚îú‚îÇn Interpe‚îú‚ñías de Zaragoza, en la ciudad todav‚îú¬°a pod‚îú¬°an encontrarse diversos espacios festivos impulsados por las pe‚îú‚ñías, como el pabell‚îú‚îÇn de la avenida de San Jos‚îú¬Æ, de Interpe‚îú‚ñías, y este mismo. La concesi‚îú‚îÇn del uso del suelo en v‚îú¬°a p‚îú‚ïëblica comenz‚îú‚îÇ pues casi al principio de la segunda legislatura de la Corporaci‚îú‚îÇn encabezada por Ram‚îú‚îÇn Sainz de Varanda, si bien ya en 1986 su sucesor Antonio Gonz‚îú√≠lez Trivi‚îú‚ñío se mostr‚îú‚îÇ partidario de no autorizar tal ocupaci‚îú‚îÇn, "pues ocasiona colapsos de tr‚îú√≠fico en los paseos de la Independencia y de la Constituci‚îú‚îÇn". Fuente visual: exposici‚îú‚îÇn √î√á√ñZaragoza y las fiestas del Pilar√î√á√ñ.', 1984, 1984, 1984, 'Anos 80', 'CENTRO', 41.64455400, -0.87738100, '0101000020E61000008237A4518113ECBFC440D7BE80D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44168636594.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44168636594.webp', 'https://www.flickr.com/photos/zaragozaantigua/44168636594/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24132, 'Edificio de los Museos 1908', 'Imagen capturada durante el proceso de construcci‚îú‚îÇn del nuevo edificio de los Museos, proyectado por Ricardo Magdalena y Julio Bravo como parte constitutiva del complejo de la Expo de 1908, ubicada en los antiguos terrenos de la huerta de Santa Engracia. Este patio articula el espacio construido, en formas regionalistas, neomedievales, ecl‚îú¬Æcticas. No deja de ser curioso este fen‚îú‚îÇmeno local consistente en construir nuevos edificios en formas y estilos propios de los palacios del renacimiento y barroco, mientras en paralelo se dejaban caer, o se derribaban directamente, los aut‚îú¬Ænticos palacios facturados en esos estilos. Este edificio sobrevivi‚îú‚îÇ a los fastos expositivos, y desde entonces ha sido objeto de modificaciones muy importantes. En la actualidad alberga al Museo de Zaragoza. Fuente visual: Gu‚îú¬°a del Museo de Zaragoza, DGA, 2003', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64824000, -0.87860500, '0101000020E61000003D44A33B881DECBFC2FA3F87F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18566518133.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18566518133.webp', 'https://www.flickr.com/photos/zaragozaantigua/18566518133/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24141, 'La Caridad 1907', 'Imagen obtenida a finales de 1907 durante la construcci‚îú‚îÇn del edificio denominado "La Caridad", que como parte integrante de los temporales pabellones de la Expo de 1908, ejercitar‚îú√≠ de "Palacio de Industrias". La captura se ha realizado desde la actual calle de Jos‚îú¬Æ Canalejas, entonces desprovista de otras edificaciones. A la izquierda, tambi‚îú¬Æn en construcci‚îú‚îÇn, "El Palacio de los Museos". Al fondo, entre ambos edificios, m‚îú√≠s andamios donde se est‚îú√≠ levantando el edificio de "Las Escuelas", luego Escuela de Artes y Oficios. A la derecha, alameda del Paseo de la Mina. La imagen incluye un interesante apunte del proceso constructivo de la ‚îú¬Æpoca: los regulares y peque‚îú‚ñíos "agujeros" de la fachada del edificio son los puntos de apoyo de los andamios de obra, que luego habr‚îú√≠ que cerrar. Fuente visual: Foto Escol‚îú√≠, para la revista "Mercurio".', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64787600, -0.87832500, '0101000020E61000005E4BC8073D1BECBF80EECB99EDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20208715271.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20208715271.webp', 'https://www.flickr.com/photos/zaragozaantigua/20208715271/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24146, 'Edificio &quot;Museos&quot; 1908', 'Imagen al final de la construcci‚îú‚îÇn del edificio destinado a "Museos" durante la Exposici‚îú‚îÇn Hispano-Francesa de 1908, proyecto de Ricardo Magdalena, y Julio Bravo. Se trata del lateral izquierdo del edificio, en la parte final de la prolongada calle de Costa, que a‚îú‚ñíos m‚îú√≠s tarde ser‚îú¬°a redenominada "Jos‚îú¬Æ Canalejas". Fuente visual: "Arquitectura y Construcci‚îú‚îÇn" (Barcelona).', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64796100, -0.87860400, '0101000020E61000002750C422861DECBFAF0AD462F0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22016715843.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22016715843.webp', 'https://www.flickr.com/photos/zaragozaantigua/22016715843/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24147, 'Edificio &quot;Museos&quot; 1908', 'Imagen al final de la construcci‚îú‚îÇn del edificio destinado a "Museos" durante la Exposici‚îú‚îÇn Hispano-Francesa de 1908, proyecto de Ricardo Magdalena, y Julio Bravo. Fuente visual: "Arquitectura y Construcci‚îú‚îÇn" (Barcelona).', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64824000, -0.87860500, '0101000020E61000003D44A33B881DECBFC2FA3F87F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22611099046.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22611099046.webp', 'https://www.flickr.com/photos/zaragozaantigua/22611099046/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24151, 'Edificio de los Museos 1908', 'Imagen de un grupo de personas disfrazadas de soldados de la Guerra de Independencia 1808-1814 posan en el patio del Edificio de los Museos de la antigua Huerta de Santa Engracia. "Para hacer la fotograf‚îú¬°a en colores seg‚îú‚ïën el nuevo procedimiento Lumiere, fueron los soldados de 1808 agrupados en el gran Patio del Palacio del Arte Antiguo". Fuente visual: l‚îú√≠mina en color reproducida por la Sociedad Lionesa de Fotocromograbado Hemmerl‚îú¬Æ de Lyon, con clich‚îú¬Æ de M. Emile Bertaux, obtenido con placa autocroma de los Sres. Lumi‚îú¬øre hermanos, en "Exposici‚îú‚îÇn Retrospectiva de Arte.-1908 Organizada bajo los auspicios del Excelent‚îú¬°simo Sr. Arzobispo de Zaragoza. [Real Junta del Centenario de los Sitios de 1808-1809] -L''Exposition Retrospective d''Art - 1908. Organisee sous les auspices de S. G. l''Archiveque de Saragosse. [Commission Royale du Centenaire des Sieges de 1808-1809]". Tipografia La Editorial (Zaragoza)-Librer‚îú¬°a Central de Bellas Artes (Par‚îú¬°s), 1910.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64823000, -0.87861700, '0101000020E61000004EB51666A11DECBF9E245D33F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26756038775.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26756038775.webp', 'https://www.flickr.com/photos/zaragozaantigua/26756038775/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24156, 'Pr‚îú‚îÇrroga Expo 1908', 'Imagen capturada en el interior del recinto de la Exposici‚îú‚îÇn Hispano Francesa de 1908, con un coral posado de pardales ante el emblem‚îú√≠tico pabell‚îú‚îÇn de Alimentaci‚îú‚îÇn. La clausura de esta muestra estaba prevista inicialmente a finales de octubre, pero la afluencia de p‚îú‚ïëblico prorrog‚îú‚îÇ el cierre hasta el mes de diciembre. Esta imagen se podr‚îú¬°a corresponder con esa etapa, tanto por las mantas y ropas de abrigo generalizadas, como porque ya es posible ver, al fondo, las alegor‚îú¬°as de la escultura, pintura y arquitectura, talladas por Carlos Palao como ornato de la fachada principal del Palacio de los Museos, y colocadas con un cierto retraso respecto de la fecha prevista. Fuente visual: Foto Estudio Coyne, AHPZ.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64839400, -0.87966600, '0101000020E61000007DE6AC4F3926ECBF19761893FED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31562618871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31562618871.webp', 'https://www.flickr.com/photos/zaragozaantigua/31562618871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24713, 'Barriada de Escoriaza 1991', 'Imagen capturada en las traseras de la barriada "Vizconde de Escoriaza" construida en 1953 para trabajadores de la empresa Los tranv‚îú¬°as de Zaragoza S.A., y con ingreso principal por la calle de Fray Luis Urbano. En primer t‚îú¬Ærmino, riego derivado de la acequia de San Jos‚îú¬Æ que, tras pasar soterrado bajo el grupo de viviendas vuelve a salir al aire bajo un puentecillo que salva su paso por lo que, aunque t‚îú¬Æcnicamente ya era el ‚îú‚ïëltimo tramo de la calle de San Adri‚îú√≠n de Sasabe, a efectos pr‚îú√≠cticos todav‚îú¬°a no lo parec‚îú¬°a.', 1991, 1991, 1991, 'Anos 90', 'LAS FUENTES', 41.64860800, -0.85766300, '0101000020E6100000EBA7FFACF971EBBF45F6419605D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50450638752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50450638752.webp', 'https://www.flickr.com/photos/zaragozaantigua/50450638752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24166, 'P.‚î¨‚ïë de la Mina 1907', 'Tardo-octubrina magen capturada durante las obras de construcci‚îú‚îÇn del edificio "La Caridad", concebido como segundo pabell‚îú‚îÇn permanente de la exposici‚îú‚îÇn Hispano-Francesa de 1908, as‚îú¬° denominado porque fue ideado para albergar luego la instituci‚îú‚îÇn ben‚îú¬Æfica as‚îú¬° denominada, fundada para evitar la mendicidad callejera. Fue proyectado por los arquitectos Luis de la Figuera Lezcano y Jos‚îú¬Æ de Yarza Echenique, si bien al entregar cada uno su propio proyecto de edificio se encarg‚îú‚îÇ de refundirlos y darles ‚îú‚ïënica forma el arquitecto municipal Ricardo Magdalena Tabuenca. Presupuestado en unas 300.000 pesetas, fue entregado a la muestra en abril de 1908. En la imagen, momento constructivo de este pabell‚îú‚îÇn en una vista tomada desde el paseo de Ronda o de la Mina.', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64775100, -0.87786500, '0101000020E610000081B229577817ECBFC4793881E9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54160569916.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54160569916.webp', 'https://www.flickr.com/photos/zaragozaantigua/54160569916/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24244, 'Jos‚îú¬Æ Galiay c.1950', 'Imagen de Jos‚îú¬Æ Galiay Sara‚îú‚ñíana (1880-1952), posiblemente en su despacho de director del Museo Provincial de Zaragoza. En su destacada faceta fotogr‚îú√≠fica, muy practicada en su etapa de comisario de excavaciones arqueol‚îú‚îÇgicas y de zona del Patrimonio Art‚îú¬°stico, destaca su constituci‚îú‚îÇn del visual "Fichero de Arte Aragon‚îú¬Æs", con numerosas im‚îú√≠genes de la Zaragoza de la primera mitad del siglo XX. Fuente visual: Archivo Fotogr‚îú√≠fico Jos‚îú¬Æ Galiay-AHPZ', 1950, 1950, 1950, 'Anos 50', 'CENTRO', 41.64823000, -0.87861700, '0101000020E61000004EB51666A11DECBF9E245D33F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30450016294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30450016294.webp', 'https://www.flickr.com/photos/zaragozaantigua/30450016294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24271, 'Quiosco de la M‚îú‚ïësica 1908', 'AHPZ-Archivo Coyne, Ignacio Coyne, 1908. Quiosco de la M‚îú‚ïësica en el Recinto Ferial de la Exposici‚îú‚îÇn de 1908.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64857600, -0.87936700, '0101000020E6100000EECF4543C623ECBF397CD28904D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14699797220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14699797220.webp', 'https://www.flickr.com/photos/zaragozaantigua/14699797220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24273, 'Plaza de Castelar 1930', '"Museo Provincial", en la Plaza de Castelar.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64812700, -0.87895900, '0101000020E6100000B0CBF09F6E20ECBFCA5356D3F5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14867705542.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14867705542.webp', 'https://www.flickr.com/photos/zaragozaantigua/14867705542/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24278, 'Quiosco de la M‚îú‚ïësica 1908', '1908. Imagen del "Quiosco de m‚îú‚ïësica" en el entorno de la Exposici‚îú‚îÇn Hispano-Francesa de 1908, en la Huerta de Santa Engracia. El Quiosco se encuentra entre el Pabell‚îú‚îÇn de la Alimentaci‚îú‚îÇn (derecha), y el "Pabell‚îú‚îÇn Franc‚îú¬Æs". Al fondo, viviendas de la cercana calle San Miguel. El Quiosco de primer plano es de otro tipo de musicalidad, m‚îú√≠s l‚îú¬°quida. El musical Quiosco, m‚îú√≠s que musical, ser‚îú√≠ viajero, muy viajero: en 1912 fue trasladado al Paseo de la Independencia; en 1924 volvi‚îú‚îÇ a su ubicaci‚îú‚îÇn en esta plaza, denominada de Castelar; en los a‚îú‚ñíos 60 fue de nuevo trasladado, en esta ocasi‚îú‚îÇn al Parque Primo de Rivera. All‚îú¬° sigue, aunque ahora ha sido redenominado Parque Grande Jos‚îú¬Æ Antonio Labordeta.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64840000, -0.87963500, '0101000020E6100000BC57AD4CF825ECBFFB5C6DC5FED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14981876831.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14981876831.webp', 'https://www.flickr.com/photos/zaragozaantigua/14981876831/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22046, 'Troleb‚îú‚ïës del Terminillo 1951', 'Colecci‚îú‚îÇn Mariano Rodr‚îú¬°guez Troleb‚îú‚ïës de la l‚îú¬°nea Terminillo, con el volante a la derecha por ser de fabricaci‚îú‚îÇn brit‚îú√≠nica, a su paso por la comisar‚îú¬°a de la avenida Valencia de Zaragoza.', 1951, 1951, 1951, 'Anos 50', 'UNIVERSIDAD', 41.64520600, -0.89987400, '0101000020E61000009BA9108FC4CBECBF6C97361C96D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14795594968.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14795594968.webp', 'https://www.flickr.com/photos/zaragozaantigua/14795594968/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24281, 'La Caridad c.1930', 'Reparto del bono semanal a los mendigos de la ciudad, por parte de la instituci‚îú‚îÇn denominada La Caridad (calle Segismundo Moret, 4), en las traseras del Museo de Zaragoza, que se ve al fondo, antes de la actual plaza de Los Sitios. La Asociaci‚îú‚îÇn Ben‚îú¬Æfica √î√á¬£La Caridad√î√á√ò lleva desde enero de 1910 en un edificio que form‚îú‚îÇ parte de los pabellones de la Exposici‚îú‚îÇn Hispano-Francesa de 1908. La presencia de guardia urbana (de uniforme, armados) y de funcionarios del Cuerpo (de paisano, desarmados) tiene que ver con la importante implicaci‚îú‚îÇn municipal del Ayuntamiento en el proyecto. Fuente visual: La Caridad, Centenaria. Sus primeros a‚îú‚ñíos (1898-1910), Ayuntamiento de Zaragoza, 2000.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64832800, -0.87778100, '0101000020E61000000B9B012EC816ECBF618A7269FCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15113536428.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15113536428.webp', 'https://www.flickr.com/photos/zaragozaantigua/15113536428/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24287, 'Pabell‚îú‚îÇn AHV 1908', 'Pabell‚îú‚îÇn particular de Altos Hornos de Vizcaya, con forma de horno de fundici‚îú‚îÇn, en la Exposici‚îú‚îÇn Hispano Francesa de Zaragoza en 1908. Se encontraba en las inmediaciones de la actual calle de Mefisto. Fuente visual: sestao.wordpress.com/2012/10/15/pabellon-de-ahv-en-la-exp... mostrada en www.facebook.com/photo.php?fbid=369314759892026&set=o...', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64789000, -0.87957500, '0101000020E610000068226C787A25ECBFE5B33C0FEED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15491146509.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15491146509.webp', 'https://www.flickr.com/photos/zaragozaantigua/15491146509/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24288, 'Exposici‚îú‚îÇn Hispano Francesa 1908', 'Vista del recinto de la Exposici‚îú‚îÇn Hispano Francesa de Zaragoza en 1908. En primer plano, a la derecha, torre del Pabell‚îú‚îÇn Mariano desde la altura del vecino Pabell‚îú‚îÇn particular de Altos Hornos de Vizcaya. A al izquierda, otros pabellones particulares, y el gran Pabell‚îú‚îÇn de Maquinaria. Al fondo, la vieja ciudad. Fuente visual: "Vista general de la Exposici‚îú‚îÇn Hispano-Francesa", fotograf‚îú¬°a de Ignacio Coyn‚îú¬Æ, en "Zaragoza art‚îú¬°stica ‚îú¬Æ industrial. ‚îú√ºlbum de la Exposici‚îú‚îÇn", 1908.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64815500, -0.87937500, '0101000020E6100000A4703D0AD723ECBF94DE37BEF6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15495429258.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15495429258.webp', 'https://www.flickr.com/photos/zaragozaantigua/15495429258/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24290, 'La Caridad c.1932', 'Terraza del edificio de La Caridad en la calle Moret 4 de Zaragoza, habilitada para patio de recreo de su escuela. Al fondo, la torre de la iglesia de San Miguel. Fuente: www.lacaridad.org/quienes-somos/historia/', 1932, 1932, 1932, 'Anos 30', 'CENTRO', 41.64793300, -0.87778300, '0101000020E61000003883BF5FCC16ECBFE57FF277EFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15709862492.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15709862492.webp', 'https://www.flickr.com/photos/zaragozaantigua/15709862492/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24291, 'Marina Moreno 1968', 'Una ma‚îú‚ñíana de niebla, el se‚îú‚ñíor C‚îú¬Æsar Garcia Jarque estaba por la "Avenida" Marina Moreno, donde arranca el paseo de la Mina, y se puso a hacer una foto a una pareja de currelas cruzando por el lugar m‚îú√≠s directo entre dos puntos, que suele ser una recta. Detr‚îú√≠s del tabl‚îú‚îÇn, el colegio de los Hermanos del Sagrado Coraz‚îú‚îÇn. Detr‚îú√≠s del colegio, el Huerva vuelve a salir al aire tras su paseo subterr‚îú√≠neo por la ciudad, y se topa con la mole poligonal del dep‚îú‚îÇsito del "Gas". T‚îú¬°midas sombras indican que la niebla se est‚îú√≠ disipando. Fuente: "Zaragoza viva" (1969)', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64715700, -0.87952800, '0101000020E61000003B527DE71725ECBF5130630AD6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15730364527.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15730364527.webp', 'https://www.flickr.com/photos/zaragozaantigua/15730364527/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24294, 'Marina Moreno 1975', 'Archivo Municipal. Gerardo Sancho Ramo. Febrero 1975. Imagen de las obras de la prolongaci‚îú‚îÇn del Paseo de Marina Moreno por debajo del Camino de las Torres. La prolongaci‚îú‚îÇn de Marina Moreno se estaba realizando, a la izquierda de esta imagen, mediante un t‚îú‚ïënel carretero que pretend‚îú¬°a ser una gran autopista de salida y entrada al cogollo de la ciudad, adem‚îú√≠s de revitalizar, de paso, a los barrios del sureste, una cancioncilla esta de la revitalizaci‚îú‚îÇn del Sureste urbano que, cuarenta a‚îú‚ñíos despu‚îú¬Æs, a‚îú‚ïën tiene int‚îú¬Ærpretes en el consistorio. Al fondo, los edificios que se‚îú‚ñíalan el comienzo del actual Paseo de la Mina. A la derecha, las traseras del antiguo edificio del colegio del Sagrado Coraz‚îú‚îÇn, junto al Huerva.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.64597100, -0.87840100, '0101000020E61000001EC2F869DC1BECBF0C957F2DAFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16063158866.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16063158866.webp', 'https://www.flickr.com/photos/zaragozaantigua/16063158866/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24297, 'La Caridad 1908', 'Foto Ignacio Coyne, 1908. Exposici‚îú‚îÇn Hispano Francesa de Zaragoza. Palacio de La Caridad. Exposici‚îú‚îÇn de peque‚îú‚ñías industrias. Vista desde la actual calle de Segismundo Moret. A la derecha, el Museo. Fuente: dara.aragon.es/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64816600, -0.87770500, '0101000020E61000004A24D1CB2816ECBF88307E1AF7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18983653873.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18983653873.webp', 'https://www.flickr.com/photos/zaragozaantigua/18983653873/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24304, 'Avenida del Jard‚îú¬°n Bot‚îú√≠nico 1908', 'Exposici‚îú‚îÇn Hispano Francesa. Avenida del Jard‚îú¬°n Bot‚îú√≠nico. A la izquierda, el pabell‚îú‚îÇn de la Alimentaci‚îú‚îÇn. A la derecha, el "Edificio de Artes e Industrias", y el "Edificio de los Museos". Al fondo, la foresta y acceso del Jard‚îú¬°n Bot‚îú√≠nico. A su derecha, hacia la calle de San Miguel. A su izquierda, la huerta y edificios del convento de Santa Catalina.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64841500, -0.87908900, '0101000020E61000003CBF28417F21ECBF309E4143FFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19416843118.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19416843118.webp', 'https://www.flickr.com/photos/zaragozaantigua/19416843118/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24311, 'Plaza de Los Sitios 1988', 'Foto Eduardo Zamarripa, 1988. Vista a‚îú¬Ærea de la plaza de Los Sitios. En el centro, el Museo de Zaragoza. Fuente: Arag‚îú‚îÇn desde el aire, Ministerio de Defensa, 1988.', 1988, 1988, 1988, 'Anos 80', 'CENTRO', 41.64824000, -0.87860500, '0101000020E61000003D44A33B881DECBFC2FA3F87F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20292256306.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20292256306.webp', 'https://www.flickr.com/photos/zaragozaantigua/20292256306/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24324, 'Marina Moreno 1978', 'Imagen capturada desde cierta altura del paseo de Marina Moreno, con interesante visual, al fondo, del camino de las Torres, con el edificado y moderno tramo entre las calles de Gonzalo de Berceo, a la izquierda, y Manuel Lorenzo Pardo, a la derecha, en el que destacan los huecos de los n‚îú‚ïëmeros 15 (izquierda), y 25 (centro). Justo enfrente de todos ellos, el contraste con algunas de las antiguas instalaciones de la f‚îú√≠brica del "Gas", y el enorme solar esquinero con Marina Moreno, e inmediato al cauce del Huerva. A la izquierda, asoma la emergente estructura del moderno edificio del n‚î¨‚ïë 16-18 de camino de las Torres. En el andador central del paseo, la antigua estatuilla del "Buen Pastor" que originalmente estuviera en el patio de entrada del Matadero municipal. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.64689500, -0.87932300, '0101000020E610000005DCF3FC6923ECBF14799274CDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32665703006.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32665703006.webp', 'https://www.flickr.com/photos/zaragozaantigua/32665703006/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24325, 'Plaza Castelar c.1928', '"Palacio Museo Provincial". Vista de la plaza de Castelar, editada en postal de Union Postale Universelle. En primer t‚îú¬Ærmino, el monumento a los Sitios. A la derecha, el kiosco de la m‚îú‚ïësica. Fuente: www.todocoleccion.net', 1928, 1928, 1928, 'Anos 20', 'CENTRO', 41.64828500, -0.87870400, '0101000020E610000009A9DBD9571EECBF62BEBC00FBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32826815241.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32826815241.webp', 'https://www.flickr.com/photos/zaragozaantigua/32826815241/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24328, 'Golosa Puerta del Carmen 1908', 'Imagen de la llamativa y visitada instalaci‚îú‚îÇn presentada por la Sociedad General Azucarera de Espa‚îú‚ñía en la Exposici‚îú‚îÇn Hispano-Francesa de 1908, ubicada en el Pabell‚îú‚îÇn de la Alimentaci‚îú‚îÇn. En ella destacaba una luminosa reproducci‚îú‚îÇn art‚îú¬°stica, realizada en az‚îú‚ïëcar, de la Puerta del Carmen previa a los eventos militares de 1808-09. Fuente visual: "Zaragoza art‚îú¬°stica ‚îú¬Æ industrial. Album de la Exposici‚îú‚îÇn. 1908."', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64839400, -0.87966600, '0101000020E61000007DE6AC4F3926ECBF19761893FED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34469551411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34469551411.webp', 'https://www.flickr.com/photos/zaragozaantigua/34469551411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24332, 'P.‚î¨‚ïë de la Mina c.1930', 'Imagen posiblemente capturada junto al paseo de la Mina, en el l‚îú¬°mite del cubrimiento del r‚îú¬°o Huerva que por entonces llegaba hasta la calle Sancho y Gil (tramo luego redenominado Mefisto), en una demostraci‚îú‚îÇn jotera al aire libre. El enorme y costumbrista escenario montado para la ocasi‚îú‚îÇn hace de pantalla que focaliza la atenci‚îú‚îÇn. Tras ‚îú¬Æl sobresale, a la izquierda, una chimenea de la f‚îú√≠brica de Gas del camino de las Torres, y parte del antiguo colegio del Sagrado Coraz‚îú‚îÇn. A la derecha, harinera de Marcos Samper y algunos almacenes del arbolado entorno industrial del camino de los Pl‚îú√≠tanos. Fuente visual: HA.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64718400, -0.87970900, '0101000020E61000004FE61F7D9326ECBF4B3FE1ECD6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37967632184.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37967632184.webp', 'https://www.flickr.com/photos/zaragozaantigua/37967632184/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24334, 'Exposici‚îú‚îÇn de 1908', 'Imagen de la Exposici‚îú‚îÇn Hispano-Francesa de 1908 capturada en el espacio entre el Edificio de Escuelas (a la izquierda) y el Palacio de Arte Moderno y peque‚îú‚ñías industrias (habilitado en la Caridad, hacia la derecha, fuera de plano), y centrada en los dos ejemplares de campa‚îú‚ñías presentados a la muestra por la Gran Fundici‚îú‚îÇn de Campanas y F‚îú√≠brica de Relojes de torre de Hijos de Ignacio M‚îú‚ïërua (Vitoria), por las que consiguieron el Gran diploma de honor con distinci‚îú‚îÇn especial y la medalla de oro de la muestra. La gran campana de la imagen, de 2300 kilos de peso y diez a‚îú‚ñíos de garant‚îú¬°a de uso, aparece volteada en la imagen para la ocasi‚îú‚îÇn. Al fondo, muro perimetral del recinto expositivo, y ‚îú√≠rboles del paseo de la MIna Fuente visual: Archivo Coyne, en AHPZ.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64847400, -0.87800300, '0101000020E6100000C34659BF9918ECBF35272F3201D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45104231761.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45104231761.webp', 'https://www.flickr.com/photos/zaragozaantigua/45104231761/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
